window.DATA = {"course": "美学", "title": "《美学原理》背诵复习", "chapters": [{"id": "c0", "title": "绪论", "color": "#5B8DEF", "nodes": [{"id": "n2", "m": "一、", "t": "美学的学科性质与定义", "r": 1, "c": [{"id": "n3", "m": "（1）", "t": "定义：美学是产生于近代、基于人类长期审美活动、研究“美”的对象与人类审美活动的人文学科", "r": 3, "c": []}, {"id": "n4", "m": "（2）", "t": "成立标志：1750年德国哲学家鲍姆嘉通出版《美学》（Aesthetica），美学成为独立学科门类", "r": 3, "c": []}, {"id": "n5", "m": "（3）", "t": "学科特性：人文学科、理论学科、与诸多相邻学科交叉", "r": 3, "c": []}, {"id": "n6", "m": "（4）", "t": "【助记】1750＋鲍姆嘉通＋《美学》；三性＝人文、理论、交叉", "r": 3, "c": []}]}, {"id": "n7", "m": "二、", "t": "美学是一门什么样的学科（历史与属性）", "r": 1, "c": [{"id": "n8", "m": "（1）", "t": "总：近代产生、基于审美活动、研究“美”与人类审美活动的人文学科", "r": 3, "c": []}, {"id": "n9", "m": "（2）", "t": "美学思维历史悠久：物象判断→借物象生发抽象→纯粹理性思考；黑格尔“象征—古典—浪漫”三阶段循环往复", "r": 3, "c": []}, {"id": "n10", "m": "（3）", "t": "学科支系庞杂多样", "r": 3, "c": [{"id": "n11", "m": "①", "t": "共时性：同期不同理论家有不同取向，如1929—1939年延安文学、国统区文学、“孤岛文学”三大分区", "r": 4, "c": []}, {"id": "n12", "m": "②", "t": "历时性：每一阶段对前段扬弃继承，如波德莱尔上承浪漫主义提出“以丑为美”", "r": 4, "c": []}]}, {"id": "n13", "m": "（4）", "t": "与社会思潮大致同步又具独立性", "r": 3, "c": [{"id": "n14", "m": "①", "t": "同步：董仲舒“罢黜百家、独尊儒术”后审美进入儒家主导阶段", "r": 4, "c": []}, {"id": "n15", "m": "②", "t": "超前：马雅可夫斯基等“未来主义”超越当代技术世界", "r": 4, "c": []}, {"id": "n16", "m": "③", "t": "滞后：林纾的小说翻译观", "r": 4, "c": []}]}, {"id": "n17", "m": "（5）", "t": "【助记】定义（近代＋人文＋审美）→三特性：思维悠久（象征古典浪漫）、支系庞杂（共时／历时）、思潮关系（同步／超前／滞后）", "r": 3, "c": []}]}, {"id": "n18", "m": "三、", "t": "美学研究什么（对象与内容）", "r": 1, "c": [{"id": "n19", "m": "（1）", "t": "研究对象：人类的审美活动（审美本质＝对审美活动的哲学抽象）", "r": 3, "c": []}, {"id": "n20", "m": "（2）", "t": "由审美对象与审美意识构成：对象是前提，意识指导活动；研究对象如何被判定、意识的特征与产生过程", "r": 3, "c": []}, {"id": "n21", "m": "（3）", "t": "按存在领域分：自然美、社会美、艺术美、美育（陶渊明“采菊东篱下”；《桃花源记》；洛可可油画；朱光潜《给青年的十二封信》）", "r": 3, "c": []}, {"id": "n22", "m": "（4）", "t": "按形态类型分：崇高、优美、悲剧、喜剧、丑（《老人与海》；欧阳修《蝶恋花》；《红楼梦》；《人间喜剧》；李贺）", "r": 3, "c": []}, {"id": "n23", "m": "（5）", "t": "【助记】对象＝审美活动；两构成（对象＋意识）；两分法＝领域（自社艺育）＋形态（崇优悲喜丑）", "r": 3, "c": []}]}, {"id": "n24", "m": "四、", "t": "怎样研究美学（研究方法）", "r": 1, "c": [{"id": "n25", "m": "（1）", "t": "定位：既区别于实证经验科学，又区别于纯思辨的人文体验描述", "r": 3, "c": []}, {"id": "n26", "m": "（2）", "t": "基本要求：学好哲学尤其马克思主义哲学；理论联系实际（美学史＋艺术实践）；独立思考、系统掌握要点", "r": 3, "c": []}, {"id": "n27", "m": "（3）", "t": "三种方式", "r": 3, "c": [{"id": "n28", "m": "①", "t": "观察：宗炳“澄怀味象”观山水；庄子“齐物”式观察", "r": 4, "c": []}, {"id": "n29", "m": "②", "t": "体验：研究者自我卷入，含追问与对话，如西苏“身体写作”", "r": 4, "c": []}, {"id": "n30", "m": "③", "t": "解释：阐发深层意义，如陶渊明接受史唐（杜甫“恨枯槁”）宋（朱熹“超脱自然”）不同", "r": 4, "c": []}]}, {"id": "n31", "m": "（4）", "t": "【助记】哲学打底＋联系实际＋独立思考；三法＝观察、体验、解释", "r": 3, "c": []}]}, {"id": "n32", "m": "五、", "t": "为什么要学习美学", "r": 1, "c": [{"id": "n33", "m": "（1）", "t": "提供愉悦感受：安顿身心、深化美感认知（博物馆全景式展示）", "r": 3, "c": []}, {"id": "n34", "m": "（2）", "t": "研究审美关系：美学对象是以意象世界为对象的人生体验活动（《拉奥孔》诗画同源）", "r": 3, "c": []}, {"id": "n35", "m": "（3）", "t": "转化为生产力：美感带来差异化价值，企业脱颖而出", "r": 3, "c": []}, {"id": "n36", "m": "（4）", "t": "提升综合能力：感性结合理性的综合能力，难为纯理性思辨把握", "r": 3, "c": []}, {"id": "n37", "m": "（5）", "t": "【助记】愉悦—关系—生产力—综合能力", "r": 3, "c": []}]}, {"id": "n38", "m": "六、", "t": "美学与哪些学科关系切近", "r": 1, "c": [{"id": "n39", "m": "（1）", "t": "与艺术学：研究内容大量重叠（都重艺术审美）", "r": 3, "c": [{"id": "n40", "m": "①", "t": "对象范围不同：美学含更广现实审美（山本耀司“侘寂”）；艺术学研究艺术品、艺术家、欣赏、创作等一切", "r": 4, "c": []}, {"id": "n41", "m": "②", "t": "内容与方法不同：美学基于哲学；艺术学还含结构主义、传记批评等", "r": 4, "c": []}]}, {"id": "n42", "m": "（2）", "t": "与心理学：心理学是有效解释工具（精神分析）", "r": 3, "c": [{"id": "n43", "m": "①", "t": "外在观测 vs 内在体验", "r": 4, "c": []}, {"id": "n44", "m": "②", "t": "生理—物理变量 vs 不同于客观说明的解释", "r": 4, "c": []}, {"id": "n45", "m": "③", "t": "自然科学 vs 形而上学", "r": 4, "c": []}]}, {"id": "n46", "m": "（3）", "t": "与宗教学：现代性“祛魅”后艺术取代“神灵”成信仰本体，承认艺术本位前提下用宗教学方法（弗莱原型批评）", "r": 3, "c": []}, {"id": "n47", "m": "（4）", "t": "【助记】艺术学（范围／方法）、心理学（外／内、变量／解释、科学／形上）、宗教学（祛魅＋原型批评）", "r": 3, "c": []}]}, {"id": "n48", "m": "七、", "t": "审美活动（名词解释）", "r": 1, "c": [{"id": "n49", "m": "（1）", "t": "含义：人按“美的规律”、在感性与理性统一中自由创造性地把握现实的实践，含赏美、创作、研究、评论、美化环境等", "r": 3, "c": []}, {"id": "n50", "m": "（2）", "t": "地位：人类特有的精神与文化活动，是人性需求，以意象世界为对象的人生体验，具社会性与历史性，是美学研究对象", "r": 3, "c": []}, {"id": "n51", "m": "（3）", "t": "构成与分类：由审美对象＋审美意识构成；领域分（社会／自然／艺术美＋美育），形态分（崇高／悲剧／喜剧／优美／丑）", "r": 3, "c": []}, {"id": "n52", "m": "（4）", "t": "【助记】美的规律＋自由创造实践；特征（人特有／意象世界／社会历史性）；两分（领域＋形态）", "r": 3, "c": []}]}, {"id": "n53", "m": "八、", "t": "审美现代性（名词解释）", "r": 1, "c": [{"id": "n54", "m": "（1）", "t": "含义：现代社会中人们在审美体验与艺术表现上呈现的现代性特征", "r": 3, "c": []}, {"id": "n55", "m": "（2）", "t": "表现：观念上中西交融（现代／后现代思想）；内容上新旧之争（传统与现代文学、戏曲与电影）", "r": 3, "c": []}, {"id": "n56", "m": "（3）", "t": "特点：古典美学时代终结，内部存三大矛盾（肯定／否定、精英／民粹、普遍人类学／资产阶级意识形态），仍是未完成阶段", "r": 3, "c": []}, {"id": "n57", "m": "（4）", "t": "【助记】现代审美特征；观念中西交融＋内容新旧之争；三矛盾＋未完成", "r": 3, "c": []}]}, {"id": "n58", "m": "九、", "t": "马克思主义美学（名词解释）", "r": 1, "c": [{"id": "n59", "m": "（1）", "t": "含义：马克思主义者关于“美”的理论体系，非专指马恩，肯定人在审美中的主体性地位", "r": 3, "c": []}, {"id": "n60", "m": "（2）", "t": "哲学基础：辩证唯物主义、历史唯物主义、德国古典哲学", "r": 3, "c": []}, {"id": "n61", "m": "（3）", "t": "核心观点：劳动创造美（艺术起源）；美有规律可循；艺术作为上层建筑依赖经济基础；异化劳动两重性—既制造丑又创造美", "r": 3, "c": []}, {"id": "n62", "m": "（4）", "t": "【助记】非专指马恩＋主体性；三基础（辩证／历史唯物＋德国古典）；四点（劳动创造美／有规律／上层建筑／异化两重性）", "r": 3, "c": []}]}, {"id": "n63", "m": "十、", "t": "中国美学发展脉络（填空速记）", "r": 1, "c": [{"id": "n64", "m": "（1）", "t": "三个黄金时代：先秦、魏晋南北朝、清代前期", "r": 3, "c": []}, {"id": "n65", "m": "（2）", "t": "真正起点：老子，开创道家美学传统；孔子是中国历史上第一个提倡美育的思想家", "r": 3, "c": []}, {"id": "n66", "m": "（3）", "t": "唐五代宋元：儒、道两线之外，禅宗影响日增", "r": 3, "c": []}, {"id": "n67", "m": "（4）", "t": "近代三大家：梁启超、王国维、蔡元培；现代两大家：朱光潜、宗白华", "r": 3, "c": []}, {"id": "n68", "m": "（5）", "t": "当代第一次热潮四大派：蔡仪（客观派）、高尔泰吕荧（主观派）、朱光潜（主客观统一派）、李泽厚（客观性与社会性统一派）", "r": 3, "c": []}, {"id": "n69", "m": "（6）", "t": "【助记】黄金三代（先秦／魏晋／清前）；起点老子＋美育孔子；近代梁王蔡、现代朱宗；四派蔡／高吕／朱／李", "r": 3, "c": []}]}], "tb": []}, {"id": "c1", "title": "第一章 审美的本质", "color": "#E0719B", "nodes": [{"id": "n71", "m": "一、", "t": "西方传统对美的本质的认识", "r": 1, "c": [{"id": "n72", "m": "（1）", "t": "本体论阶段：追求独立、终极、普遍的美", "r": 3, "c": [{"id": "n73", "m": "①", "t": "毕达哥拉斯学派：数是万物法则，美在“数的和谐”，音乐是典型", "r": 4, "c": []}, {"id": "n74", "m": "②", "t": "柏拉图：区分“美的事物”与“美本身”，“美本身”即“理念”，是永恒不变的原型", "r": 4, "c": []}, {"id": "n75", "m": "③", "t": "亚里士多德：美存在于具体事物之中，是秩序、匀称与和谐", "r": 4, "c": []}, {"id": "n76", "m": "④", "t": "中世纪神学美学（奥古斯丁）：上帝是真善美的创造者，美是以上帝为原型的完善与和谐", "r": 4, "c": []}]}, {"id": "n77", "m": "（2）", "t": "认识论阶段：探求审美何以可能、如何构成", "r": 3, "c": [{"id": "n78", "m": "①", "t": "经验主义：美来自感官知觉与经验（夏夫兹博里“内在感官”；休谟诉诸生理心理结构）", "r": 4, "c": []}, {"id": "n79", "m": "②", "t": "理性主义：重理性与法则（笛卡尔数学逻辑；鲍姆嘉通反映客观和谐秩序）", "r": 4, "c": []}, {"id": "n80", "m": "③", "t": "法国启蒙（狄德罗）：“美在关系”—事物内部、事物之间、事物与人三种关系", "r": 4, "c": []}, {"id": "n81", "m": "④", "t": "德国古典：康德沟通自然与自由（审美的合目的性）；黑格尔“美是理念的感性显现”", "r": 4, "c": []}]}, {"id": "n82", "m": "（3）", "t": "语言学阶段：语言是人的存在方式", "r": 3, "c": [{"id": "n83", "m": "①", "t": "人文主义美学：关注主体生成（海德格尔“转向”、伽达默尔接受美学）", "r": 4, "c": []}, {"id": "n84", "m": "②", "t": "科学主义美学：返回工具维度，使美学可分析化（格式塔、结构主义；杜威、贝尔、维特根斯坦）", "r": 4, "c": []}, {"id": "n85", "m": "③", "t": "后现代／解构／后殖民：从社会文化符号机制思考人的生存，具文化批判倾向", "r": 4, "c": []}]}, {"id": "n86", "m": "（4）", "t": "【助记】三阶段＝本体（毕／柏／亚／神学）→认识（经验／理性／关系／德国古典）→语言（人文／科学／后现代）", "r": 3, "c": []}]}, {"id": "n87", "m": "二、", "t": "中国传统对美的本质的认识", "r": 1, "c": [{"id": "n88", "m": "（1）", "t": "精髓：天人合一", "r": 3, "c": []}, {"id": "n89", "m": "（2）", "t": "原始先秦：“神人以和”为天人合一雏形；儒家以社会伦理为本位（孔子“里仁为美”），道家“无为”“天然之美”", "r": 3, "c": []}, {"id": "n90", "m": "（3）", "t": "汉代：以气、阴阳、五行为核心的宇宙论结构；《淮南子》《毛诗序》“发乎情，止乎礼”", "r": 3, "c": []}, {"id": "n91", "m": "（4）", "t": "魏晋隋唐：魏晋美学正式独立（《世说新语》《人物志》、陆机《文赋》“诗缘情”）；唐代意境理论兴起", "r": 3, "c": []}, {"id": "n92", "m": "（5）", "t": "宋元明清：宋代平淡境界、以禅喻诗（严羽）、自然审美（郭熙《林泉高致》）；明清主情（李贽“童心说”、汤显祖“至情”、黄宗羲“诗以道性情”）", "r": 3, "c": []}, {"id": "n93", "m": "（6）", "t": "【助记】天人合一一线贯穿；先秦（神人以和／儒道）→汉（气阴阳五行）→魏晋唐（独立＋意境）→宋元明清（平淡／禅／童心至情）", "r": 3, "c": []}]}, {"id": "n94", "m": "三、", "t": "人为什么能按照美的规律来建造", "r": 1, "c": [{"id": "n95", "m": "（1）", "t": "出处：马克思《1844年经济学哲学手稿》", "r": 3, "c": []}, {"id": "n96", "m": "（2）", "t": "人的生产与动物有本质不同：动物受肉体支配、只生产自身；人解放肉体需求、生产整个自然界，充盈自由性", "r": 3, "c": []}, {"id": "n97", "m": "（3）", "t": "内容上人能按任何“种的尺度”进行生产，并把固有尺度运用于对象", "r": 3, "c": []}, {"id": "n98", "m": "（4）", "t": "劳动是内在尺度与外在尺度寻求统一的活动，故人的生产是全面、自由、自觉的，能体现美的因素", "r": 3, "c": []}, {"id": "n99", "m": "（5）", "t": "【助记】手稿出处；人／动物之别→任何种的尺度→内外尺度统一（全面／自由／自觉）", "r": 3, "c": []}]}, {"id": "n100", "m": "四、", "t": "探讨美的本质必须坚持的原则", "r": 1, "c": [{"id": "n101", "m": "（1）", "t": "历史性：探讨审美本质是美学思想史首要传统", "r": 3, "c": []}, {"id": "n102", "m": "（2）", "t": "价值理想性：审美本质属精神哲学范畴，非经验科学实体对象", "r": 3, "c": []}, {"id": "n103", "m": "（3）", "t": "整体性：是含审美对象与审美意识在内的整体审美活动经验的本质", "r": 3, "c": []}, {"id": "n104", "m": "（4）", "t": "实践性：以劳动及更广实践为人类学原型，是探讨的基础与出发点", "r": 3, "c": []}, {"id": "n105", "m": "（5）", "t": "【助记】历史—价值—整体—实践（劳动为根）", "r": 3, "c": []}]}, {"id": "n106", "m": "五、", "t": "马克思主义本质观：作为目的与规律统一的自由形式", "r": 1, "c": [{"id": "n107", "m": "（1）", "t": "以劳动工具及其使用技术为中心，劳动双向陶冶主体（人）与客体（自然），目的与规律统一为工具技术的自由操作", "r": 3, "c": []}, {"id": "n108", "m": "（2）", "t": "自然规律因纳入人类目的而“人化”，欲望目的遵循规律而失利己性，形成人与自然新型互渗关系", "r": 3, "c": []}, {"id": "n109", "m": "（3）", "t": "自由形式既是工具积淀结果，又是工具活动运行前提，规律与目的相统一是动态机制", "r": 3, "c": []}, {"id": "n110", "m": "（4）", "t": "审美作为自由形式，本源是以劳动为原型的实践中介方式；中介演变以符号为媒介，沿“巫术—艺术”发展", "r": 3, "c": []}, {"id": "n111", "m": "（5）", "t": "规律与目的对立统一的动态平衡，是审美形态及范畴多样差异的根源；唯艺术中自由形式呈现为纯粹自由（意境）", "r": 3, "c": []}, {"id": "n112", "m": "（6）", "t": "【助记】工具技术为中心→目的×规律＝自由形式；人化＋互渗；巫术→艺术；意境＝纯粹自由", "r": 3, "c": []}]}, {"id": "n113", "m": "六、", "t": "真善美之间的关系", "r": 1, "c": [{"id": "n114", "m": "（1）", "t": "联系：三者品质相近，人在实践中掌握规律（真）、实现功利目的（善）、成为生动形象才有美；同一对象的三个方面", "r": 3, "c": []}, {"id": "n115", "m": "（2）", "t": "美与善：善与功利直接相联，美与功利间接相联（功利潜伏于形象）；善重内容、美重形象；善是意志对象、美是观赏对象", "r": 3, "c": []}, {"id": "n116", "m": "（3）", "t": "美与真：美的产生以对真的认识掌握为前提；真可脱离实践独立存在，美不能离开主体与实践；真是求知对象、美是欣赏对象", "r": 3, "c": []}, {"id": "n117", "m": "（4）", "t": "【助记】相近三品质；善＝功利／意志，真＝规律／求知，美＝形象／欣赏", "r": 3, "c": []}]}, {"id": "n118", "m": "七、", "t": "如何看待今天的审美时尚", "r": 1, "c": [{"id": "n119", "m": "（1）", "t": "价值相对主义导向价值虚无主义：“以丑为美”可能消解元价值的“美”与真善美／假恶丑的对立（“大冰现象”）", "r": 3, "c": []}, {"id": "n120", "m": "（2）", "t": "现代性分化使真善美解体：“美”弱化对真善的依存，空前扩展形式美与符号化，造成个体畸变与群体异化", "r": 3, "c": []}, {"id": "n121", "m": "（3）", "t": "当代亟需重建真善美元价值体系，克服价值虚无主义，需国家力量与群体意向共同努力", "r": 3, "c": []}, {"id": "n122", "m": "（4）", "t": "【助记】相对→虚无（以丑为美）；分化→真善美解体（符号化）；出路＝重建元价值", "r": 3, "c": []}]}, {"id": "n123", "m": "八、", "t": "美的规律（名词解释）", "r": 1, "c": [{"id": "n124", "m": "（1）", "t": "出处：马克思论动物生产与人的生产不同时提出，是物质生产实践中、在真与善基础上发展起来的独立规律", "r": 3, "c": []}, {"id": "n125", "m": "（2）", "t": "含义：人在欣赏美、创造美及一切实践中所表现的关于美的尺度、标准等规定的总和", "r": 3, "c": []}, {"id": "n126", "m": "（3）", "t": "实质：集中体现人的本质及其劳动的理想性—人本质自由无限，要求超越动物式“生产”的自由劳动理想", "r": 3, "c": []}, {"id": "n127", "m": "（4）", "t": "【助记】马克思＋真善基础上的独立规律；尺度标准总和；体现劳动理想性", "r": 3, "c": []}]}, {"id": "n128", "m": "九、", "t": "美的形式与两个尺度（名词解释）", "r": 1, "c": [{"id": "n129", "m": "（1）", "t": "美的形式：显现人本质力量、能唤起美感的事物感性形式，与“美的内容”相对，含内形式（内部组织结构）与外形式（外部表现／装饰）", "r": 3, "c": []}, {"id": "n130", "m": "（2）", "t": "两个尺度：外在尺度＝马克思“物种的尺度”，即客观事物本身规律性；内在尺度＝人自身目的、需要的体现", "r": 3, "c": []}, {"id": "n131", "m": "（3）", "t": "意义：人不仅按外在尺度、还能按内在尺度满足需要，是马克思美学重大突破，对西方马克思主义美学具指导作用", "r": 3, "c": []}, {"id": "n132", "m": "（4）", "t": "【助记】美的形式（内／外形式）；两尺度＝外（物种／规律）＋内（人之目的）", "r": 3, "c": []}]}, {"id": "n133", "m": "十、", "t": "人本质力量的对象化与自然的人化（名词解释）", "r": 1, "c": [{"id": "n134", "m": "（1）", "t": "人本质力量对象化：人的自由自觉意识（有目的、有计划改造自然）通过社会实践在现实中得到体现与贯彻，社会实践是必要条件", "r": 3, "c": []}, {"id": "n135", "m": "（2）", "t": "自然的人化：马克思术语，指人的对象性活动使越来越多天然生态系统变为人工生态系统的过程", "r": 3, "c": []}, {"id": "n136", "m": "（3）", "t": "审美中：人化后的自然可作精神活动产物分析，辩证深化人对第一自然的美感认识，是马克思文化哲学最核心价值取向", "r": 3, "c": []}, {"id": "n137", "m": "（4）", "t": "【助记】对象化＝本质力量经实践显现；人化＝天然→人工＋美感深化", "r": 3, "c": []}]}, {"id": "n138", "m": "十一、", "t": "意象、象罔与艺术意象（名词解释）", "r": 1, "c": [{"id": "n139", "m": "（1）", "t": "意象：客观物象经创作主体独特情感活动而创造的艺术形象，“意”是作者之意、“象”是客观物象；最早可追溯《易经》，最一般规定是情景交融", "r": 3, "c": []}, {"id": "n140", "m": "（2）", "t": "儒道之别：儒家以“意”为作家内在修养、意象为审美表象本体根源；道家“意”为内敛朴拙的圣人精神，否定具体物象之美", "r": 3, "c": []}, {"id": "n141", "m": "（3）", "t": "象罔：出自《庄子》，象＝形象境相、罔＝无虚幻，象征虚实结合、有限与无限、混沌与差别的统一", "r": 3, "c": []}, {"id": "n142", "m": "（4）", "t": "艺术意象：朱光潜、宗白华结合艺术美与传统“意象”论的产物，主体之情与对象之景融合，凝聚人生升华，创作者与欣赏者双向交流", "r": 3, "c": []}, {"id": "n143", "m": "（5）", "t": "【助记】意象（情景交融／源《易经》／儒道别）；象罔（庄子／虚实统一）；艺术意象（朱宗／情景融合双向交流）", "r": 3, "c": []}]}, {"id": "n144", "m": "十二、", "t": "主体间性（名词解释）", "r": 1, "c": [{"id": "n145", "m": "（1）", "t": "含义：探究主体相互关系的哲学观念", "r": 3, "c": []}, {"id": "n146", "m": "（2）", "t": "发展：胡塞尔现象学（他者、先验自我与自我）；伽达默尔“视域融合”；哈贝马斯以语言学“交往”突破先验自我", "r": 3, "c": []}, {"id": "n147", "m": "（3）", "t": "意义：肯定主体交往实践能力，交互以肯定彼此为主体为前提，语言沟通使交互成为可能，是对传统主体的延伸与反思", "r": 3, "c": []}, {"id": "n148", "m": "（4）", "t": "【助记】主体相互关系；胡塞尔→伽达默尔（视域融合）→哈贝马斯（交往）", "r": 3, "c": []}]}, {"id": "n149", "m": "十三、", "t": "和谐说与理式说（名词解释）", "r": 1, "c": [{"id": "n150", "m": "（1）", "t": "和谐说：毕达哥拉斯学派，美是数量关系的“和谐”，人体是“小宇宙”，是西方第一次深入探讨美本质的学说，标志审美反思与本体论思维的萌芽", "r": 3, "c": []}, {"id": "n151", "m": "（2）", "t": "理式说：柏拉图，区分“美的事物”与“美本身”，认为物质世界不存在美，美与超现实的精神实体（理式）相联，由其注入或显现使事物成为美", "r": 3, "c": []}, {"id": "n152", "m": "（3）", "t": "大希庇亚篇：柏拉图，首次专题讨论审美本质的文献，否定美是有用、恰当、快感等，提出“美本身”是使一切成其为美的共同本质", "r": 3, "c": []}, {"id": "n153", "m": "（4）", "t": "【助记】和谐说（毕／数／小宇宙／首探）；理式说（柏／美本身＝理念）；大希庇亚篇（首次专题／美本身）", "r": 3, "c": []}]}, {"id": "n154", "m": "十四、", "t": "美是道德的象征与美是生活（名词解释）", "r": 1, "c": [{"id": "n155", "m": "（1）", "t": "美是道德的象征：康德《判断力批判》提出，美具主观普遍性的先验根据，预设通向自由的可能；道德即“实践理性”，审美使人由自然走向自由", "r": 3, "c": []}, {"id": "n156", "m": "（2）", "t": "美是生活：车尔尼雪夫斯基《艺术对现实的审美关系》提出，凡有益于、符合人类生活要求或显示生活的就是美，把美从理念天国拉回现实", "r": 3, "c": []}, {"id": "n157", "m": "（3）", "t": "【助记】道德象征（康德／自然→自由）；美是生活（车／拉回现实）", "r": 3, "c": []}]}], "tb": []}, {"id": "c2", "title": "第二章 审美活动经验", "color": "#3FB68B", "nodes": [{"id": "n159", "m": "一、", "t": "为什么要从审美活动整体性来理解审美经验", "r": 1, "c": [{"id": "n160", "m": "（1）", "t": "审美经验不能孤立存在：意识发生依赖机体且晚近，个体差异突出审美价值的相对性，先验存在于活动之外在逻辑上谬误", "r": 3, "c": []}, {"id": "n161", "m": "（2）", "t": "审美经验不直接反映审美对象、而是反映审美活动：基于主体审美实践产生，含与对象内容不同一、超出后者的方面", "r": 3, "c": []}, {"id": "n162", "m": "（3）", "t": "【助记】不孤立（依赖机体）＋反映活动（非对象）→产生于审美活动", "r": 3, "c": []}]}, {"id": "n163", "m": "二、", "t": "审美体验在审美经验中的地位", "r": 1, "c": [{"id": "n164", "m": "（1）", "t": "深刻性表明审美经验是第二性的：实践先于对象与意识，体验先于经验而发生（《小欢喜》乔英子）", "r": 3, "c": []}, {"id": "n165", "m": "（2）", "t": "亲历性激活审美经验的表述可能性：体验深刻方能创造（周立波《山乡巨变》邓秀梅）；不同个体形成不同体验（《红楼梦》大众与学界解读）", "r": 3, "c": []}, {"id": "n166", "m": "（3）", "t": "整体性使审美经验丰富化、多维化：把握对象整体而非某一方面（《狂人日记》多重解读）", "r": 3, "c": []}, {"id": "n167", "m": "（4）", "t": "【助记】深刻性（第二性／体验先于经验）＋亲历性（创造／差异）＋整体性（丰富多维）", "r": 3, "c": []}]}, {"id": "n168", "m": "三、", "t": "影响审美经验发展的条件", "r": 1, "c": [{"id": "n169", "m": "（1）", "t": "生产劳动分工状况制约其分化独立（狩猎民族以动物、农牧民族以植物为审美对象）", "r": 3, "c": []}, {"id": "n170", "m": "（2）", "t": "上层建筑及其他意识形态的制约（魏晋玄学促山水画；中世纪基督教禁锢戏剧）", "r": 3, "c": []}, {"id": "n171", "m": "（3）", "t": "艺术对审美意识的巨大促进（近体诗、俳句影响意象派庞德）", "r": 3, "c": []}, {"id": "n172", "m": "（4）", "t": "审美对象对审美意识的促进（《罪与罚》刺激“复调”理论）", "r": 3, "c": []}, {"id": "n173", "m": "（5）", "t": "审美经验系统内部各部分相互促进（“东野圭吾热”＝本格→非本格趣味）", "r": 3, "c": []}, {"id": "n174", "m": "（6）", "t": "【助记】分工—意识形态—艺术—对象—系统内部，五条", "r": 3, "c": []}]}, {"id": "n175", "m": "四、", "t": "审美经验内部结构的主要构成", "r": 1, "c": [{"id": "n176", "m": "（1）", "t": "审美感受：狭义美感，审美活动时的心理活动过程，是整个审美经验的基础", "r": 3, "c": []}, {"id": "n177", "m": "（2）", "t": "审美心理结构：社会历史积累形成的审美生理—心理机制，是审美感受的物质基础", "r": 3, "c": []}, {"id": "n178", "m": "（3）", "t": "审美态度：基于审美心理结构主动构成审美关系的特殊心理状态", "r": 3, "c": []}, {"id": "n179", "m": "（4）", "t": "审美趣味：审美经验基础上形成的有偏好、有心理定势的审美风格倾向", "r": 3, "c": []}, {"id": "n180", "m": "（5）", "t": "审美理想：对审美最高境界的向往与追求，是审美的最高范型与标准，是审美趣味的升华与结晶", "r": 3, "c": []}, {"id": "n181", "m": "（6）", "t": "【助记】感受→心理结构→态度→趣味→理想（层层升华，系统不平衡引发整体变化）", "r": 3, "c": []}]}, {"id": "n182", "m": "五、", "t": "审美积淀的含义及形成形式", "r": 1, "c": [{"id": "n183", "m": "（1）", "t": "含义：人将外在社会生活与历史内化为个体心理结构的过程，个体性且依赖人类千百代历史性继承积累", "r": 3, "c": []}, {"id": "n184", "m": "（2）", "t": "生产积淀：生产劳动的结果，工具制造提高感觉中枢协同，催生对对称、和谐的追求（鲁迅“杭育”说）", "r": 3, "c": []}, {"id": "n185", "m": "（3）", "t": "以巫术为主的原始文化积淀：远古巫术激活情感、培养想象、塑造超验体悟（屈原《楚辞》）", "r": 3, "c": []}, {"id": "n186", "m": "（4）", "t": "以艺术为代表的日常文化积淀：艺术把社会总体运动内化为个体心理运动，使心理活动多样、复杂、丰满（酒神舞蹈）", "r": 3, "c": []}, {"id": "n187", "m": "（5）", "t": "【助记】内化为心理结构；三积淀＝生产、巫术、艺术", "r": 3, "c": []}]}, {"id": "n188", "m": "六、", "t": "审美感受的特性", "r": 1, "c": [{"id": "n189", "m": "（1）", "t": "合规律性：美感以超前的普遍合规律性提供契机（西方文论“三次死亡”：上帝／作者／人之死）", "r": 3, "c": []}, {"id": "n190", "m": "（2）", "t": "合目的性：审美感受排除特定有限目的，指向最高目的（沈从文《抽象的抒情》；宫崎骏《幽灵公主》）", "r": 3, "c": []}, {"id": "n191", "m": "（3）", "t": "二者统一：合目的性与合规律性统一于审美感受，对认识与意志欲望具协调中介性质（杜甫；维纳斯“断臂”）", "r": 3, "c": []}, {"id": "n192", "m": "（4）", "t": "还具理性深度、综合性、整体性", "r": 3, "c": []}, {"id": "n193", "m": "（5）", "t": "【助记】合规律＋合目的＋二者统一；附理性深度／综合／整体", "r": 3, "c": []}]}, {"id": "n194", "m": "七、", "t": "审美直觉的内涵", "r": 1, "c": [{"id": "n195", "m": "（1）", "t": "直接性：直接感觉到而非经思维把握，快速瞬时、当下即得（布列东“自动写作”）", "r": 3, "c": []}, {"id": "n196", "m": "（2）", "t": "超理性：达到并在快速反应、超前预感上超出理性，把握普遍内在联系与人生重大价值", "r": 3, "c": []}, {"id": "n197", "m": "（3）", "t": "现象与本质相统一：不抛弃感性现象而把握本质，是整体性、综合性的审美心理结构", "r": 3, "c": []}, {"id": "n198", "m": "（4）", "t": "【助记】直接（瞬时）＋超理性（超前）＋现象本质统一", "r": 3, "c": []}]}, {"id": "n199", "m": "八、", "t": "审美心理要素的构成", "r": 1, "c": [{"id": "n200", "m": "（1）", "t": "感觉：对色彩、声音、形状等个别感性属性的感受（李贺“昆山玉碎凤凰叫”通感）", "r": 3, "c": []}, {"id": "n201", "m": "（2）", "t": "知觉：把感觉材料联合为完整对象的整体性感觉（《人类之子》整体把握）", "r": 3, "c": []}, {"id": "n202", "m": "（3）", "t": "想象：在外物刺激下对记忆表象加工改造形成新形象（《奥本海默》审美想象）", "r": 3, "c": []}, {"id": "n203", "m": "（4）", "t": "情感：最活跃因素，使审美过程浸染情感色彩，推动总体活动", "r": 3, "c": []}, {"id": "n204", "m": "（5）", "t": "领悟：贯穿全过程对审美意蕴本质的把握，类似禅宗“顿悟”", "r": 3, "c": []}, {"id": "n205", "m": "（6）", "t": "【助记】感觉—知觉—想象—情感—领悟（由表及里，情感最活跃）", "r": 3, "c": []}]}, {"id": "n206", "m": "九、", "t": "想象和情感的关系", "r": 1, "c": [{"id": "n207", "m": "（1）", "t": "情感是想象的动力，规定想象方向（“仁者乐山，智者乐水”）", "r": 3, "c": []}, {"id": "n208", "m": "（2）", "t": "想象为情感提供“客观对应物”，丰富情感内涵（艾略特“客观对应物”；杜甫“国破山河在”）", "r": 3, "c": []}, {"id": "n209", "m": "（3）", "t": "二者需一定客观条件约定：特定情感与特定对象结合，须基于历史积淀与审美心理结构", "r": 3, "c": []}, {"id": "n210", "m": "（4）", "t": "【助记】情感→动力方向；想象→客观对应物；须有客观约定", "r": 3, "c": []}]}, {"id": "n211", "m": "十、", "t": "审美经验、审美体验、审美直觉、审美理想（名词解释）", "r": 1, "c": [{"id": "n212", "m": "（1）", "t": "审美经验：主体感受、体验、创造美的经验，由审美实践抽象而成；特征＝直观性、非功利性（康德）、无限性、非理性、情感伴随性", "r": 3, "c": []}, {"id": "n213", "m": "（2）", "t": "审美体验：审美主体深度参与所达到的审美效果，贯穿创作、欣赏、消费、传播始终，是融入与超越的内在状态", "r": 3, "c": []}, {"id": "n214", "m": "（3）", "t": "审美直觉：审美中对对象不假思索即刻把握领悟的能力，使人刹那忘我、全身心沉浸于审美愉悦", "r": 3, "c": []}, {"id": "n215", "m": "（4）", "t": "审美理想：对审美最高境界的向往追求，是最高范型与标准，具稳定性、升华概括性，包含主体愿望", "r": 3, "c": []}, {"id": "n216", "m": "（5）", "t": "审美共通感：身处同一传统氛围的主体形成相似心灵结构、产生共同心理感受，体现于审美活动即审美共通感", "r": 3, "c": []}, {"id": "n217", "m": "（6）", "t": "【助记】经验（抽象／五特征）—体验（深度参与／贯穿始终）—直觉（即刻忘我）—理想（最高范型）—共通感（共同心理）", "r": 3, "c": []}]}, {"id": "n218", "m": "十一、", "t": "移情说与心理距离说（名词解释）", "r": 1, "c": [{"id": "n219", "m": "（1）", "t": "移情说：德国利普斯，美感是在客观事物中看到自我的心理错觉，根源在“移情”—情感“外射”到事物上、达物我同一（胡塞尔、巴赫金有发展）", "r": 3, "c": []}, {"id": "n220", "m": "（2）", "t": "心理距离说：英国布洛，欣赏需保持适度心理距离（太近成生活、太远失兴趣）并保持连贯；修正了“审美无功利”，但仍属唯心认识论", "r": 3, "c": []}, {"id": "n221", "m": "（3）", "t": "【助记】移情（利普斯／外射／物我同一）；距离（布洛／适度＋连贯／修正无功利）", "r": 3, "c": []}]}, {"id": "n222", "m": "十二、", "t": "完型说与内在感官说（名词解释）", "r": 1, "c": [{"id": "n223", "m": "（1）", "t": "完型说：德国阿恩海姆，基于“格式塔”心理学，强调知觉整体性，美感判断是从整体到部分；突出审美与人类本源关系，但过分强调独特结构、陷唯心", "r": 3, "c": []}, {"id": "n224", "m": "（2）", "t": "内在感官说：英国夏夫兹博里，人先天具审美能力，审辨善恶的道德感与审美的美感根本相通，带理性色彩，最终将美赋予神性、美善不分", "r": 3, "c": []}, {"id": "n225", "m": "（3）", "t": "【助记】完型（阿恩海姆／格式塔／整体→部分）；内在感官（夏夫兹博里／先天／美善相通）", "r": 3, "c": []}]}, {"id": "n226", "m": "十三、", "t": "审美经验与心理学说（填空速记）", "r": 1, "c": [{"id": "n227", "m": "（1）", "t": "美感不是认识而是体验；审美体验与生命人生相连，认识可脱离生命孤立研究物质世界", "r": 3, "c": []}, {"id": "n228", "m": "（2）", "t": "西方“审美态度”＝中国“审美心胸”＝禅宗“平常心”", "r": 3, "c": []}, {"id": "n229", "m": "（3）", "t": "美感重要特性＝愉悦性，是高级精神享受，须与生理快感区分而不绝对化；“食”“色”快感特殊条件下可转化为美感", "r": 3, "c": []}, {"id": "n230", "m": "（4）", "t": "弗洛伊德：美感源于无意识，人分本我（快乐原则）、自我（现实原则）、超我（道德原则）", "r": 3, "c": []}, {"id": "n231", "m": "（5）", "t": "荣格：修正个体无意识，提出“集体无意识”与“原始意象”（分析心理学、神话原型）", "r": 3, "c": []}, {"id": "n232", "m": "（6）", "t": "【助记】体验非认识；态度＝心胸＝平常心；愉悦性／食色转化；弗（本我自我超我）／荣（集体无意识）", "r": 3, "c": []}]}], "tb": []}, {"id": "c3", "title": "第三章 形式美", "color": "#E8954A", "nodes": [{"id": "n234", "m": "一、", "t": "形式美和美的形式的区别", "r": 1, "c": [{"id": "n235", "m": "（1）", "t": "美的形式：含内形式与外形式，强调与内容的联系、不能脱离内容（傣族“泼水节”与丰收祝福相关联）", "r": 3, "c": []}, {"id": "n236", "m": "（2）", "t": "形式美：从美的形式中再抽象提取、与内容脱离直接关系，含各种形式因素＋形式美法则两部分（漫威特效；罗丹《思想者》黄金比）", "r": 3, "c": []}, {"id": "n237", "m": "（3）", "t": "【助记】美的形式（连内容／内外形式）→再抽象→形式美（脱内容／因素＋法则）", "r": 3, "c": []}]}, {"id": "n238", "m": "二、", "t": "形式美的构成要素", "r": 1, "c": [{"id": "n239", "m": "（1）", "t": "色：视觉接受，有象征关系（红＝激情、黑＝恐惧），并随历史文化积淀变化（“黑—红”联想暴力血腥）", "r": 3, "c": []}, {"id": "n240", "m": "（2）", "t": "形：视觉接受，由点、线、面结合的抽象形态，含模仿（“马踏飞燕”）与改造（夸张《哥斯拉》、减弱“侘寂”、抽象《星月夜》）", "r": 3, "c": []}, {"id": "n241", "m": "（3）", "t": "声音：听觉接受，提取自然声组合成音乐，具强烈表情性（《十面埋伏》战场；《百鸟朝凤》凤鸣）", "r": 3, "c": []}, {"id": "n242", "m": "（4）", "t": "材质（质）：触觉接受，分天然与人工材质，表面组织引起不同生理心理感受（丝绸轻柔、毛皮温暖）", "r": 3, "c": []}, {"id": "n243", "m": "（5）", "t": "味：嗅觉与味觉接受，含味道（川菜“无辣不欢”）与气味（香水“香／臭”判别），有赖联想能力", "r": 3, "c": []}, {"id": "n244", "m": "（6）", "t": "【助记】色—形—声—质—味，五要素配感官（视／视／听／触／嗅味）", "r": 3, "c": []}]}, {"id": "n245", "m": "三、", "t": "为什么说多样统一是美的最高法则", "r": 1, "c": [{"id": "n246", "m": "（1）", "t": "“多样”＝事物个性的千差万别；“统一”＝共性与整体联系，使差异在整体中消融为协调统一体", "r": 3, "c": []}, {"id": "n247", "m": "（2）", "t": "体现人类与大自然的密切联系：自然和谐，人摹仿自然运用形式美法则", "r": 3, "c": []}, {"id": "n248", "m": "（3）", "t": "给人丰富的美感结构层次：既丰富多彩、灵动活泼，又协调一致、安静舒畅", "r": 3, "c": []}, {"id": "n249", "m": "（4）", "t": "结论：因蕴含多种形式美原则、带来多样化美感，故为最高法则（又称“和谐”）", "r": 3, "c": []}, {"id": "n250", "m": "（5）", "t": "【助记】多样×统一＝差异消融；联系自然＋层次丰富＝最高法则（和谐）", "r": 3, "c": []}]}, {"id": "n251", "m": "四、", "t": "形式美的组合规律", "r": 1, "c": [{"id": "n252", "m": "（1）", "t": "对称与均衡：对称＝同形同量（轴／中心对称），稳定端庄（故宫）；均衡＝不追求同形同量、静中有动（毕加索《阅读》）", "r": 3, "c": []}, {"id": "n253", "m": "（2）", "t": "调和与对比：调和趋同、给人协调融合（《天净沙·秋思》）；对比求异、给人鲜明醒目（《雪国》驹子与叶子）", "r": 3, "c": []}, {"id": "n254", "m": "（3）", "t": "比例与尺度：比例＝整体与局部数量关系（黄金分割）；尺度＝主体尺度（客弱于主＝优美，客强于主＝崇高）", "r": 3, "c": []}, {"id": "n255", "m": "（4）", "t": "节奏与韵律：节奏＝运动中有规律的强弱反复；韵律＝赋予情感色彩的节奏", "r": 3, "c": []}, {"id": "n256", "m": "（5）", "t": "多样与统一：把差异因素组合、使其在整体中消融，是最高法则（《诗经》隔行换词，节奏＋对称）", "r": 3, "c": []}, {"id": "n257", "m": "（6）", "t": "【助记】对称均衡／调和对比／比例尺度／节奏韵律／多样统一，五组", "r": 3, "c": []}]}, {"id": "n258", "m": "五、", "t": "如何看待形式美的商品化", "r": 1, "c": [{"id": "n259", "m": "（1）", "t": "是商品经济发展的必然结果：审美需求强化，形式美必然商品化", "r": 3, "c": []}, {"id": "n260", "m": "（2）", "t": "形式产品是重要商品化形象：外貌引起精神需求、提高审美价值（漫威特效、综艺高音）", "r": 3, "c": []}, {"id": "n261", "m": "（3）", "t": "品牌标志是衍生凝结物：符号凝结形式美感、直接对话精神需求（可口可乐、MINISO）", "r": 3, "c": []}, {"id": "n262", "m": "（4）", "t": "需保持谨慎态度：大众文化易扭曲形式美（DIOR水晶拖鞋），须以美学规范市场", "r": 3, "c": []}, {"id": "n263", "m": "（5）", "t": "【助记】必然结果→形式产品＋品牌标志→谨慎（防扭曲）", "r": 3, "c": []}]}, {"id": "n264", "m": "六、", "t": "形式美与时尚的关系", "r": 1, "c": [{"id": "n265", "m": "（1）", "t": "求新倾向对“美”的追求决定时尚风向：感官易疲劳，追求刺激催生集体追求（波旁王朝香水）", "r": 3, "c": []}, {"id": "n266", "m": "（2）", "t": "时尚变化有规律可循：求新心理周而复始，对旧风尚作修正与激活（2024“周王陶林”；仙侠套路）", "r": 3, "c": []}, {"id": "n267", "m": "（3）", "t": "时尚一定程度左右主体对形式美的判定：人困于心灵惰性、被畸形时尚改变判断标准（《歌手2024》现象）", "r": 3, "c": []}, {"id": "n268", "m": "（4）", "t": "【助记】求新定风向＋有规律＋左右判断", "r": 3, "c": []}]}, {"id": "n269", "m": "七、", "t": "形式美与黄金分割比（填空速记）", "r": 1, "c": [{"id": "n270", "m": "（1）", "t": "形式美是实践中体会把握的、伴随目的与规律统一方式的自由感；实践活动分生命体自身活动与谋生活动两类", "r": 3, "c": []}, {"id": "n271", "m": "（2）", "t": "使用工具是人类劳动区别于动物活动的标志；马克思“色彩的感觉是一般美感中最大众化的形式”", "r": 3, "c": []}, {"id": "n272", "m": "（3）", "t": "器物造型三类：模仿自然形态、对其大幅改造、抽象几何造型；质感＝长期实践中获得的触觉记忆", "r": 3, "c": []}, {"id": "n273", "m": "（4）", "t": "黄金分割率＝公元前6世纪古希腊毕达哥拉斯学派发现（较长段与较短段之比1.618∶1时美感最大）", "r": 3, "c": []}, {"id": "n274", "m": "（5）", "t": "形式美最高法则称为“和谐”；可被直接或间接地商品化；基本规律＝对称均衡、调和对比、比例尺度、节奏韵律、多样统一", "r": 3, "c": []}, {"id": "n275", "m": "（6）", "t": "【助记】自由感＋工具标志＋色彩最大众化；造型三类／质感触觉；黄金比（毕／前6世纪／1.618）；最高＝和谐", "r": 3, "c": []}]}], "tb": []}, {"id": "c4", "title": "第四章 技术美", "color": "#9A6FE0", "nodes": [{"id": "n277", "m": "一、", "t": "技术与艺术的区别", "r": 1, "c": [{"id": "n278", "m": "（1）", "t": "本质与目的：技术追求效率、准确、可重复，解决实际问题；艺术追求美感、情感共鸣与精神满足，传达情感思想", "r": 3, "c": []}, {"id": "n279", "m": "（2）", "t": "表现形式：技术以工艺流程、设计图、操作方法出现、可商品化；艺术以色彩线条声音动作传达、形式多样", "r": 3, "c": []}, {"id": "n280", "m": "（3）", "t": "评价标准：技术基于客观性能指标（速度、精度、可靠性）；艺术具主观性，受喜好、文化与审美观影响、难有客观标准", "r": 3, "c": []}, {"id": "n281", "m": "（4）", "t": "【助记】本质（效率／美感）—形式（流程／多样）—评价（客观／主观）", "r": 3, "c": []}]}, {"id": "n282", "m": "二、", "t": "为什么设计是技术与艺术的结合", "r": 1, "c": [{"id": "n283", "m": "（1）", "t": "设计受科技影响，结合美学因素创作，带来实用与美观结合的产品", "r": 3, "c": []}, {"id": "n284", "m": "（2）", "t": "审美性应寓于实用性之中：围绕实际使用要求，从材料、造型、色彩装饰多方面结合考虑", "r": 3, "c": []}, {"id": "n285", "m": "（3）", "t": "实用工艺品应适用、经济、美观：在满足物质需要同时满足精神需要，美观地位日益重要", "r": 3, "c": []}, {"id": "n286", "m": "（4）", "t": "【助记】科技＋美学；审美寓于实用；适用经济美观", "r": 3, "c": []}]}, {"id": "n287", "m": "三、", "t": "艺术美、功能美与“实用是否就是美”", "r": 1, "c": [{"id": "n288", "m": "（1）", "t": "艺术美：一种观念存在的反映美", "r": 3, "c": []}, {"id": "n289", "m": "（2）", "t": "功能美：人在使用产品过程中所感受到的、产品形式符号对功能目的最大化实现后的审美表现美，克服单纯形式观点", "r": 3, "c": []}, {"id": "n290", "m": "（3）", "t": "实用并不等于美：功利价值与审美价值性质不同，产品可有实用却缺审美（未实现对功能目的的审美表现）", "r": 3, "c": []}, {"id": "n291", "m": "（4）", "t": "功能美的意义：具丰富文化内涵（直观科技成就）、促进环境与人协调、激发购买欲促进流通", "r": 3, "c": []}, {"id": "n292", "m": "（5）", "t": "【助记】艺术美（观念反映）／功能美（功能目的的审美表现）；实用≠美；功能美三意义", "r": 3, "c": []}]}, {"id": "n293", "m": "四、", "t": "技术、艺术、装饰（名词解释）", "r": 1, "c": [{"id": "n294", "m": "（1）", "t": "技术：人从事生产活动的手段，自觉应用客观规律调控人与自然的物质交换，是历史范畴（亚里士多德＝“制作的智慧”）", "r": 3, "c": []}, {"id": "n295", "m": "（2）", "t": "艺术：在掌握技艺基础上按规律进行的美的创造，是人自由本质的精神对象化方式；以形式美为手段、技术美为结构、社会美为主题、自然美为形态榜样", "r": 3, "c": []}, {"id": "n296", "m": "（3）", "t": "装饰：动词＝按美的规律装点对象使审美特性鲜明，名词＝具审美效果的成品；艺术对日常生活审美化改造即发挥装饰功能", "r": 3, "c": []}, {"id": "n297", "m": "（4）", "t": "【助记】技术（手段／制作智慧）／艺术（美的创造／对象化）／装饰（装点＋成品）", "r": 3, "c": []}]}, {"id": "n298", "m": "五、", "t": "技术美要点（填空速记）", "r": 1, "c": [{"id": "n299", "m": "（1）", "t": "亚里士多德把技术看作“制作的智慧”；技术对象功能确定、按目标制造、具预期性", "r": 3, "c": []}, {"id": "n300", "m": "（2）", "t": "英国手工艺运动倡导者约翰·罗斯金：“机器本身没有灵魂，它会让人类也同样失去灵魂”", "r": 3, "c": []}, {"id": "n301", "m": "（3）", "t": "技术美的核心是功能美；实用产品的功能价值是其各种价值的核心部分", "r": 3, "c": []}, {"id": "n302", "m": "（4）", "t": "【助记】制作智慧＋预期性；罗斯金机器无灵魂；核心＝功能美", "r": 3, "c": []}]}], "tb": []}, {"id": "c5", "title": "第五章 社会美", "color": "#48A9C5", "nodes": [{"id": "n304", "m": "一、", "t": "社会美在审美形态中的特殊意义", "r": 1, "c": [{"id": "n305", "m": "（1）", "t": "最先产生：是人类最早、最基本的审美领域，是审美活动的基础与起点", "r": 3, "c": []}, {"id": "n306", "m": "（2）", "t": "与人社会存在关系最密切：距离最近、接触最多、欣赏最方便，直接关联日常生活与社会实践", "r": 3, "c": []}, {"id": "n307", "m": "（3）", "t": "在实现人和人生审美化的历史进程中占重要地位，现代性背景下愈加重要", "r": 3, "c": []}, {"id": "n308", "m": "（4）", "t": "能培育正确人生观世界观、人的尊严意识与高尚情操，促进社会和谐进步", "r": 3, "c": []}, {"id": "n309", "m": "（5）", "t": "【助记】最早—最近—审美化历程—育人（观念＋情操）", "r": 3, "c": []}]}, {"id": "n310", "m": "二、", "t": "社会美的特征", "r": 1, "c": [{"id": "n311", "m": "（1）", "t": "是人类社会实践产物最直接的现实存在形式（“光之教堂”；《咱们工人有力量》）", "r": 3, "c": []}, {"id": "n312", "m": "（2）", "t": "直接体现人的自由自觉特性：目的意识带来自觉、合规律实现目的带来自由（《感动中国》）", "r": 3, "c": []}, {"id": "n313", "m": "（3）", "t": "具较直接的功利性内容、体现明显价值取向，并有时代性、民族性（许劭“月旦评”）", "r": 3, "c": []}, {"id": "n314", "m": "（4）", "t": "形式感从属于直接的美的内容：内容支配形式导致审美差异性与趣味的阶级差异", "r": 3, "c": []}, {"id": "n315", "m": "（5）", "t": "【助记】实践产物—自由自觉—功利价值（时代民族）—内容支配形式", "r": 3, "c": []}]}, {"id": "n316", "m": "三、", "t": "社会交往如何可能引起美感", "r": 1, "c": [{"id": "n317", "m": "（1）", "t": "语言交流最能体现道德修养与精神境界：语言美＝生动、准确、得体（新批评论语言公共性）", "r": 3, "c": []}, {"id": "n318", "m": "（2）", "t": "形体交际产生具象化的美：肢体、眼神超越语言显精神境界（佛陀“拈花一笑”）", "r": 3, "c": []}, {"id": "n319", "m": "（3）", "t": "心灵交融是彼此心意相通、精神交融的理想境界（“高山流水”俞伯牙钟子期）", "r": 3, "c": []}, {"id": "n320", "m": "（4）", "t": "【助记】语言（道德修养）—形体（具象）—心灵（交融）", "r": 3, "c": []}]}, {"id": "n321", "m": "四、", "t": "巴赫金的狂欢理论", "r": 1, "c": [{"id": "n322", "m": "（1）", "t": "出处：主要见于《陀思妥耶夫斯基创作问题》（又《诗学问题》）", "r": 3, "c": []}, {"id": "n323", "m": "（2）", "t": "前提＝两种世界、两种生活的划分：第一世界官方、严肃、等级森严；第二世界狂欢广场式、“颠倒的世界”", "r": 3, "c": []}, {"id": "n324", "m": "（3）", "t": "第二生活打破阶级、财产、门第、等级、身份、性别界限，人平等亲昵地交往游戏", "r": 3, "c": []}, {"id": "n325", "m": "（4）", "t": "重视人类的笑文学，主张从狂欢化考察体裁与人物发展", "r": 3, "c": []}, {"id": "n326", "m": "（5）", "t": "提倡平等对待一切体裁语言风格、否定权威性，以狂欢化思维颠覆逻各斯中心主义、发掘创造性潜力", "r": 3, "c": []}, {"id": "n327", "m": "（6）", "t": "【助记】两世界（官方／狂欢）＋打破界限＋笑文学＋反逻各斯", "r": 3, "c": []}]}, {"id": "n328", "m": "五、", "t": "社会美与人体美的关系", "r": 1, "c": [{"id": "n329", "m": "（1）", "t": "人物美是社会美的重要形式：作为实践主体的人对社会实践有直接影响（《感动中国》）", "r": 3, "c": []}, {"id": "n330", "m": "（2）", "t": "人物美含人体美与人格美两部分", "r": 3, "c": [{"id": "n331", "m": "①", "t": "人体美：相貌、身材、姿态等，衡量标准是比例、色彩等形式因素（《断臂的维纳斯》；敦煌飞天）", "r": 4, "c": []}, {"id": "n332", "m": "②", "t": "人格美：形体行为中体现的人格魅力与崇高精神境界，含明确价值取向（“曾点气象”）", "r": 4, "c": []}]}, {"id": "n333", "m": "（3）", "t": "辩证统一：社会美诞生于人作为实践主体的活动，人自身的美（人物美）也被纳入社会美、成为重要组成", "r": 3, "c": []}, {"id": "n334", "m": "（4）", "t": "【助记】人物美＝社会美分支；含人体（形式）＋人格（精神）；主体与部分辩证统一", "r": 3, "c": []}]}, {"id": "n335", "m": "六、", "t": "人体美及如何感受一个人的美", "r": 1, "c": [{"id": "n336", "m": "（1）", "t": "人体美：指相貌、身材、姿态、动作、肤色、仪表等方面的美", "r": 3, "c": []}, {"id": "n337", "m": "（2）", "t": "是自然因素与社会因素的统一：依赖自然生理条件，但被社会生活经历改造，最终显现人的感性生命", "r": 3, "c": []}, {"id": "n338", "m": "（3）", "t": "感受一个人的美：既欣赏外在人体美，也欣赏形体行为中的人格魅力与崇高精神，表达对人精神力量的崇敬与对自由的追求", "r": 3, "c": []}, {"id": "n339", "m": "（4）", "t": "【助记】人体美＝自然×社会；既看外在＋更看人格（精神／自由）", "r": 3, "c": []}]}, {"id": "n340", "m": "七、", "t": "曾点气象与人物美（名词解释）", "r": 1, "c": [{"id": "n341", "m": "（1）", "t": "社会美：以劳动为核心形成的审美形态，范围广泛，含社会实践活动、实践成果、实践主体（人）的美", "r": 3, "c": []}, {"id": "n342", "m": "（2）", "t": "人物美：人自身显现的美，含侧重外在的人体美与侧重内在精神的人格美", "r": 3, "c": []}, {"id": "n343", "m": "（3）", "t": "曾点气象：曾皙之评，“气象”本于孟子“养气说”，是人格美品评用语；孔子赞曾皙“暮春浴沂”、寄寓悠游自乐的人生理想，从本体论肯定美的社会形态", "r": 3, "c": []}, {"id": "n344", "m": "（4）", "t": "【助记】社会美（劳动核心／活动成果人）；人物美（人体＋人格）；曾点气象（养气／人格美／暮春浴沂）", "r": 3, "c": []}]}, {"id": "n345", "m": "八、", "t": "社会美要点（填空速记）", "r": 1, "c": [{"id": "n346", "m": "（1）", "t": "人物美属于社会美；尼采认为节庆狂欢的生活状态是酒神精神的表现", "r": 3, "c": []}, {"id": "n347", "m": "（2）", "t": "欧洲雕塑史三座高峰：菲狄亚斯、米开朗基罗、罗丹；魏晋《世说新语》多处品评人物之美", "r": 3, "c": []}, {"id": "n348", "m": "（3）", "t": "西方中世纪对人体美持否认态度；《拾穗者》是米勒的名画", "r": 3, "c": []}, {"id": "n349", "m": "（4）", "t": "朱光潜提出“人生艺术化”：“知道生活的人就是艺术家，他的生活就是艺术作品”；语言美是社会美的主要内容", "r": 3, "c": []}, {"id": "n350", "m": "（5）", "t": "车尔尼雪夫斯基《艺术与现实的审美关系》：“美是生活”“美是应当如此的生活”", "r": 3, "c": []}, {"id": "n351", "m": "（6）", "t": "【助记】人物美属社会美／酒神狂欢／三高峰／世说新语／中世纪否认／米勒拾穗／朱光潜人生艺术化／语言美", "r": 3, "c": []}]}], "tb": []}, {"id": "c6", "title": "第六章 自然美", "color": "#C7603F", "nodes": [{"id": "n353", "m": "一、", "t": "自然美的内涵", "r": 1, "c": [{"id": "n354", "m": "（1）", "t": "外在自然物之美：狭义＝非人工自然事物之美（与艺术美、社会美并列）；广义＝含自然与社会事物的所有现实事物之美（与艺术美并列）", "r": 3, "c": []}, {"id": "n355", "m": "（2）", "t": "从单整看：既指单个自然事物之美，也指一定范围全部自然事物的整体之美", "r": 3, "c": []}, {"id": "n356", "m": "（3）", "t": "内在天性之美三层：天地万物自在自足的本然状态；人生最高境界的自由状态；艺术的审美理想或最高境界（“芙蓉出水”）", "r": 3, "c": []}, {"id": "n357", "m": "（4）", "t": "地位：在中国古典美学中是涵盖自然、艺术、人生社会诸领域的核心审美范畴", "r": 3, "c": []}, {"id": "n358", "m": "（5）", "t": "【助记】外在（狭／广、单／整）＋内在天性（本然／自由／芙蓉出水）", "r": 3, "c": []}]}, {"id": "n359", "m": "二、", "t": "自然美的特性", "r": 1, "c": [{"id": "n360", "m": "（1）", "t": "对自然事物属性的依赖性／鲜明的自然性：是自然属性与社会属性的统一（峨眉佛光、挪威极光）", "r": 3, "c": []}, {"id": "n361", "m": "（2）", "t": "内容相对朦胧广泛：与实践目的联系间接、人化成果隐藏较深（马尔代夫“湛蓝之眼”因人而异）", "r": 3, "c": []}, {"id": "n362", "m": "（3）", "t": "形态多变且具变异性：景观多样（《醉翁亭记》），心境视角不同致美感变异（黛玉悲秋／刘禹锡乐秋）", "r": 3, "c": []}, {"id": "n363", "m": "（4）", "t": "在场性与不可传达性：须亲身全身心参与，感官发展不同故难以等量传达（《雨中曲》塞纳河；《有风的地方》洱海）", "r": 3, "c": []}, {"id": "n364", "m": "（5）", "t": "【助记】依赖自然性—朦胧广泛—多变变异—在场不可传达", "r": 3, "c": []}]}, {"id": "n365", "m": "三、", "t": "自然美的欣赏模式", "r": 1, "c": [{"id": "n366", "m": "（1）", "t": "如画模式：以艺术品风景画为典范欣赏自然（苏轼“江山如画”）", "r": 3, "c": []}, {"id": "n367", "m": "（2）", "t": "比德模式：中国独有，将君子品格与自然比附（《诗经·淇奥》“谦谦君子，温润如玉”），放大道德、忽略自在美感", "r": 3, "c": []}, {"id": "n368", "m": "（3）", "t": "宇宙模式：以宇宙为美的源泉（毕派数学原则；庄子“天地之美”浑然天成）", "r": 3, "c": []}, {"id": "n369", "m": "（4）", "t": "天成之美：存在论意义的天成境界（庄子先“齐物”后“与游”；刘伶《酒德颂》以天地为被床）", "r": 3, "c": []}, {"id": "n370", "m": "（5）", "t": "【助记】如画—比德—宇宙—天成，四模式", "r": 3, "c": []}]}, {"id": "n371", "m": "四、", "t": "如何理解中国美学中的“自然”", "r": 1, "c": [{"id": "n372", "m": "（1）", "t": "发端于庄子“天籁”，兼具自然界之美与内在天性之美", "r": 3, "c": []}, {"id": "n373", "m": "（2）", "t": "对自然景物的审美化：含山水悟道、比附美德、热爱自然三类（“柳暗花明”悟理；《淇奥》比德；谢灵运“池塘生春草”）", "r": 3, "c": []}, {"id": "n374", "m": "（3）", "t": "人与人交往中的美感：欣赏天真朴素不矫饰的言语与本真天成的人生（苏轼“好诗冲口”；《世说新语》谢道韫咏雪）", "r": 3, "c": []}, {"id": "n375", "m": "（4）", "t": "艺术品中“芙蓉出水”的天然美：超越一切人工技巧，即无意、无法、无工（苏轼“随物赋形”）", "r": 3, "c": []}, {"id": "n376", "m": "（5）", "t": "【助记】源天籁；景物审美化（悟道／比德／热爱）＋人生交往（朴素本真）＋艺术天然（芙蓉出水）", "r": 3, "c": []}]}, {"id": "n377", "m": "五、", "t": "为什么当今人们特别强调自然美", "r": 1, "c": [{"id": "n378", "m": "（1）", "t": "自然美与道德美的共通性：休谟《人性论》指二者共同因素是产生快乐的能力", "r": 3, "c": []}, {"id": "n379", "m": "（2）", "t": "自然审美的普遍性与现代性：18世纪英国欣赏自然成为普遍的现代性存在", "r": 3, "c": []}, {"id": "n380", "m": "（3）", "t": "自然美的独立性与内在构成：生态学视角下是内容与形式合一、反映自然作为生命体的内在美", "r": 3, "c": []}, {"id": "n381", "m": "（4）", "t": "自然审美的价值与意义：自然美作为生命之美是自由的最高象征", "r": 3, "c": []}, {"id": "n382", "m": "（5）", "t": "现代性进程中审美自觉的角色：推动感性精神解放，促进对自然与生命的理解与尊重", "r": 3, "c": []}, {"id": "n383", "m": "（6）", "t": "【助记】道德共通—普遍现代性—独立（生态）—自由象征—感性解放", "r": 3, "c": []}]}, {"id": "n384", "m": "六、", "t": "自然美、比德说、天籁（名词解释）", "r": 1, "c": [{"id": "n385", "m": "（1）", "t": "自然美：含外在非人工自然物之美与事物内在天性之美两种基本内涵", "r": 3, "c": []}, {"id": "n386", "m": "（2）", "t": "比德说：儒家自然美观念，主体从客体品味人格化道德美（“以玉比德”“以水比德”）；提供切身参照系，但僵化感知、忽略非道德愉快", "r": 3, "c": []}, {"id": "n387", "m": "（3）", "t": "天籁：出自《庄子》，各物因自然状态自发之声；庄子分地籁、人籁、天籁，天籁为最高，返归自然、无我无物的浑然状态", "r": 3, "c": []}, {"id": "n388", "m": "（4）", "t": "自然的人化：人的对象活动使天然生态变人工生态的过程，辩证深化人对第一自然的美感认识", "r": 3, "c": []}, {"id": "n389", "m": "（5）", "t": "【助记】自然美（外／内）；比德（儒／玉水／道德）；天籁（庄子／最高／浑然）；人化（天然→人工）", "r": 3, "c": []}]}, {"id": "n390", "m": "七、", "t": "自然美要点（填空速记）", "r": 1, "c": [{"id": "n391", "m": "（1）", "t": "20世纪50年代美学大讨论中，自然美讨论集中在自然美的“性质”问题上", "r": 3, "c": []}, {"id": "n392", "m": "（2）", "t": "中国人对自然美的发现始于魏晋时期；西方对自然美的发现始于文艺复兴时期", "r": 3, "c": []}, {"id": "n393", "m": "（3）", "t": "黑格尔主张艺术美高于自然美；“自然总是美的”是肯定美学的观点", "r": 3, "c": []}, {"id": "n394", "m": "（4）", "t": "西方以“如画”概念评论自然美发端于17世纪、盛行于18世纪", "r": 3, "c": []}, {"id": "n395", "m": "（5）", "t": "“比德”是中国传统尤其儒家最重要的自然美欣赏模式；道家是“物化”模式（主体存在状态同化为对象状态）", "r": 3, "c": []}, {"id": "n396", "m": "（6）", "t": "晋代郭象、清代郭庆藩注《庄子》将自然而然的存在称为“天然”；推崇自然与天然是老庄哲学重要内容", "r": 3, "c": []}, {"id": "n397", "m": "（7）", "t": "【助记】50年代论性质；中国魏晋／西方文艺复兴；黑格尔艺＞自；如画17→18；比德（儒）／物化（道）；郭象郭庆藩“天然”", "r": 3, "c": []}]}], "tb": []}, {"id": "c7", "title": "第七章 艺术美", "color": "#6FA84B", "nodes": [{"id": "n399", "m": "一、", "t": "审美共通感在艺术美中的作用与影响", "r": 1, "c": [{"id": "n400", "m": "（1）", "t": "帮助美的本质在不同艺术形式中交叉呈现（“典雅”见于雅乐与楷书；“崇高”见于俄狄浦斯）", "r": 3, "c": []}, {"id": "n401", "m": "（2）", "t": "形成主体的认同感与归属感（“妈祖”信仰凝聚闽文化区；“高尔基研究学会”）", "r": 3, "c": []}, {"id": "n402", "m": "（3）", "t": "促进艺术审美特性的传播（“河”被符号化：《虞美人》《小河淌水》《春江水暖》）", "r": 3, "c": []}, {"id": "n403", "m": "（4）", "t": "促进各地各种艺术形式的交流（《查拉图斯特拉如是说》催生鲁迅“立人”与艾略特《荒原》；“汤莎会”）", "r": 3, "c": []}, {"id": "n404", "m": "（5）", "t": "升华艺术的意义（“奇境游历”原型中西并见：《格列佛游记》《老残游记》）", "r": 3, "c": []}, {"id": "n405", "m": "（6）", "t": "【助记】交叉呈现—认同归属—传播—交流—升华，五点", "r": 3, "c": []}]}, {"id": "n406", "m": "二、", "t": "如何理解艺术独立的现代性", "r": 1, "c": [{"id": "n407", "m": "（1）", "t": "艺术与审美价值的独立：审美价值占据重要地位，艺术细腻精致（扇子由纳凉到增添绘画装饰）", "r": 3, "c": []}, {"id": "n408", "m": "（2）", "t": "与现代化运动紧密相关：启蒙祛魅、世俗化把世界分为科学、道德、艺术三领域，分别以真、善、美为最高原则", "r": 3, "c": []}, {"id": "n409", "m": "（3）", "t": "体现在艺术形式与理念的现代“变异”：抽象主义、野兽派、立体主义、未来主义关注本体与感性欲望，崇尚活力、批判与未完成状态", "r": 3, "c": []}, {"id": "n410", "m": "（4）", "t": "【助记】价值独立—现代化（真善美三分）—形式变异（诸流派／未完成）", "r": 3, "c": []}]}, {"id": "n411", "m": "三、", "t": "如何理解艺术终结论", "r": 1, "c": [{"id": "n412", "m": "（1）", "t": "存有被“误读”的历史：瓦萨里《大艺术家》、黑格尔“艺术丧失生命”，但身后仍有艺术繁荣", "r": 3, "c": []}, {"id": "n413", "m": "（2）", "t": "是艺术观念的转型：现存艺术观念因语境转型，黑格尔“象征—古典—浪漫”中浪漫型瓦解后理念回到以精神表现精神（宗教或哲学）", "r": 3, "c": []}, {"id": "n414", "m": "（3）", "t": "反映艺术的市场化：科技与复制使艺术消融于日常生活，非复制艺术只能作收藏品", "r": 3, "c": []}, {"id": "n415", "m": "（4）", "t": "反映人们对艺术与哲学的危机感：提供批判视角，提醒人的尊严与存在危机", "r": 3, "c": []}, {"id": "n416", "m": "（5）", "t": "【助记】误读—观念转型（浪漫型瓦解）—市场化—危机感", "r": 3, "c": []}]}, {"id": "n417", "m": "四、", "t": "如何把握艺术美与人生艺术化的内在关系", "r": 1, "c": [{"id": "n418", "m": "（1）", "t": "商品经济推动艺术场所泛化：科技打破艺术、场所、欣赏者的距离，文化民主化，艺术进入日常生活", "r": 3, "c": []}, {"id": "n419", "m": "（2）", "t": "人生与艺术是一对辩证范畴：人生本质上是一种广义的艺术，人通过品味艺术审视并艺术化加工人生", "r": 3, "c": []}, {"id": "n420", "m": "（3）", "t": "艺术美装点人生的艺术化：用艺术美装点改造主体人生，艺术美由对象观审转向主体自我完善体验", "r": 3, "c": []}, {"id": "n421", "m": "（4）", "t": "【助记】场所泛化—人生／艺术辩证—艺术美装点（转向自我完善）", "r": 3, "c": []}]}, {"id": "n422", "m": "五、", "t": "如何理解日常生活审美化", "r": 1, "c": [{"id": "n423", "m": "（1）", "t": "最早由英国美学家迈克·费瑟斯通提出", "r": 3, "c": []}, {"id": "n424", "m": "（2）", "t": "日常生活中的一切被审美化：占据大众文化的不再是诗画经典艺术，而是流行歌曲、广告等泛化门类（崔健摇滚、J-pop、K-pop）", "r": 3, "c": []}, {"id": "n425", "m": "（3）", "t": "艺术和审美进入日常生活、被日常生活化", "r": 3, "c": [{"id": "n426", "m": "①", "t": "艺术场所与生活场所界限消失：城市广场、购物中心中文化、审美、商业活动无严格界限（书店“方所”）", "r": 4, "c": []}, {"id": "n427", "m": "②", "t": "艺术产品自动化：见到艺术产品频率提高、消解原先神圣意义（“蒙娜丽莎”瓷砖）", "r": 4, "c": []}]}, {"id": "n428", "m": "（4）", "t": "【助记】费瑟斯通；一切被审美化（泛门类）＋进入日常（场所消失＋产品自动化）", "r": 3, "c": []}]}, {"id": "n429", "m": "六、", "t": "艺术美、艺术意象、日常生活审美化（名词解释）", "r": 1, "c": [{"id": "n430", "m": "（1）", "t": "艺术美：艺术形态的审美对象，是现实审美自觉形态与艺术独立的产物（现代性下结合为“美的艺术”），表现审美趣味、观念与理想，是审美交流传播的自觉形态", "r": 3, "c": []}, {"id": "n431", "m": "（2）", "t": "艺术意象：朱光潜、宗白华结合艺术美与传统“意象”论，主体之情与对象之景融合，凝聚人生升华，创作者与欣赏者双向交流", "r": 3, "c": []}, {"id": "n432", "m": "（3）", "t": "日常生活的审美化：费瑟斯通提出，含艺术与审美进入日常生活、日常生活产品与环境被审美化两方面", "r": 3, "c": []}, {"id": "n433", "m": "（4）", "t": "【助记】艺术美（美的艺术／二次对象化）；艺术意象（朱宗／情景融合）；日常审美化（费瑟斯通／两方面）", "r": 3, "c": []}]}, {"id": "n434", "m": "七、", "t": "艺术美要点（填空速记）", "r": 1, "c": [{"id": "n435", "m": "（1）", "t": "黑格尔把艺术分为象征型、古典型、浪漫型，浪漫型是“内容压倒形式”", "r": 3, "c": []}, {"id": "n436", "m": "（2）", "t": "艺术美再现社会交往中的美主要表现在“惩恶”与“扬善”；再现人物美主要分“圣贤”与“英雄”两类", "r": 3, "c": []}, {"id": "n437", "m": "（3）", "t": "艺术终结问题黑格尔最早提出；20世纪丹托以现代与后现代艺术为背景重提；“艺术的终结”意味当代艺术对象与日常事物边界消失", "r": 3, "c": []}, {"id": "n438", "m": "（4）", "t": "意境作为美学范畴形成于唐代；杜夫海纳分艺术作品为艺术质料、主题、表现性三层；桑塔亚那分为材料、形式、表现三层", "r": 3, "c": []}, {"id": "n439", "m": "（5）", "t": "杜尚开启装置艺术、磨掉艺术品与现成物的区分；“美的艺术”的出现标志艺术的独立；欧洲古代与中世纪有“自由的艺术”与“粗俗（机械）的艺术”分野", "r": 3, "c": []}, {"id": "n440", "m": "（6）", "t": "艺术创造以现实审美为基础；罗中立油画《父亲》是我国农民生存状态的缩影；人生艺术化含人生成为艺术对象、艺术审美关注人生两方面", "r": 3, "c": []}, {"id": "n441", "m": "（7）", "t": "【助记】黑三型（浪漫＝内容压形式）／惩恶扬善·圣贤英雄／终结（黑→丹托·边界消失）／意境唐代·杜夫海纳·桑塔亚那三层／杜尚装置·美的艺术标志独立／《父亲》", "r": 3, "c": []}]}], "tb": []}, {"id": "c8", "title": "第八章 作为审美范畴的优美与崇高", "color": "#D2A032", "nodes": [{"id": "n443", "m": "一、", "t": "优美和崇高的联系和区别", "r": 1, "c": [{"id": "n444", "m": "（1）", "t": "联系", "r": 3, "c": [{"id": "n445", "m": "①", "t": "都是西方美学基本形态，都是认识改造自然与社会生活中积累的审美体验，是主客体相互作用的结果", "r": 4, "c": []}, {"id": "n446", "m": "②", "t": "美学史上先有“优美”（曾等同于美），认识提高后“美”分化为优美与崇高，崇高为优美作补充与参照", "r": 4, "c": []}]}, {"id": "n447", "m": "（2）", "t": "区别", "r": 3, "c": [{"id": "n448", "m": "①", "t": "内在结构：优美是规律与目的统一、主客和谐完满；崇高突出主客、感性与理性的矛盾对立，含由痛到快感", "r": 4, "c": []}, {"id": "n449", "m": "②", "t": "外在形式：优美柔媚安静、小巧平缓圆润，多见于艺术与自然；崇高突出“大”、趋无限、甚至反常怪异，多见于社会美与自然美", "r": 4, "c": []}, {"id": "n450", "m": "③", "t": "审美享受：优美是直观愉悦、轻松心旷神怡；崇高是痛苦的愉悦，由紧张压力经抗争转向骄傲自豪", "r": 4, "c": []}]}, {"id": "n451", "m": "（3）", "t": "【助记】联系（主客作用＋优先于崇高）；区别三维＝结构（和谐／对立）、形式（小巧／大）、享受（愉悦／痛苦愉悦）", "r": 3, "c": []}]}, {"id": "n452", "m": "二、", "t": "优美的特征", "r": 1, "c": [{"id": "n453", "m": "（1）", "t": "规律与目的相统一是优美的内在结构：是本质力量对象化的结果，对象秀丽单纯完整，心灵柔和舒畅", "r": 3, "c": []}, {"id": "n454", "m": "（2）", "t": "对象表现出静态特征：侧重结果展示、少矛盾冲突（谢朓“好诗圆美流转如弹丸”）", "r": 3, "c": []}, {"id": "n455", "m": "（3）", "t": "以形式美为主要表现方式：偏重小巧纤细、平缓光滑（王维《山居秋暝》人景情统一）", "r": 3, "c": []}, {"id": "n456", "m": "（4）", "t": "最终效果是“审美愉快”：消除紧张、达到心理和谐，是审美形态感受的最高境界", "r": 3, "c": []}, {"id": "n457", "m": "（5）", "t": "【助记】规律目的统一—静态—形式美—审美愉快", "r": 3, "c": []}]}, {"id": "n458", "m": "三、", "t": "崇高的特征", "r": 1, "c": [{"id": "n459", "m": "（1）", "t": "个体处于压迫状态，带社会总体伦理道德：以个体牺牲显示人本质力量的伟大（《俄狄浦斯王》）", "r": 3, "c": []}, {"id": "n460", "m": "（2）", "t": "以庄严、宏伟为外在特征，表现主体斗争与反抗的美（南北战争废奴、抗日战争；鲁迅“俯首甘为孺子牛”）", "r": 3, "c": []}, {"id": "n461", "m": "（3）", "t": "外形突出特征为“大”、趋向无限性：极致是“无限”，达极致后反转为粗糙丑陋的反传统特征（泰山封禅）", "r": 3, "c": []}, {"id": "n462", "m": "（4）", "t": "给人痛苦的愉悦：经由紧张压力与抗争，自觉意识到伟大持久的人类本质力量（《普罗米修斯》盗火）", "r": 3, "c": []}, {"id": "n463", "m": "（5）", "t": "【助记】个体压迫（伦理）—庄严斗争—“大”趋无限—痛苦愉悦", "r": 3, "c": []}]}, {"id": "n464", "m": "四、", "t": "从现代性语境看崇高的生成和演变", "r": 1, "c": [{"id": "n465", "m": "（1）", "t": "从审美文化史看：优美是人类最早注意的范畴，崇高更晚近、属近代以后；近代工业化打破田园和谐、矛盾冲突成常态，崇高是其审美反映，也反映文明更高成就", "r": 3, "c": []}, {"id": "n466", "m": "（2）", "t": "范畴主要从西方引进：中国古代有“大”“阳刚”“风骨”；朗吉弩斯《论崇高》最早提出，博克并立优美与崇高（崇高以痛感为基础），康德分数学的与力学的崇高，黑格尔“理念压倒形式”", "r": 3, "c": []}, {"id": "n467", "m": "（3）", "t": "【助记】晚近近代（工业化矛盾）；西方源流＝朗吉弩斯→博克→康德（数学／力学）→黑格尔", "r": 3, "c": []}]}, {"id": "n468", "m": "五、", "t": "优美与崇高的相互转化", "r": 1, "c": [{"id": "n469", "m": "（1）", "t": "基本规律：由崇高趋向优美再转向崇高，由审美本质（真与善、合规律与合目的统一）规定", "r": 3, "c": [{"id": "n470", "m": "①", "t": "由崇高到优美：遭遇阻力牺牲时呈崇高，矛盾趋和谐、规律目的统一时转优美（姚鼐《登泰山记》迷雾冰滑→苍山负雪→坐观日出）", "r": 4, "c": []}, {"id": "n471", "m": "②", "t": "由优美到崇高：新因素介入致不平衡、又从无冲突走向冲突（叙事学“突转”；普洛普“王子救公主”；“白素贞”）", "r": 4, "c": []}]}, {"id": "n472", "m": "（2）", "t": "转换产生新的审美范畴：被客体压倒→悲剧（《美狄亚》《浮士德》）；对抗力量落后→可笑（《伪君子》《钦差大臣》）；失合规律合目的→丑或荒诞（《秃头歌女》《禁闭》）", "r": 3, "c": []}, {"id": "n473", "m": "（3）", "t": "【助记】崇⇄优（登泰山／突转）；衍生＝悲剧／喜剧／丑荒诞", "r": 3, "c": []}]}, {"id": "n474", "m": "六、", "t": "结合现代审美状况分析崇高的现代意义", "r": 1, "c": [{"id": "n475", "m": "（1）", "t": "重塑新的人性建设与完善现代主体：对抗后现代审美贫困与媚俗，解放个体压抑、激活生命力（北岛《回答》“我不相信”）", "r": 3, "c": []}, {"id": "n476", "m": "（2）", "t": "唤醒人类集体的审美共通感：把个体痛觉转化为人类普遍荣耀感（马尔克斯《百年孤独》）", "r": 3, "c": []}, {"id": "n477", "m": "（3）", "t": "聚合人自由的个性与社会的使命：是生命精神与实践目的的回归（海明威《老人与海》）", "r": 3, "c": []}, {"id": "n478", "m": "（4）", "t": "【助记】重塑主体—唤醒共通感—聚合个性与使命", "r": 3, "c": []}]}, {"id": "n479", "m": "七、", "t": "优美、崇高、中和之美（名词解释）", "r": 1, "c": [{"id": "n480", "m": "（1）", "t": "优美：又称秀美，狭义美，与崇高相对，形式小巧柔和清新秀丽圆润，内容无激烈冲突、矛盾相对静止，形式内容协调和谐，给人赏心悦目", "r": 3, "c": []}, {"id": "n481", "m": "（2）", "t": "崇高：与优美相对，外形突出为“大”、含反常巨大粗糙甚至丑陋，内在侧重本质对象化的曲折过程、主客矛盾对立，给人“痛苦的愉悦”", "r": 3, "c": []}, {"id": "n482", "m": "（3）", "t": "中和之美：中国古代审美形态的最高典范，外在调和阴柔与阳刚，内在将对象与主体、美与善、形式与内容普遍化，给人温柔敦厚的精神享受", "r": 3, "c": []}, {"id": "n483", "m": "（4）", "t": "【助记】优美（秀美／和谐／悦目）；崇高（大／对立／痛苦愉悦）；中和（最高典范／阴阳调和／温柔敦厚）", "r": 3, "c": []}]}, {"id": "n484", "m": "八、", "t": "优美与崇高要点（填空速记）", "r": 1, "c": [{"id": "n485", "m": "（1）", "t": "古罗马朗吉弩斯《论崇高》明确提出并论证“崇高”后，崇高才进入美学思考范围", "r": 3, "c": []}, {"id": "n486", "m": "（2）", "t": "优美感的获得＝本质力量对象化的完满实现、主观合目的性与客观合规律性的内在统一", "r": 3, "c": []}, {"id": "n487", "m": "（3）", "t": "毕达哥拉斯用数解释美、亚里士多德把美的形式规定为“秩序、匀称与明确”，都指“优美”", "r": 3, "c": []}, {"id": "n488", "m": "（4）", "t": "崇高突出形式特征“大”、趋无限；黑格尔认为崇高是内在理念压倒形式；崇高是自由个性与社会使命的统一", "r": 3, "c": []}, {"id": "n489", "m": "（5）", "t": "当本质实现对象化、矛盾相对和谐、规律目的统一时，崇高感可向优美感转化", "r": 3, "c": []}, {"id": "n490", "m": "（6）", "t": "【助记】朗吉弩斯／优美＝完满统一／毕亚＝优美／崇高＝大·理念压形式·个性使命统一", "r": 3, "c": []}]}], "tb": []}, {"id": "c9", "title": "第九章 悲剧和喜剧", "color": "#7E84F2", "nodes": [{"id": "n492", "m": "一、", "t": "悲剧的审美特征", "r": 1, "c": [{"id": "n493", "m": "（1）", "t": "至少有一个值得同情与认同的个性化人物作主人公", "r": 3, "c": []}, {"id": "n494", "m": "（2）", "t": "主人公遭遇结局不幸的灾祸、失败或死亡，常使个性毁灭或人性受伤", "r": 3, "c": []}, {"id": "n495", "m": "（3）", "t": "所受痛苦死亡及人性伤害既必然不可避免，又不正当、令人不可接受", "r": 3, "c": []}, {"id": "n496", "m": "（4）", "t": "会引发恐惧、怜悯与悲伤等复杂情感，甚至发生精神提升或转变（《巴黎圣母院》《红楼梦》《俄狄浦斯王》）", "r": 3, "c": []}, {"id": "n497", "m": "（5）", "t": "【助记】同情人物—不幸毁灭—必然又不当—恐惧怜悯（净化提升）", "r": 3, "c": []}]}, {"id": "n498", "m": "二、", "t": "喜剧的审美特征", "r": 1, "c": [{"id": "n499", "m": "（1）", "t": "喜剧人物的无价值或反价值性（《吝啬鬼》阿巴贡视财如命）", "r": 3, "c": []}, {"id": "n500", "m": "（2）", "t": "喜剧事件的矛盾性与可笑性：形式不和谐、内容可笑（阿巴贡要儿娶寡妇、自己与儿子爱同一女人）", "r": 3, "c": []}, {"id": "n501", "m": "（3）", "t": "喜剧矛盾的突发性：有悬念、急转直下、出乎意料（《你好，李焕英》沈光林）", "r": 3, "c": []}, {"id": "n502", "m": "（4）", "t": "喜剧效果的愉悦性：直接强烈、有大众性，含讽刺、批判与同情（《儒林外史》范进中举）", "r": 3, "c": []}, {"id": "n503", "m": "（5）", "t": "【助记】无价值人物—矛盾可笑—突发—愉悦（讽刺批判同情）", "r": 3, "c": []}]}, {"id": "n504", "m": "三、", "t": "崇高和悲剧的联系和区别", "r": 1, "c": [{"id": "n505", "m": "（1）", "t": "联系", "r": 3, "c": [{"id": "n506", "m": "①", "t": "内容上都展现主人公本质对象化中的矛盾激化、艰难斗争与对抗", "r": 4, "c": []}, {"id": "n507", "m": "②", "t": "目的上都在暂时失败中激发对人本质的伟大自豪感与必胜信心", "r": 4, "c": []}, {"id": "n508", "m": "③", "t": "心理上都在压迫中升华出“痛苦”的快感", "r": 4, "c": []}]}, {"id": "n509", "m": "（2）", "t": "区别", "r": 3, "c": [{"id": "n510", "m": "①", "t": "崇高突出斗争精神与胜利前景；悲剧偏重条件限制与主体不可避免的失败、人性毁灭", "r": 4, "c": []}, {"id": "n511", "m": "②", "t": "崇高突出人类整体背景、引导道德升华；悲剧侧重个体命运、刺激个体意识觉醒", "r": 4, "c": []}, {"id": "n512", "m": "③", "t": "崇高性悲剧还含非崇高性的深邃哲理（三岛由纪夫《金阁寺》）", "r": 4, "c": []}, {"id": "n513", "m": "④", "t": "悲剧审美范围较小（只涉人的行为或事件）；崇高对象还可是自然景观（玉龙雪山）", "r": 4, "c": []}]}, {"id": "n514", "m": "（3）", "t": "【助记】联系（矛盾斗争／自豪／痛苦快感）；区别（胜利前景／失败、整体／个体、含哲理、范围小／含自然）", "r": 3, "c": []}]}, {"id": "n515", "m": "四、", "t": "悲剧和喜剧的本质", "r": 1, "c": [{"id": "n516", "m": "（1）", "t": "悲剧本质：主人公因坚持正义或积极进取而与现实环境冲突，感性生命毁灭却成就精神生命永恒价值，使心灵净化、精神提升", "r": 3, "c": []}, {"id": "n517", "m": "（2）", "t": "恩格斯：悲剧本质是“历史的必然要求和这个要求的实际上不可能实现之间的悲剧性冲突”", "r": 3, "c": []}, {"id": "n518", "m": "（3）", "t": "喜剧本质：以笑为手段否定生活中不协调的形式、肯定其中的美，是强烈的讽刺与揭露，核心是对喜剧主人公遮蔽自我或人性本质的揭露", "r": 3, "c": []}, {"id": "n519", "m": "（4）", "t": "【助记】悲剧（正义×现实／精神胜利／恩格斯必然要求）；喜剧（以笑否定／讽刺揭露）", "r": 3, "c": []}]}, {"id": "n520", "m": "五、", "t": "净化说、乖谬说、突然荣耀说（名词解释）", "r": 1, "c": [{"id": "n521", "m": "（1）", "t": "净化说：朱光潜对亚里士多德《诗学》“卡塔西斯”的翻译，悲剧引发恐惧、怜悯，使精神得到提升与转变，奠定西方悲剧效果认识基础", "r": 3, "c": []}, {"id": "n522", "m": "（2）", "t": "乖谬说／预期失望说：康德《判断力批判》论喜剧效果，可笑之物荒谬不和谐、出乎预料，“笑是紧张的期待突然转变成虚无”（斯宾塞分上升／下降的乖谬）", "r": 3, "c": []}, {"id": "n523", "m": "（3）", "t": "突然荣耀说：18世纪英国霍布斯，喜剧令人发笑在于发现缺点、产生令自己荣耀的优越感，对象含他人与以前的自己", "r": 3, "c": []}, {"id": "n524", "m": "（4）", "t": "【助记】净化（朱译亚／恐惧怜悯）；乖谬（康德／预期落空）；突然荣耀（霍布斯／优越感）", "r": 3, "c": []}]}, {"id": "n525", "m": "六、", "t": "酒神精神与狂欢化理论（名词解释）", "r": 1, "c": [{"id": "n526", "m": "（1）", "t": "酒神精神：尼采《悲剧的诞生》提出，狂欢中打破禁忌、放纵欲望、复归自然，处痛苦与狂喜交织的非理性状态；早期＝从个人毁灭获悲剧性陶醉，后期＝从生命无意义中获陶醉，“太一”消除个体差异", "r": 3, "c": []}, {"id": "n527", "m": "（2）", "t": "狂欢化理论：俄国巴赫金提出，世界分官方等级秩序世界与狂欢广场式生活两个世界，后者打破等级、平等亲昵、颠倒亵渎，使人回复本真存在，是对常态生活的中断与升华", "r": 3, "c": []}, {"id": "n528", "m": "（3）", "t": "【助记】酒神（尼采／非理性／太一）；狂欢化（巴赫金／两世界／回复本真）", "r": 3, "c": []}]}, {"id": "n529", "m": "七、", "t": "悲剧与喜剧要点（填空速记）", "r": 1, "c": [{"id": "n530", "m": "（1）", "t": "悲剧产生于人本质自由遭伤害甚至牺牲时；喜剧产生于本质力量对象化即将实现、主体确定占据矛盾支配地位时", "r": 3, "c": []}, {"id": "n531", "m": "（2）", "t": "鲁迅：“悲剧将人生有价值的东西毁灭给人看，喜剧将那无价值的撕破给人看”", "r": 3, "c": []}, {"id": "n532", "m": "（3）", "t": "命运悲剧代表作《俄狄浦斯王》；悲剧分崇高性悲剧、非崇高性悲剧；悲剧四要素＝悲剧人物、事件、悖论、效果", "r": 3, "c": []}, {"id": "n533", "m": "（4）", "t": "喜剧分肯定性喜剧与否定性喜剧；喜剧四要素＝喜剧人物、事件、矛盾、效果；喜剧矛盾具突发性", "r": 3, "c": []}, {"id": "n534", "m": "（5）", "t": "康德用“预期失望说”解释喜剧（可笑之物荒谬不和谐、出乎意料、期待突然消失）", "r": 3, "c": []}, {"id": "n535", "m": "（6）", "t": "【助记】悲（自由受损）／喜（即将实现）；鲁迅名言；悲（俄狄浦斯／两类／四要素）；喜（两类／四要素／突发／康德）", "r": 3, "c": []}]}], "tb": []}, {"id": "c10", "title": "第十章 丑", "color": "#C2526B", "nodes": [{"id": "n537", "m": "一、", "t": "如何理解作为审美范畴的“丑”", "r": 1, "c": [{"id": "n538", "m": "（1）", "t": "广义的丑：现实对人本质的否定、对目的与规律统一的破坏", "r": 3, "c": [{"id": "n539", "m": "①", "t": "从主客体看：人本质对象化的未实现与残缺，目的性与规律性不统一", "r": 4, "c": []}, {"id": "n540", "m": "②", "t": "从内容与形式看：理性内容与感性形式、理想与现实、社会与自然的背离，是对正常尺度的破坏", "r": 4, "c": []}, {"id": "n541", "m": "③", "t": "从审美感受看：富刺激性、使人不安厌恶，否定与苦味愉悦是其本质属性", "r": 4, "c": []}]}, {"id": "n542", "m": "（2）", "t": "狭义的丑：一种形式美的特殊形态，背离和谐对称均衡等法则，含自然形态、社会形态、艺术形态的丑", "r": 3, "c": []}, {"id": "n543", "m": "（3）", "t": "丑有赖于人类丑感的觉醒：非永恒抽象，现代意义中成为时尚与先锋的重要因素", "r": 3, "c": []}, {"id": "n544", "m": "（4）", "t": "【助记】广义（主客／内形式／感受三视角）＋狭义（反形式美／三形态）＋丑感觉醒", "r": 3, "c": []}]}, {"id": "n545", "m": "二、", "t": "怎样在美丑转化中把握丑的特征", "r": 1, "c": [{"id": "n546", "m": "（1）", "t": "审美活动包括对美的发现与对丑的揭露：两侧面都处于历史过程、不断生成发展", "r": 3, "c": []}, {"id": "n547", "m": "（2）", "t": "丑可使人联想到美或转换为美：亚里士多德认为现实的丑可转化为艺术的美，激活积极生命经验", "r": 3, "c": []}, {"id": "n548", "m": "（3）", "t": "丑依据美的规则进行表现：罗森克兰兹认为丑通过比例、对称等形式美因素表现、削弱不快", "r": 3, "c": []}, {"id": "n549", "m": "（4）", "t": "【助记】发现美＋揭露丑；丑→美（亚）；依美的规则表现（罗森克兰兹）", "r": 3, "c": []}]}, {"id": "n550", "m": "三、", "t": "丑的审美本质", "r": 1, "c": [{"id": "n551", "m": "（1）", "t": "从主客体看：人本质对象化的未实现与残缺，目的性与规律性的不统一", "r": 3, "c": []}, {"id": "n552", "m": "（2）", "t": "从内容与形式看：理性内容与感性形式、理想与现实、社会与自然的背离，对正常尺度的破坏与否定", "r": 3, "c": []}, {"id": "n553", "m": "（3）", "t": "从审美感受看：富刺激性、使人不安厌恶，否定与苦味愉悦是丑的本质属性", "r": 3, "c": []}, {"id": "n554", "m": "（4）", "t": "【助记】未实现残缺—背离尺度—苦味愉悦，三视角", "r": 3, "c": []}]}, {"id": "n555", "m": "四、", "t": "丑与崇高、优美之间的渗透和转换", "r": 1, "c": [{"id": "n556", "m": "（1）", "t": "丑与优美以“反形式”相联：优美和谐圆满，丑反常混乱、不完整不规律不和谐，决不能构成优美整体（《水浒》武大郎外丑内美、潘金莲外美内丑）", "r": 3, "c": []}, {"id": "n557", "m": "（2）", "t": "丑与崇高高度关联：都从个体痛苦转向族群经验、形式上不完整扭曲、观念大于形式；但丑须激活敬仰或牺牲进取意义、且主体取得胜利后才成崇高（《拉奥孔》；《西游记》孙悟空猪八戒）", "r": 3, "c": []}, {"id": "n558", "m": "（3）", "t": "【助记】丑×优美（反形式／内外错位）；丑×崇高（观念大于形式／须主体胜利）", "r": 3, "c": []}]}, {"id": "n559", "m": "五、", "t": "丑的审美范畴", "r": 1, "c": [{"id": "n560", "m": "（1）", "t": "怪：对正常尺度的极端反常变形，含事物变形（“浩克”、烛九阴）、事物关系变形（“聂小倩”由鬼化人）、整个世界图景变形（《爱丽丝梦游仙境》《老残游记》）", "r": 3, "c": []}, {"id": "n561", "m": "（2）", "t": "酷：本质对象化的特定阶段，自恋式认同，含自恋情结、超然嘲讽、享乐主义，是无深度平面文化（“杀马特”、y2k）", "r": 3, "c": []}, {"id": "n562", "m": "（3）", "t": "荒诞：本质分解弥散缺位致无根基、无秩序、无归宿的解体过程，是对虚无的对象化（《等待戈多》）", "r": 3, "c": []}, {"id": "n563", "m": "（4）", "t": "恐怖：对“异形”反常形式的虚构组合，对背后力量的“升格”或神秘化，混合恐惧惊悚崇拜厌恶（《午夜凶铃》贞子；《招魂2》鬼修女）", "r": 3, "c": []}, {"id": "n564", "m": "（5）", "t": "【助记】怪（三变形）—酷（自恋平面）—荒诞（解体虚无）—恐怖（升格神秘）", "r": 3, "c": []}]}, {"id": "n565", "m": "六、", "t": "如何理解荒诞", "r": 1, "c": [{"id": "n566", "m": "（1）", "t": "含义：本质对象化的特定阶段，本质分解弥散缺位致对象化无根基无秩序无归宿，用否定方式曲折肯定人的自由", "r": 3, "c": []}, {"id": "n567", "m": "（2）", "t": "由三对关系存有意义：主客体（主体虚位、客体碎片）、内容与形式（无理性内容的感性形式、无深度平面）、人与他者（人与世界皆无意义、相互冷漠）", "r": 3, "c": []}, {"id": "n568", "m": "（3）", "t": "是现代社会运动结果：高度异化、彻底绝望、孤独无助使荒诞得以生成", "r": 3, "c": []}, {"id": "n569", "m": "（4）", "t": "审美特征：形式碎片化与丑怪（《犀牛》《城堡》）、内容平面化无中心（《喧哗与骚动》《尤利西斯》）、主体零度化与无力感（《人间失格》《沉沦》）", "r": 3, "c": []}, {"id": "n570", "m": "（5）", "t": "【助记】解体过程（曲折肯定自由）；三关系；现代异化产物；三特征（碎片／平面／零度）", "r": 3, "c": []}]}, {"id": "n571", "m": "七、", "t": "丑及相关名词（名词解释）", "r": 1, "c": [{"id": "n572", "m": "（1）", "t": "丑：特殊的否定审美范畴，是人本质对象化的未实现与残缺、对正常尺度的破坏，富刺激性；含自然、社会、艺术三形态", "r": 3, "c": []}, {"id": "n573", "m": "（2）", "t": "恐怖小说：以“恐怖”为审美范畴的小说，分哥特小说与现代恐怖；爱伦·坡是现代恐怖小说开山鼻祖（斯蒂芬·金等）", "r": 3, "c": []}, {"id": "n574", "m": "（3）", "t": "丑的美学：德国罗森克兰兹著，是第一部研究丑的美学专著，标志丑正式成为特殊审美形态、开启现代丑学", "r": 3, "c": []}, {"id": "n575", "m": "（4）", "t": "【助记】丑（否定范畴／三形态）；恐怖小说（哥特／现代·爱伦坡）；《丑的美学》（罗森克兰兹／首部）", "r": 3, "c": []}]}, {"id": "n576", "m": "八、", "t": "丑要点（填空速记）", "r": 1, "c": [{"id": "n577", "m": "（1）", "t": "从审美感受看，丑引起的是复杂的苦味或带苦味的愉快，富刺激性、使人不安厌恶甚至痛苦", "r": 3, "c": []}, {"id": "n578", "m": "（2）", "t": "丑分三类：自然形态的丑、社会形态的丑、艺术形态的丑；审美经验中美与丑共存", "r": 3, "c": []}, {"id": "n579", "m": "（3）", "t": "美丑相互转化两情形：历史文化语境变化使标准互转；现实美丑进入艺术审美转化为对立面", "r": 3, "c": []}, {"id": "n580", "m": "（4）", "t": "马克斯·德索认为丑比美更深刻、审丑比审美更有价值", "r": 3, "c": []}, {"id": "n581", "m": "（5）", "t": "丑与崇高共同点：形式上都不和谐不完整扭曲变形、效果上都引起苦痛感、关系上都观念大于形式", "r": 3, "c": []}, {"id": "n582", "m": "（6）", "t": "丑的审美范畴＝怪、酷、荒诞、恐怖；怪含事物变形、事物关系变形、整个世界图景变形", "r": 3, "c": []}, {"id": "n583", "m": "（7）", "t": "【助记】苦味愉快／三形态／两情形／德索（丑更深刻）／丑崇共同点／怪酷荒诞恐怖", "r": 3, "c": []}]}], "tb": []}, {"id": "c11", "title": "第十一章 美育", "color": "#3C9D7E", "nodes": [{"id": "n585", "m": "一、", "t": "美育的使命", "r": 1, "c": [{"id": "n586", "m": "（1）", "t": "素质教育的保障：美育既是审美教育、也是艺术教育", "r": 3, "c": []}, {"id": "n587", "m": "（2）", "t": "肩负完整人的塑造：以铸造完美人格为核心，以全面发展与创造性培养为旨归（以情感丰富心灵、以艺术启迪智慧、以审美培养情操）", "r": 3, "c": []}, {"id": "n588", "m": "（3）", "t": "决定人类生活的品质：把生活由追求物质提升到追求生活艺术与品位", "r": 3, "c": []}, {"id": "n589", "m": "（4）", "t": "促进和谐社会构建：催化道德、融汇法律（感性理性结合）、促进人与自然和谐", "r": 3, "c": []}, {"id": "n590", "m": "（5）", "t": "【助记】素质保障—完整人—生活品质—和谐社会", "r": 3, "c": []}]}, {"id": "n591", "m": "二、", "t": "美育的特性", "r": 1, "c": [{"id": "n592", "m": "（1）", "t": "从施教手段看是形象教育：通过审美对象媒介、以感性形象诉之于人，使灵魂受到净化（《孔子》、《西南联大》辅助教学）", "r": 3, "c": []}, {"id": "n593", "m": "（2）", "t": "从受教方式看是情感教育：以情服人而非以理服人，须受教者自觉作为审美主体进入体验（朱光潜“美育是一种情感教育”）", "r": 3, "c": []}, {"id": "n594", "m": "（3）", "t": "从受教效果看是快乐教育：接受美育是高级精神享受、获得愉悦的过程（贺拉斯“寓教于乐”）", "r": 3, "c": []}, {"id": "n595", "m": "（4）", "t": "【助记】形象（手段）—情感（方式）—快乐（效果）", "r": 3, "c": []}]}, {"id": "n596", "m": "三、", "t": "美育的功能", "r": 1, "c": [{"id": "n597", "m": "（1）", "t": "培养审美能力：从情感与形象角度提高想象力与理解力、健全审美心理结构", "r": 3, "c": []}, {"id": "n598", "m": "（2）", "t": "陶冶人的性情：在自由审美空间中获得情感振荡、超越与洗涤，潜移默化、带固定性与延续性", "r": 3, "c": []}, {"id": "n599", "m": "（3）", "t": "完善人格：使心理功能自由和谐、进入高尚境界，去“小我”、唤起人的真正价值", "r": 3, "c": []}, {"id": "n600", "m": "（4）", "t": "树立正确的审美观：自觉领略美丑分界，帮助树立正确世界观与审美观", "r": 3, "c": []}, {"id": "n601", "m": "（5）", "t": "【助记】审美能力—陶冶性情—完善人格—正确审美观，四功能", "r": 3, "c": []}]}, {"id": "n602", "m": "四、", "t": "美育的途径", "r": 1, "c": [{"id": "n603", "m": "（1）", "t": "审美理论的学习：含美学基础理论、艺术理论与艺术史、其他审美常识三部分", "r": 3, "c": []}, {"id": "n604", "m": "（2）", "t": "艺术美赏析：对典型艺术品作美学分析、陶冶性情、完善精神人格", "r": 3, "c": []}, {"id": "n605", "m": "（3）", "t": "自然美赏析：生成对大自然的感激与敬畏、达天人合一", "r": 3, "c": []}, {"id": "n606", "m": "（4）", "t": "社会美赏析：明确人生目标、塑造美的形象、激励在生活中发现美创造美", "r": 3, "c": []}, {"id": "n607", "m": "（5）", "t": "【助记】理论—艺术美—自然美—社会美，四途径", "r": 3, "c": []}]}, {"id": "n608", "m": "五、", "t": "美育、寓教于乐、美育书简、以美育代宗教（名词解释）", "r": 1, "c": [{"id": "n609", "m": "（1）", "t": "美育：又称美感教育，通过培养认识、体验、感受、欣赏与创造美的能力，使人具美的理想、情操、品格与素养；分狭义（审美教育）与广义（美学原则渗透各科）", "r": 3, "c": []}, {"id": "n610", "m": "（2）", "t": "寓教于乐：古罗马贺拉斯《诗艺》提出，文艺须既劝谕又使人愉悦，揭示艺术是形式与内容的美的统一", "r": 3, "c": []}, {"id": "n611", "m": "（3）", "t": "《美育书简》：席勒所作，正式提出“美育”概念，以“游戏冲动”消除人性分裂，是第一部以美育为对象的理论著作、“第一部美的宣言书”，但夸大美育作用", "r": 3, "c": []}, {"id": "n612", "m": "（4）", "t": "以美育代宗教说：蔡元培提出，美育自由、进步、普及，宗教强制、保守、有限，反映以美育救国的主张，具进步意义", "r": 3, "c": []}, {"id": "n613", "m": "（5）", "t": "【助记】美育（认识到创造／狭广）；寓教于乐（贺拉斯）；美育书简（席勒／首部宣言书／游戏冲动）；以美育代宗教（蔡元培／三对比）", "r": 3, "c": []}]}, {"id": "n614", "m": "六、", "t": "美育要点（填空速记）", "r": 1, "c": [{"id": "n615", "m": "（1）", "t": "18世纪德国席勒《审美教育书简》正式提出“美育”概念，是“第一部美育的宣言书”", "r": 3, "c": []}, {"id": "n616", "m": "（2）", "t": "蔡元培美育思想最突出的是“以美育代宗教”学说；古罗马诗人贺拉斯第一个提出“寓教于乐”", "r": 3, "c": []}, {"id": "n617", "m": "（3）", "t": "古代美育无论中西都从属于道德教育、是道德教育的补充手段；梁启超首次在中国提出“趣味教育”概念", "r": 3, "c": []}, {"id": "n618", "m": "（4）", "t": "美育的功能：培养审美能力、陶冶性情、完善人格、树立正确的审美观", "r": 3, "c": []}, {"id": "n619", "m": "（5）", "t": "审美理论主要包括：美学基础理论、艺术理论与艺术史、其他审美常识三方面", "r": 3, "c": []}, {"id": "n620", "m": "（6）", "t": "【助记】席勒书简／蔡以美育代宗教／贺拉斯寓教于乐／古代属道德／梁趣味教育／功能四项／理论三方面", "r": 3, "c": []}]}], "tb": []}], "quiz": {"c5": [{"id": "q1", "type": "名词解释", "q": "名词解释：社会美", "a": "是以人类基础性生存活动——劳动为核心所形成的审美形态。由于与人类实践密切相关，社会美的范围十分广泛，它渗透在人类社会生活的方方面面，举凡在人们的社会生活中显现出某种精神价值与自由，都可以成为社会美的审美对象。具体来说，社会美的范围大致可以包括如下几个方面：社会实践活动的美，社会实践成果的美，以及社会实践主体即人的美。"}, {"id": "q2", "type": "名词解释", "q": "名词解释：人物美", "a": "是社会美的重要形式之一。指人自身显现出的美，具体包括人体美与人格美。人体美侧重于外在的方面，通常指人的相貌、身材、姿态、动作、肤色等方面的美。而人格美则主要侧重于内在精神方面，指在人的形体、行为中所体现出的独特的人格魅力以及崇高的精神境界。"}, {"id": "q30", "type": "名词解释", "q": "名词解释：曾点气象", "a": "曾点即曾皙，孔子七十二弟子之一，“气象”则是基于孟子的“养气说”的审美用语，即内心之气与外界之物结合，是人格美的品评用语。曾点气象原是孔子对学生曾皙“暮春者，春服既成，冠者五六人,童子六七人,浴乎沂,风乎舞雩,咏而归。”的评价，表明了悠游自乐的人民生活理想，渗透着以孔子为代表的对“内圣外王”的人格美的追求，经由后世概括而成的赞美用语。对“曾点气象”的点评代表着中国美学自觉地进行人格作为美感的审美探索，代表着审美范畴的进一步扩大，从本体论的角度肯定了美的社会形态。"}, {"id": "q94", "type": "简答", "q": "社会美在审美形态中有什么特殊意义？", "a": "在人类社会最先产生，因而社会美是人类最早、最基本的审美领域；社会美是审美活动的基础和起点，是人类审美经验的重要组成部分。\n社会美是与人的社会存在关系最密切的审美形态，也是与人距离最近、人们接触最多、最频繁、欣赏最方便的审美对象，意味着社会美直接关联于人的日常生活和社会实践，是人们在社会中互动和体验美的最直接方式。\n社会美在实现人和人生的审美化的历史进程中占有重要地位。特别是在现代性的背景下，社会美在人类审美活动中开始占有愈加重要的位置，强调了社会美在现代社会中的重要作用，它不仅关乎个人的审美体验，还涉及到社会文化和精神生活的提升。\n社会美能够培育人正确的人生观和世界观，以及人的尊严意识和高尚情操。通过欣赏社会美，人们可以培养一双善于发现生活之美的眼睛，并使人更加热爱生活。这种作用不仅限于个人层面，还扩展到对整个社会的积极影响，促进社会的和谐与进步。"}, {"id": "q95", "type": "简答", "q": "社会美有哪些特征？", "a": "社会美是人类社会实践产物最直接的现实存在形式。社会美本身体现在人类实践活动及其成果当中，从切身的工具、生产与生活材料，到直接的生产与生活产品，都直接展现了人类合规律性的实践力量，体现出人的创造性与创造。例如安藤忠雄通过改变特定的透光角度，形成了日本知名的建筑物“光之教堂”，是建筑学的重要实践产物；建国初期歌曲《咱们工人有力量》反映了我国人民生产实践的活动美。\n社会美直接体现了人的自由自觉的特性。人类的实践活动因明确的目的意识获得了自觉性，又因符合社会规律、实现预期目的而得到自由性。“感动中国”的节目形式就以人类实践活动的“自由”性发现社会的美。\n社会美具有较为直接的功利性内容，体现出明显的价值取向。社会美包含着人合目的性的追求，指向人的生存与发展、人的提升与超越，体现出对理想生活的追求与向往，人们对社会美进行评判时往往侧重于社会功利性因素。社会美的功利性与价值取向还与特定的时代生活相关，受到各方面因素的制约，体现出明显的时代性、民族性特征。东汉时期许劭每月“人物品评”行为既有时代中“察举”的文化因素，也有对社会个体独立的美感。\n社会美的形式感从属于直接的美的内容。社会美的产生必须从具体的美的美感事物中才能展现，这种内容对形式的支配导致了审美产生差异性，从而审美风格史上审美趣味的阶级差异与对立由此也产生。"}, {"id": "q96", "type": "简答", "q": "社会交往如何可能引起美感？", "a": "语言交流最能体现了人的道德修养与精神境界。社会交往首先体现于语言的层面上，语言为人们沟通信息、交流思想、联络感情提供工具，语言美主要体现为语言的生动、准确、得体。英美新批评提出语言由于其公共性，如果不能做到准确的话，文章内容则会因为公共性对私人性的侵入而导致误读。\n形体交际产生的美是具象化的美。形体交际是通过肢体语言形体动作进行社会交往活动，通常眼神、动作就能显示出超越语言的别样韵味，反映出主体内在的精神境界和生活追求。佛家有佛陀“拈花一笑”就论出刹那永恒的形体美感。\n心灵交融是交往中彼此心意相通、精神交融的效果。社会交往总是人与人之间的交往，体现为精神、思想的交流与沟通，当心灵之间的沟通与交融成为社会交往的理想境界后就具有了审美的趣味。“高山流水”的俞伯牙和钟子期就是彼此心灵的交融与汇通。"}, {"id": "q97", "type": "简答", "q": "简述巴赫金的狂欢理论", "a": "狂欢理论主要见于巴赫金的专著《陀思妥耶夫斯基创作问题》\n前提是两种世界、两种生活的划分。第一世界是官方的、严肃的、等级森严的秩序世界，统治阶级拥有无限的权力,而平民大众则过着常规的、谨小慎微的日常生活，对权威、权力、真理、教条、死亡充满屈从、崇敬与恐惧。\n而第二世界（第二生活）则是狂欢广场式生活,是在官方世界的彼岸建立起的完全“颠倒的世界”，这是平民大众的世界，打破了阶级、财产、门第、职位、等级、年龄、身份、性别的区分与界限,\n重视人类的笑文学。主张从狂欢化的角度考察文学创作体裁和人物性格的发展变化，强调狂欢化文学传统是人类文学宝库中不可忽视的部分。\n提倡平等对待一切文学体裁、语言和风格等，否定文学艺术创作形式中的一切权威性，反对传统理论重高压文学而轻视低俗文学的美学立场。消除诗学研究的封闭性，加大文学内容和形式的开放性，打破逻各斯中心主义，以狂欢化思维来颠覆理性化思维结构，发掘人类的创造性思维潜力"}, {"id": "q98", "type": "简答", "q": "论述社会美与人体美之间的关系。", "a": "社会美体现在人的社会实践活动之中，作为社会实践活动主体的人，对于社会实践活动的开始、发展与深化有着直接影响，因此人物美就成为社会美的重要形式之一。例如《感动中国》\n人物美包括了人体美与人格美两个部分，是社会美的分支组成。\n①人体美主要指人的相貌、身材、姿态等反面的美，衡量这些美的标准则是社会美中定义的比例、色彩等形式因素。中西方对人体美的判定都基于社会层面的美学经验，例如著名雕塑《断臂的维纳斯》身上透露出的比例、身材等层面的美感；我国的敦煌飞天图也表现出神女身姿曼妙、肢体修长。\n②人格美是在人的形体、行为之中所体现出的独特的人格魅力与崇高的精神境界。在人格美中，往往体现出明确的价值取向和对人的自由与超越的追求，蕴含着对人类生存和发展状态的关切，构成了人格美的精神内涵。“曾点气象”\n综上，社会美与人体美是辩证统一的，主体与部分的关系，社会美的产生诞生于人作为实践主体的实践活动，人与人的结社带来了丰富的集体劳动智慧，从而将社会美对象化。但同时由于人是在整体的社会活动中进行实践，人自身的美感（人物美）也被纳入社会美的部分，成为社会美的重要组成部分。"}, {"id": "q99", "type": "简答", "q": "人体美是什么，如何感受一个人的美？", "a": "人体美通常是指人的相貌、身材、姿态、动作、肤色、仪表等方面的美。\n现实的人体美虽然有赖于人体的自然生理条件和自然素质，但人体决不仅仅是自然的产物，而是被人们的社会生活经历改造过的，因而人体美是自然因素和社会因素的统一\n在人体美中，形体、比例、曲线、色彩等形式因素起着很大的作用，但是，形式因素并不能脱离人的生命整体和人的社会文化环境，人体美最终显现出的是人的感性生命。人的美即人物美是指人自身显现出的美，具体包括侧重于外在方面的人体美与侧重于内在的精神方面的人格美。\n感受一个人的美，既要欣赏其相貌、身材、姿态、动作、肤色、仪表等方面的外在人体美，也要欣赏一个人的形体、行为中所体现出的独特的人格魅力以及崇高的精神境界，表达对人自身精神力量的崇敬与向往，以及对人的超越性与自由的追求。"}, {"id": "q159", "type": "填空", "q": "（____）属于社会美", "a": "人物美属于社会美"}, {"id": "q160", "type": "填空", "q": "（____）认为，节庆狂欢的生活状态是酒神精神的表现", "a": "尼采认为，节庆狂欢的生活状态是酒神精神的表现"}, {"id": "q161", "type": "填空", "q": "欧洲雕塑史上的三座高峰分别是艺术家（____）、（____）和（____）", "a": "欧洲雕塑史上的三座高峰分别是艺术家菲狄亚斯、米开朗基罗和罗丹"}, {"id": "q162", "type": "填空", "q": "我国魏晋时期的（____）多处品评人物之美（魏晋南北朝品评人物美的著作）", "a": "我国魏晋时期的《世说新语》多处品评人物之美（魏晋南北朝品评人物美的著作）"}, {"id": "q163", "type": "填空", "q": "（____）是米勒的名画", "a": "《拾穗者》是米勒的名画"}, {"id": "q164", "type": "填空", "q": "（____）提出了“人生艺术化”的观点，认为“知道生活的人就是艺术家，他的生活就是艺术作品”", "a": "朱光潜提出了“人生艺术化”的观点，认为“知道生活的人就是艺术家，他的生活就是艺术作品”"}, {"id": "q165", "type": "填空", "q": "俄罗斯文艺理论家（____）认为，有两种世界和两种生活第一种是官方的、严肃的、等级森严的秩序世界；第二种则是狂欢广场式生活，是在官方世界的对面建立起的“颠倒的世界”", "a": "俄罗斯文艺理论家巴赫金认为，有两种世界和两种生活第一种是官方的、严肃的、等级森严的秩序世界；第二种则是狂欢广场式生活，是在官方世界的对面建立起的“颠倒的世界”"}], "c3": [{"id": "q3", "type": "名词解释", "q": "名词解释：形式美", "a": "是从美的形式中抽象而出的，独立于内容的美的外在形式。包括两个方面，一是自然、社会和艺术中各种感性形式因素（色彩、线条、形体、声音、味），可以引起人不同的心理反应，二是长期审美过程中人们提炼、概括出的引起人审美愉悦的形式规律，即形式美的法则，是人类对美的形式规律的经验总结和抽象概括，包括对称与均衡，调和与对比，节奏与旋律，比例与尺度，多样与统一。"}, {"id": "q26", "type": "名词解释", "q": "名词解释：黄金分割比", "a": "古希腊毕达哥拉斯学派发现的关于人内在尺度与比例关系。毕达哥拉斯学派通过将线段分成长短不一的两部分，并且根据观感的愉悦总结出了当较长段与较短段的比值为1.618:1时，该几何形式给人的审美快感达到最大化。黄金分割率被发现后，人们发现被称作“美”的形式总是满足黄金分割率，因此在美的实践过程中，艺术家们总是遵从黄金分割的比值进行创造，给欣赏者带来匀称与舒适感，同时又带有适度的变化与活泼。"}, {"id": "q85", "type": "简答", "q": "形式美和美的形式有什么区别？", "a": "形式美是对美的形式的再抽象化，具体区别如下：\n美的形式包括内形式与外形式，强调的是与内容的联系，美的形式不能脱离内容。原始阶段人类对于美的形式的判断与欲望的满足、工具的顺手等内容相关联，美的形式必然是外在的形式/活动与精神活动的目的契合，例如我国傣族的“泼水节”就是美的形式，都分别与丰收、祝福等精神目的相关联。\n形式美是从美的形式中进一步抽象而提取出来的，与内容脱离了直接的关系，是人类对美的形式中外形式产生了独立的审美活动，并从中总结出独立的美感特征，包括了各种形式因素和形式美法则两个部分，就前者而言，人们对“漫威系列”电影的追捧源自好莱坞特效对人的视觉刺激；而就后者，罗丹的《思考者》雕塑就是自觉运用黄金分割比这一美学原则的创造。"}, {"id": "q86", "type": "简答", "q": "试分析形式美的构成要素", "a": "形式美的构成要素主要包括直觉作用于人类感官的各种自然形态，包括有色、形、声音、材质、味五类。\n色是由视觉器官接受的形式因素，并产生与之对应的象征关系，例如红色给人以激情、积极的感受；黑色给人以恐惧、死亡的感受；但在历史与文化的积淀中，色彩也有了不同象征关系，例如因恐怖电影的生产逻辑，人们对“黑-红”的搭配易联想到鬼魂、暴力、血腥。\n形是由视觉接受的形式因素，是通过点、线、面不同结合形成的抽象形态。点是指细小而集中的形态；线是点的运动轨迹，包括了曲线、折线和直线三类；面是线的移动轨迹，不同的面构成了不同的审美风格。形包括模仿自然生物或无生物的造型，例如我国汉代的“马踏飞燕”铜像；还有对自然形态进行大幅度的改造，主要包括夸张、减弱和抽象造型，电影《哥斯拉》序列的怪兽主角哥斯拉就是对蜥蜴的夸张；日本茶道的“侘寂”则是减弱自然对品茶的影响；梵高的画作《星月夜》则是对自然的抽象改造。\n声音是由听觉接受的形式因素。人们从自然的声音中提取出人们能够接受并产生快感的声音，并将其组合，就构成了音乐。声音具有强烈的表情性，人类的情感都能在声音中找到与之对应的形式，例如琵琶曲《十面埋伏》就以急促的琵琶声表现战场冲杀；唢呐曲《百鸟朝凤》则用高亢的唢呐象征凤凰。\n材质是由触觉器官接受的形式因素，质指材质，材质分为天然材质和人工材质。是主要由触觉器官所接受的形式因素，是指材料表面的组织形态特征，如粗糙、光泽、坚硬、厚实等。它们能引起人不同的生理与心理感受。如丝绸的轻柔飘逸引起亲切、柔滑的温情，抚摸丰厚稠密的毛皮给人柔软、温暖的感觉\n味包括味道和气味，是由嗅觉器官和味觉器官接受的形式因素。味道主要是人的味蕾……"}, {"id": "q87", "type": "简答", "q": "为什么说多样统一是美的最高法则？", "a": "“多样”是指事物个性的千差万别，“统一”是千差万别事物的共性和整体联系。多样统一把具有差异、变化、对立的各种形式因素有机组合在一起，使得差异、变化、对立的各种形式因素有机地组合在一起，使得差异在整体中消除，构成了一个协调一致的统一体，包含了各种形式美的法则。\n多样统一体现了人类与大自然的密切联系。大自然是和谐的，自然界中的所有按照自然地规律存在、变化和发展，构成了丰富的自然风光；人类摹仿自然，在美感的创造中运用多种形式美的法则，体现出和谐整一的美感。\n多样统一给人以丰富的美感结构层次。和谐统一的美既让人感到丰富多彩，灵动活泼，又协调一致，安静舒畅，给人以极高的审美享受。\n综上，多样统一因创造物（美的事物）内部蕴含的多种形式美原则让人体验到多样化的美感感受，故而是美的最高法则。"}, {"id": "q88", "type": "简答", "q": "形式美有哪些组合规律？", "a": "对称与均衡。对称讲求以对称中心的同形同量对应，包括有轴对称和中心对称两种形式，是人们最早获得的关于形式美的法则规律。对明显特征是稳定性，对称的事物给人以安静、稳定、端庄的美感，例如我国的故宫博物院建筑群就呈现出明显的对称性，给人以强烈的庄严感；均衡是对称的变体，是一种不追求同形同量的对称，被称为静中有动，给人以活泼灵巧的动态美感。抽象主义画作大多都是均衡美学的体现，毕加索的《阅读》将阅读中的女人脸部畸形化，在毫无对称中心的状态以左右不均衡表现了诡异的平静\n调和与对比是不同形式因素的并列比较，调和趋同，对比求异。调和是两种不同而又接近的元素并列，一般包括同类质素搭配和临近质素搭配两种形式，给人以协调、融合的美感，马致远的《天净沙·秋思》就是将最能代表“悲秋”传统的景物调和共演；对比则是突出不同质素各自的特征，给人带来鲜明、振奋、醒目、活跃的美感，例如川端康成《雪国》中驹子和叶子的对比，既突出了驹子身上的热烈与激情，又表现出叶子的温柔与端庄。\n比例与尺度。比例指一件事物整体与局部以及局部与局部之间的数量关系。而符合形式美法则的比例关系是指人认为合适的、能让人感到满意和喜欢的比例，这人在实践中逐步形成的一种形式感觉。例如西方的黄金分割比例。尺度更强调的是一种主体尺度，强调主体与客体的比例关系。西方美学家在区分优美、崇高等范畴时使用的就是主体尺度，客体比主体弱小就能产生优美与优美感，比主体更强大甚至到了主体难以把握时就产生崇高与崇高感。\n节奏与韵律\n节奏：指形式因素在运动中有秩序的变化，有规律的组合和反复。把运动中的强弱变化有规律地组合起来加以反复便形成节奏。例如，亚里士多德《诗学》强……"}, {"id": "q89", "type": "简答", "q": "如何看待形式美的商品化？", "a": "美学商品化是商品经济发展的必然结果。当商品社会发展到一定程度后，审美需求逐步强化，形式美也必然发生商品化。\n形式产品是形式美的重要商品化形象。商品市场中不同产品呈现出的不同外貌是消费者选购的重要依据，是人对商品进行精神需求判断的直接媒介，形式产品所以具有的形式美能够引起人们的精神需求，提高商品的审美价值。在具体商业生产中，例如电影工业中“漫威”序列电影就以大量的特效堆叠吸引观众眼球，在歌曲竞演综艺中，高音、强混等技巧也往往能够换来观众的青睐。\n品牌标志是形式美的衍生凝结物。延伸产品是顾客购买产品时所得到的利益综合，是企业在产品实体外附加的一系列因素，其中最典型的是品牌标志，品牌标志的符号特征凝结了相当程度的形式美感，并且通过符号对应关系直接与人的精神需求对话，例如可口可乐、MINISO等商品标志背后凝结的形式美经验。\n对形式美的商品化需要保持谨慎态度。形式美进入市场代表了人类社会的进步与发展，确证了人类审美经验的普遍性，代表了人类生产力与精神能力的提高。但大众文化的特质与形式美混合后容易对形式美发生扭曲，对美学发起挑战，例如DIOR的水晶拖鞋等现象，所以在形式美商品化中需求保持谨慎的态度，以美学规范形式美的市场发展。"}, {"id": "q90", "type": "简答", "q": "分析形式美与时尚的关系。", "a": "时尚的含义是时髦、时兴等语义，与形式有着密切的关联，时尚是人类求新倾向的直接反映，表现为对不同形式美的追捧与需求，具体分析如下：\n求新倾向对“美”的追求决定着时尚的风向。“新”与“旧”是一组相对的概念，其主要特征在于变化。人们通过外界刺激满足自己的心理需求，但由于人的适应性，感官是容易疲劳的，感官本身追求的刺激诞生了某特定时期对美感的集体追求，即时尚。时尚随着人类群体的审美需求变化而变化，处在始终变化的状态，波旁王朝时期皇室贵族追求不洗澡为风尚，并由此掀起了对香水的变态追求。\n时尚的变化有着相当的规律可循。人类求新求变心理发展具有周而复始的特征，由此时尚的发展总有相当规律的规律可循。人们在不同时代将自己投射回到历史当中谋求认识的过程实际上是对主宰时尚过久的形式的厌倦，但创造性的局限性无法产生新的物象，于是对历史的风尚作出修正与激活。例如在2024年华语流行音乐圈仍然困在“周王陶林”的时代中；仙侠恋爱剧仍然遵循着“按照颜值分配财产和地位，按照地位分配道德与性格”的旧有套路当中。\n时尚一定程度上左右着主体对形式美的判定。时尚的发展具有独立性，处在某种时尚中的人们困于心灵的惰性，任由某种“时尚”发展，在无形中被畸形的时尚改变了形式美的判断标准，无法发现新的形式美。《歌手2024》现象佐证了长期被滞留于国内音综的观众们的审美能力，是群体性的关于形式美判断能力的反思。"}, {"id": "q148", "type": "填空", "q": "（____）是人类劳动区别于动物活动的标志", "a": "使用工具是人类劳动区别于动物活动的标志"}, {"id": "q149", "type": "填空", "q": "马克思认为，“（____）”", "a": "马克思认为，“色彩的感觉是一般美感中最大众化的形式”"}, {"id": "q150", "type": "填空", "q": "（____）是人类在长期实践活动中获得的关于材料与对象的（____）", "a": "质感是人类在长期实践活动中获得的关于材料与对象的触觉记忆"}, {"id": "q151", "type": "填空", "q": "“（____）”是公元前6世纪古希腊的毕达哥拉斯学派发现的", "a": "“黄金分割率”是公元前6世纪古希腊的毕达哥拉斯学派发现的"}, {"id": "q152", "type": "填空", "q": "形式美的最高法则称为（____）", "a": "形式美的最高法则称为和谐"}, {"id": "q153", "type": "填空", "q": "形式美可以被直接或间接地（____）", "a": "形式美可以被直接或间接地商品化"}, {"id": "q154", "type": "填空", "q": "形式美的基本规律：（____）；（____）；（____）；（____）；（____）", "a": "形式美的基本规律：对称与平衡；调和与对比；比例与尺度；节奏与韵律；多样与统一"}], "c6": [{"id": "q4", "type": "名词解释", "q": "名词解释：自然美", "a": "总体上也存在着外在非人工的自然物之美与事物的内在天性之美两种基本内涵"}, {"id": "q12", "type": "名词解释", "q": "名词解释：比德说", "a": "儒家重要的自然美观念，即自然事物的美感意义在于审美主体能够从审美客体当中品味到某种人格化的道德美。“比德”的常见形式有“以玉比德”和“于水比德”两种模式，后来被儒学家们拓展化，将儒家对人的人格理想与自然比附，强调审美活动的本质是人提高自身品德的过程。“比德说”在我国美学史上的影响十分巨大，为人们欣赏自然美提供了一种切身的参照系；但由于过分强调美与道德观念的关联，比德说也僵化了审美主体的感知能力，忽略了自然本质的美给予人的非道德愉快。"}, {"id": "q32", "type": "名词解释", "q": "名词解释：天籁", "a": "出自《庄子》，指代各物因其自然状态而自己发出的声音，是天地间音响中的一种。庄子将世间美感分为三类，地籁、人籁与天籁。天籁是美的最高境界。在庄子看来，美是返归自然，无我无物的浑然状态，呈现出万物谐和、自然中心的新精神境界，反映了庄子美学思想中返璞归真的特质。在艺术创作中，天籁被用作形容诗文的浑然天成的淳朴状态，文论家们用“天籁”比喻那些没有任何工笔痕迹的，符合自然规律的艺术品，反映了自然美与人类审美的密切关系。"}, {"id": "q100", "type": "简答", "q": "自然美的内涵是怎样的？", "a": "自然美因限制于“自然”的不同内涵而产生了如下三种含义：\n与自然概念总体外在中的自然事物与内在的天性两种内涵对应，自然美也包括了非人工的自然物之美和事物的内在天性之美。\n就外在自然美概念而言，自然美既可以狭义地指代非人工的自然事物的美，也可指广义的包括自然事物与社会事物在内的所有现实事物的美感；从单个事物来看，自然美既可以指单个自然事物的美，也可以指一定范围内的全部自然事物整体的美。\n就内在天性的自然概念而言，自然美主要包括三种内涵，一是天地万物自然自足的本然状态；二是人生最高境界的自由状态；三是艺术的审美理想或最高境界。"}, {"id": "q101", "type": "简答", "q": "自然美的特性有哪些？", "a": "对自然事物及其属性的依赖性或鲜明的自然性。自然美是自然属性和社会属性的统一，自然物的物质属性提供了美感产生的前提和基础，例如峨眉佛光、挪威极光；但自然美的总结产生也必然需要经过人类社会的实践活动，所以作为一种社会价值，自然美与人类的形式美范畴息息相关。\n内容相对朦胧广泛。自然美通社会实践目的性的联系相对间接，人的对象化本质与自然人化的成果被隐藏较深，由而在内容意蕴上其含义模糊、宽泛切难以琢磨，例如对马尔代夫“湛蓝之眼”的美感因人而异，描述多样而广泛；自然美形象清晰鲜明、具体生动，鲜艳的色彩、悦耳的声响都通过形式美给人以美的享受，例如普罗旺斯的薰衣草海就以强烈的紫色给人难忘的印象；云贵川交界处的“鸡鸣三省”现象则以听觉形成了诧异感。\n形态多变且具有变异性。自然美因自然景观的变化呈现出多样，欧阳修就在《醉翁亭记》中记录“若夫日出而林霏开，云归而岩穴暝”，另一方面，人因面对自然景观的心境、视角不同从而导致了对同一美感的变异呈现。林黛玉《秋窗风雨夕》悲秋；而刘禹锡却说“自古逢秋悲寂寥，我言秋日胜春朝”乐秋。\n在场性与不可传达性。自然事物环境的特殊性要求人们必须亲身经历其中才能感受美感，人类在美的自然风光中必然需要全身心的参与，采用所有的感官去体验自然的美；而每个人的感官功能发展情况不同，所以针对某一自然美感的现象无法进行等量的传达。就在场性而言，人们观看法国电影《雨中曲》看到的塞纳河与亲自到场视觉所及的塞纳河情感完全是不同的；就不可传递性而言，对待同样的风景，大理洱海的船夫与《有风的地方》中对洱海的感受是完全不同的。"}, {"id": "q102", "type": "简答", "q": "自然美的欣赏模式有哪些？", "a": "如画模式。如画观念首先体现了人们欣赏真实的自然风景和作为艺术品的风景画的一种态度，人们将艺术美中的自然美题材的典型化，而将其引导为现实中的自然美欣赏的典范，从画作出发欣赏自然风光。例如苏轼《念奴娇·赤壁怀古》就有“江山如画，一时多少豪杰”，把江山与画作关联，将英雄争斗不休的美学原因点出。\n比德模式。比德是中国美学独有的自然观察模式，是将儒家君子品格与自然界事物相比附的审美欣赏模式，比德模式当中自然风景的美感完全基于审美主体是否满足儒家的君子风范，忽略了自然界自在美感，过分放大了道德在自然美欣赏中的作用。《诗经·淇奥》篇就有“谦谦君子，温润如玉”将君子的谦逊与玉石相比附。\n宇宙模式。将宇宙当做美的源泉，毕达哥拉斯学派提出宇宙万事万物都符合相当程度的数学原则，这种美感的比例是自然自生的，人类只能模拟却无法更改；而就事物的自然性特征而言，我国的庄子指出“宇宙”模式则换用“天地之美”的名称，认为自然美不在于对人类实用性的适应，而是万物浑然天成的状态。\n（4）天成之美。对于存在论意义上的人的自然审美而言，自然美是一种天成境界之美。例如庄子先“齐物”后“与游”；魏晋刘伶《酒德颂》就有“以天为被，以地为床，河水为邻,清风做伴”的语句，将自我丢入天地当中，放弃主体的首要性与自然一道齐一。"}, {"id": "q103", "type": "简答", "q": "如何理解中国美学中的“自然”？", "a": "中国美学中的“自然”发端于庄子的“天籁”思想，同时具有作为自然界之美的自然美与作为内在天性之美的自然美的涵义：\n“自然”首先表现为对自然景物的审美化。汉魏六朝时期我国视野从传统的社会交往转向了对山水风光的发掘。我国对“自然”的审美化主要包括三种类型，一是山水悟道；二是比附美德，三是热爱自然，在对山水的审美转向中三种方法都发挥了相当的作用。其一如“山重水复疑无路，柳暗花明又一村”，从山水当中体悟玄理；其二如《诗经·淇奥》篇就有“谦谦君子，温润如玉”将君子的谦逊与玉石相比附；其三如谢灵运《登池上楼》中“池塘生春草”，表现出诗人眼光被自然风光牵引后的细致观察。\n“自然”是人生社会中人与人交往的美感。“自然”意味着对天真朴素而不虚伪不矫饰的人言语的欣赏，意味着人各种生活的自然化和对本真天成的人生自由境界的亲身体验。前者如苏轼形容诗人创作的诗文应当遵循“好诗冲口谁能择”，强调语言的直接性与不装饰；后者如《世说新语》中记录了“谢家咏雪”篇章，谢道韫一氏虽身为名门，但仍然天真浪漫，颇具士人风度。\n“自然”是艺术品当中的“芙蓉出水”的天然美。在艺术品中，自然美意味着对一切人工技巧的超越，即无意、无法与无工。例如苏轼谈论诗文时强调“随物赋形”，要求从心而出，不加选择。"}, {"id": "q104", "type": "简答", "q": "为什么当今人们特别强调“自然美”？", "a": "自然美与道德美的共通性：休谟在《人性论》中提到，自然美和道德美共同的因素是产生快乐的能力，这表明自然美不仅具有审美价值，还与道德评价相关联，反映了人类对美的普遍追求和道德情感的共鸣。\n自然审美的普遍性与现代性：18世纪的英国，文化精英们对自然美景的欣赏成为一种普遍的现代性存在，这种对自然美的追求和想象，标志着自然审美在当时的英国已成为一种重要的文化现象和社会实践。\n自然美的独立性与内在构成：自然美被定义为现实生活(或自然界)中自然物的美，但这一定义可以进一步深化。在生态学的视角下，自然美不仅是形式性的，而是内容与形式合一的，反映了自然作为生命体的内在美和审美价值的独立性。\n自然审美的价值与意义：自然美作为生命之美，是自然而然的，它是自由的最高象征。通过审美的眼光观照日常生活，可以发现充满情趣的意象世界，显现出生活的本真状态和深刻的历史意蕴。\n现代性进程中审美自觉的角色：在现代性进程中，审美自觉推动着人们感性精神的解放。自然审美作为一种重要的审美实践，不仅丰富了人们的感官体验，还促进了人们对自然和生命的深刻理解与尊重。"}, {"id": "q166", "type": "填空", "q": "在20世纪50年代的美学大讨论中，对于自然美讨论集中在自然美的（____）问题上", "a": "在20世纪50年代的美学大讨论中，对于自然美讨论集中在自然美的（性质）问题上"}, {"id": "q167", "type": "填空", "q": "中国人对于自然美的发现始于（____）时期", "a": "中国人对于自然美的发现始于魏晋时期"}, {"id": "q168", "type": "填空", "q": "西方对于自然美的发现始于（____）时期", "a": "西方对于自然美的发现始于文艺复兴时期"}, {"id": "q169", "type": "填空", "q": "（____）主张艺术美高于自然美", "a": "黑格尔主张艺术美高于自然美"}, {"id": "q170", "type": "填空", "q": "在西方，以“（____）”概念评论自然美，发端于17世纪，盛行于18世纪", "a": "在西方，以“如画”概念评论自然美，发端于17世纪，盛行于18世纪"}, {"id": "q171", "type": "填空", "q": "“（____）”模式是中国传统美学尤其是儒家美学最重要的自然美欣赏模式", "a": "“比德”模式是中国传统美学尤其是儒家美学最重要的自然美欣赏模式"}, {"id": "q172", "type": "填空", "q": "晋代的郭象、清代的郭庆藩在注释《庄子》时，将自然而然的存在状态称为“（____）”", "a": "晋代的郭象、清代的郭庆藩在注释《庄子》时，将自然而然的存在状态称为“天然”"}, {"id": "q173", "type": "填空", "q": "推崇（____），是老庄哲学的重要内容", "a": "推崇自然与天然，是老庄哲学的重要内容"}], "c7": [{"id": "q5", "type": "名词解释", "q": "名词解释：艺术美", "a": "艺术形态的审美对象。艺术美的产生有两条基本线索：它既是现实审美发展的自觉形态，又是艺术自身经历人类活动分工化而独立的产物。这二者在现代性背景下结合为“美的艺术”。按照马克思以美的规律塑造的思想，艺术美承担着对现实审美更高综合的使命，代表着更高更自觉的审美理想，因此要进一步表现二次对象化人的自由理想：艺术美表现审美趣味、审美观念与审美理想，同时是审美交流与传播的自觉形态"}, {"id": "q33", "type": "名词解释", "q": "名词解释：艺术意象", "a": "指艺术领域的意象呈现，朱光潜与宗白华结合了艺术美与我国传统美学中的“意象”论结合后的产物，意象主体将自身情感灌注于对象之中，在超越自然对象的层面上形成了独有的意象世界，从而出现了主体之情与对象之景的融合，意象的意蕴丰富产生了艺术美，主体在审美想象中完成艺术体验。艺术意象凝聚了人生的升华，是艺术家为了充分表现自身审美情感而创造的典型形象，在艺术美的体验中，创作者与欣赏者之间发生了双向交流，艺术美通过艺术意象引导主体在审美实践中改造既有生活，建构美好生活。"}, {"id": "q60", "type": "名词解释", "q": "名词解释：日常生活的审美化", "a": "英国美学家费瑟斯通提出的美学概念。费瑟斯通认为当代审美泛化的背后是社会中艺术和生活的距离不断缩小，日常生活得以被艺术化。具体包括两个方面，一是艺术和审美进入日常生活；二是日常生活产品与环境被审美化。大众文化生活中心的已经不是诗歌、绘画等经典的艺术门类，而是一些新兴的泛审美/艺术门类，如广告、流行歌曲乃至居室装修，艺术活动的场所深入到大众的日常生活空间，如城市广场、购物中心等。而在这些场所中，文化活动、审美活动、商业活动、社交活动之间不存在严格的界限。“日常生活审美化”带有鲜明的时代背景，对我们思考生活的美具有启发。"}, {"id": "q105", "type": "简答", "q": "怎样认识审美共通感在艺术美中的作用与影响？", "a": "（1）帮助美的本质在不同的艺术形式中交叉呈现。审美共通感超越了感官的审美快感，不局限于具体的审美活动，帮助审美主体在不同的艺术形式中把握美的快感。在中国的语境中，“典雅”作为一种美的本质能够被主体在中正和谐的“雅乐”与方正沉稳的楷体书法中感受到；在西方的语境中，“崇高”作为一种审美范畴，观众既能在俄狄浦斯面对的无力感中求得。\n（2）形成主体的认同感与归属感。审美共通感是处在相同团体当中的个体们凝聚得到的集体审美经验，它调动了主体的集体审美意识，帮助个体回到具有相同经验的解释群当中，同构着审美集体的形成。关于“妈祖”传说的敬畏感与神往使得闵文化区的人们获得了彼此互认的经验；对高尔基文学艺术的共同经验也推动了“高尔基研究学会”的生成。\n（3）促进了艺术审美特性的传播。艺术美的形成需要审美主体结合审美理想再现外在世界，审美共同感的不断交流赋予了艺术审美特质最大范围的认可和体验，调动了更多的主体体验艺术带来的审美享受。作为一种美感的形式，“河”已经被我国文化传统高度的符号化，出现在各种艺术当中，例如李煜的《虞美人》、民歌《小河淌水》、电影《春江水暖》等，在不同的艺术形式中，“河”被赋予了时光流逝、愁绪、民族魂等多种含义，这只有通过中华民族的审美共通性才能认识。\n（4）促进各地各种艺术形式的交流。拥有审美共同感的审美主体可以产生审美共鸣，不同审美主体同样可以进行审美交流，各个国家与民族的审美共同感在交流中不断碰撞融合，形成了更为广阔的审美空间与审美的共同体。可以产生一是对同一艺术形式产生共同认识，对《查拉图斯特拉如是说》的价值认识使得东方出现了鲁迅的“立人”主张，西方则出现了艾略特的《荒……"}, {"id": "q106", "type": "简答", "q": "如何理解艺术独立的现代性？", "a": "（1）艺术与审美价值的独立。现代社会的不断发展带来了主体思想的逐渐成熟，传统的与实用技术与功利目的结合的艺术也逐渐被人的美感发掘，艺术的审美价值逐渐占据重要地位，艺术变得细腻且精致化，例如传统社会中“扇子”的目的是扇风纳凉，现代意义的扇子则增添了更多的绘画装饰。\n（2）艺术独立与现代化运动紧密相关。作为一种现代社会的产物，艺术独立的现代性欲现代运动紧密相关，现代性运动过程是一个启蒙祛魅和世俗化的过程，它以理性破除了传统社会中的统一的世界观，将其分为科学、道德和艺术三个独立的文化领域，并形成了分别以真、善、美为最高价值原则的专业体系，反映了启蒙现代性的基本特性。\n（3）艺术独立的现代性体现在艺术形式与艺术理念的现代“变异”中。现代社会的消费行为解放了艺术家的创作心灵，艺术家的职业化带来了对传统神学世界艺术的批判，现代的艺术形式例如抽象主义、野兽派、立体主义、未来主义等更多关注艺术的本体，关心感性欲望，普通民众成为了创作的主题。在理念上，现代的艺术独立表现出不完整或残缺的艺术价值取向，崇尚活力、批判与未完成状态。"}, {"id": "q107", "type": "简答", "q": "如何理解“艺术终结论”？", "a": "（1）“艺术终结论”存有被“误读”的历史。“艺术终结论”来自于西方美学的传统。1550年瓦萨里在《大艺术家》中指出艺术的历史同人的生命一般，经历诞生、成熟、最后衰亡；黑格尔在1817年指出艺术丧失了生命，转移到人的观念当中。但这种宣言是一种误读，在二人身后仍然有无数的艺术繁荣的时代。\n（2）“艺术终结论”是艺术观念的转型。“艺术终结”的准确含义是现存艺术观念因现实语境转型，美学家们对艺术发展持一种更加开放的理解。黑格尔认为“美是理念的感性显现”，理念运动的不同阶段就产生了不同类型的艺术，黑格尔将其分为“象征性艺术-古典型艺术-浪漫型艺术”，浪漫型艺术瓦解了象征与精神的联系，从而理念回到了以精神表现精神的阶段，在意识上体现为宗教或哲学，人们只是从哲学上、思辨上对艺术加以认识。\n（3）“艺术终结”反映了艺术的市场化。现代科技与市场复制的艺术作为构成元素被消融于日常生活，非复制的艺术只能作为收藏品被收藏，传统艺术的存在方式被上述两种压力终结。\n（4）“艺术终结论”反映了人们对艺术与哲学的危机感。“艺术终结论”是关于艺术与历史、艺术史与人类现实世界的讨论，涉及了人的存在问题与人关于世界的精神方式。“艺术终结论”为我们提供了一种批判视角，提醒着人类的尊严与存在危机。"}, {"id": "q108", "type": "简答", "q": "如何把握艺术美与人生艺术化的内在关系？", "a": "（1）商品经济推动了艺术场所的泛化。科学技术打破了艺术、艺术场所、欣赏者的距离限制，文化逐渐民主化。伴随着传播记述的演进，艺术脱离艺术场所而进入日常生活，生产的进步与生活水平的提高打破了艺术与生活的界限，艺术美与人生融合。\n（2）人生与艺术是一对辩证的范畴。艺术是人类情趣生活的表现，人生的创造与欣赏也是艺术活动，不存在无欣赏、无创造的人生。人生本质上是一种广义的艺术，人通过品味艺术来审视自己的人生，对人生进行艺术化的加工，得到了美学意义上的完善。\n（3）艺术美装点了人生的艺术化。人生艺术化要求用艺术美装点、改造主体的人生，人生与艺术美走向了统一，二者在有机融合的过程中将艺术美升华至主体的人生整合与重新建构，艺术美从对象观审转而倾向于主体的自我完善体验。"}, {"id": "q109", "type": "简答", "q": "如何理解“日常生活审美化”？", "a": "“日常生活审美化”最早由英国美学家迈克·费瑟斯通提出\n（1）日常生活中的一切被审美化。商品经济的发展拓宽了审美的重要性，日产生活中的一切都被主体以美的眼光感受，占据大众文化生活的已经不再是诗歌、绘画等经典艺术，而是一些泛化的艺术门类，例如流行歌曲、广告等。流行歌曲的内容却以日常生活为主，表现现代的生活情感。另一方面，其传播方式不再是传统艺术的书面形式，而是借助网络、广播的新媒体广泛地入侵我们的日常生活，我国的“崔健摇滚现象”、日本的“Jpop”、韩国的“Kpop”文化等都是以流行音乐为媒介的日常生活审美化。\n（2）艺术和审美进入日常生活，被日常生活化。艺术和审美的日常生活化包括两个方面，一是艺术场所与生活场所的界限消失；二是艺术产品自动化：\n①艺术场所与生活场所界限消失。由于商品经济的发展，艺术场所与日常生活场所的界限被打破，文化民主化与传播技术进步化缩小了艺术与生活的距离，如城市广场、购物中心等，在这些场所中，文化活动、审美活动、商业活动不存在严格界限。以成都书店“方所”为例，该书店仿造霍格沃兹图书馆设计地下风格，同时又明确书店牟利的目标。\n②艺术产品自动化。传播技术的发展与商业发展需求提高了人们在日常生活中见到艺术产品的频率，消解了艺术品原先的神圣意义，艺术品与生活融合，成为人们自动化生活中的部分。与画作同名的“蒙娜丽莎”瓷砖将画作作为自己的宣发策略，《蒙娜丽莎的微笑》被自动化。"}, {"id": "q174", "type": "填空", "q": "黑格尔把艺术分成三种类型，即（____）、（____）、（____）", "a": "黑格尔把艺术分成三种类型，即象征性、古典型、浪漫型"}, {"id": "q175", "type": "填空", "q": "艺术美再现社会交往中的美，主要表现在“（____）”和“（____）”", "a": "艺术美再现社会交往中的美，主要表现在“惩恶”和“扬善”"}, {"id": "q176", "type": "填空", "q": "艺术美对人物美进行完美再现，其人物塑造主要分两个类型：“（____）”和“（____）”", "a": "艺术美对人物美进行完美再现，其人物塑造主要分两个类型：“圣贤”和“英雄”（客观题）"}, {"id": "q177", "type": "填空", "q": "黑格尔认为浪漫型艺术是（____）", "a": "黑格尔认为浪漫型艺术是内容压倒形式"}, {"id": "q178", "type": "填空", "q": "（____）的问题是黑格尔最早提出的", "a": "艺术终结的问题是黑格尔最早提出的"}, {"id": "q179", "type": "填空", "q": "20世纪，（____）以现代主义艺术和后现代主义艺术为背景，重新提出艺术终结的问题", "a": "20世纪，丹托以现代主义艺术和后现代主义艺术为背景，重新提出艺术终结的问题"}, {"id": "q180", "type": "填空", "q": "意境作为一个美学范畴形成于（____）时期", "a": "意境作为一个美学范畴形成于唐代时期"}, {"id": "q181", "type": "填空", "q": "（____）把艺术作品分为艺术质料、主题、表现性三个层次", "a": "杜夫海纳把艺术作品分为艺术质料、主题、表现性三个层次"}, {"id": "q182", "type": "填空", "q": "（____）那把艺术作品分为材料、形式、表现三个层次", "a": "桑塔亚那把艺术作品分为材料、形式、表现三个层次"}, {"id": "q183", "type": "填空", "q": "（____）开启了（____），磨掉了艺术品与现成物的区分", "a": "杜尚开启了装置艺术，磨掉了艺术品与现成物的区分"}, {"id": "q184", "type": "填空", "q": "“（____）”的出现标志着艺术的独立", "a": "“美的艺术”的出现标志着艺术的独立"}, {"id": "q185", "type": "填空", "q": "欧洲古代与中世纪出现了“（____）”与“（____）”的分野", "a": "欧洲古代与中世纪出现了“自由的艺术”与“粗俗(机械)的艺术”的分野"}, {"id": "q186", "type": "填空", "q": "艺术创造以（____）为基础", "a": "艺术创造以现实审美为基础"}, {"id": "q187", "type": "填空", "q": "20世纪下半叶，“（____）”成为热点话题", "a": "20世纪下半叶，“艺术的终结”成为热点话题"}, {"id": "q188", "type": "填空", "q": "“（____）”意味着当代艺术对象与日常事物之间边界的消失", "a": "“艺术的终结”意味着当代艺术对象与日常事物之间边界的消失"}, {"id": "q189", "type": "填空", "q": "人生的艺术化包含两个方面的含义一方面，（____），另一方面，（____）", "a": "人生的艺术化包含两个方面的含义一方面，人生成为艺术对象，另一方面，艺术审美活动关注人生"}], "c2": [{"id": "q6", "type": "名词解释", "q": "名词解释：移情说", "a": "德国美学家利普斯。移情说从心理学的角度出发，认为人的美感是一种心理错觉，一种在客观事物中看到自我的错觉。它认为，产生美感的根本原因在于“移情”。所谓“移情”，就是我们的情感“外射”到事物身上去，使感情变成事物的属性，达到物我同一的境界。移情说在后来发展中也有更多的学者与新学说，包括胡塞尔的现象学移情、巴赫金的互动移情等等。"}, {"id": "q7", "type": "名词解释", "q": "名词解释：心理距离说", "a": "英国美学家布洛。“心理距离”指的是对自然和艺术的欣赏中人们需要保持一种心理距离，即欣赏与艺术间的非实践感，距离需要适度，太近则成为生活，太远则失去兴趣。其次，心理距离需要保持连贯性，在艺术作品当中不能出现无度的“机械降神”现象，欣赏者与作品要以作品特征为原则，坚守欣赏的合理性与规范性。“距离说”的优点在于修正了康德以来的“审美无功利”论，从中确证了审美欣赏先验携带的功利要素与审美对象的选择，但该学说仍然在谈论关于审美的态度，无法解释如何产生“心理距离”，本质上仍然是从唯心认识论的角度思考美学。"}, {"id": "q8", "type": "名词解释", "q": "名词解释：完型说", "a": "德国美学家阿恩海姆。基于“格式塔”心理学的一种解释艺术创造和欣赏的审美学说，强调人知觉上的整体性，认为人的美感判断是从整体到部分的过程，比较广泛地解释艺术创作与欣赏中的复杂心理现象，不仅克服了“心理距离”说以来的主观审美倾向，更加突出了审美与人类的本源关系。但过于强调美的事物所具有的独特结构，否认了历史的审美经验对把握现代事物的重要作用，陷入了唯心主义。"}, {"id": "q9", "type": "名词解释", "q": "名词解释：内在感官说", "a": "英国美学家夏夫兹博里。“内在感官”指的是人先天具有审美能力，认为人天生就有审辨善恶和美丑的能力，而且审辨善恶的道德感和审美丑的美感根本上是相通的，是一种感官的能力，带有明显的理性色彩，“内在感官说”一方面揭示了美的来源是人内心，并最终将“美”赋予神性；另一方面美善不分，美感和道德感是相通的。"}, {"id": "q37", "type": "名词解释", "q": "名词解释：审美经验", "a": "主体感受、体验、创造美的经验，由具体的审美实践而抽象出来的，往往上升为文学理论或美学相关的理论，多见于具体作品的赏析和阅读体验。就其特征而言，审美经验包括直观性、非功利性（康德）、无限性、非理性以及情感伴随性。"}, {"id": "q38", "type": "名词解释", "q": "名词解释：审美体验", "a": "在审美主体深度参与的情况下所达到的审美效果，跟日常生活中的“体验”一词意思一致，强调过程和主观因素。 审美体验是贯穿于创作、欣赏、消费及传播之始终的精神活动。审美体验是主体与作为审美对象的审美客体构成的一种已然的融入和超越的内在状态。"}, {"id": "q39", "type": "名词解释", "q": "名词解释：审美直觉", "a": "人们在审美活动或艺术鉴赏活动中，对于审美对象或艺术形象具有一种不假思索而即刻把握与领悟的能力。审美直觉使人刹那间暂时忘却一切，聚精会神地观赏它，全部身心沉浸在审美愉悦之中。"}, {"id": "q40", "type": "名词解释", "q": "名词解释：审美理想", "a": "主对审美最高境界的向往和追求，是审美的最高范型和标准，是人类审美意识高度发展的产物,是一种指向未来、指向人的生活远景的创造性想象的成果。它既是具体的、形象的,又蕴含着人的系统化的理性需求。审美理想具有稳定性，升华概括性，而且强调是包含主体愿望在内的审美对象。"}, {"id": "q41", "type": "名词解释", "q": "名词解释：审美共通感", "a": "共通感的一种，共通感表现为“一种共同的感觉的理念”。审美的形成需要主体完成社会人的转变后意识高度活跃，主体背后的社会性因素必然会影响审美建构。社会属性对所有社会成员产生一定的约束力以保证该社会群体的稳定性和凝聚力，身处同样社会背景下的主体受到同一传统和氛围的影响，必然会形成相似的心灵结构，产生共同的心理感受，这种共同心理感受被称作共通感。共通感在主体审美活动中的体现被称为审美共通感。"}, {"id": "q69", "type": "简答", "q": "为什么要从审美活动整体性来理解审美经验？", "a": "（1）审美经验不能孤立存在。早期的美学起源研究主张审美的发生是由于审美对象适合了审美意识的独特感觉，将审美的主体先验性看作一个无须考察的公理，但现代科学发展证明了意识的发生对机体的依赖性与晚近性，主观心理的个体差异突出了审美价值的相对判断性，将普遍意义的审美标准排除到审美活动之外，在逻辑上发生了谬误，故而审美经验并不能先验地存在于审美活动之外。\n（2）审美经验不直接反映审美对象，而是反映审美活动。审美经验的产生基于主体的审美实践，主体对客体的审美实践产生了审美经验，包括选择审美对象与对审美对象做出价值评判的体系等，审美经验中包含了与审美对象内容不同一、超出后者的方面。另一方面，对审美对象的美感产生是人类对自己审美经验的调动与引证的结果，并在新的审美活动中获得新的审美经验，所以审美经验产生于审美活动。"}, {"id": "q70", "type": "简答", "q": "审美体验在审美经验中的地位。", "a": "（1）审美体验的深刻性表明审美经验是第二性的。审美体验的深刻性来自于实践先于对象与意识的本质，在审美活动发生过程中主体首先是对事物的体验，产生直观的感受；其次才是对事物进行美学观照，结合审美经验产生美感。体验先于经验而发生。对当下高中教育的生活体验才导致观众产生了对电视剧《小欢喜》乔英子的生活遭遇的同情。\n（2）审美体验的亲历性激活了审美经验的表述可能性。审美活动是连接审美对象和审美意识、审美经验的桥梁，具体而言，审美主体通过体验了解了审美对象，并联系了自我的审美经验，审美意识的运动有赖于深刻的审美体验。周立波在写作《山乡巨变》前到湖南农村与农民一同劳动，以自身体验的深刻性创造了邓秀梅这一优秀的共产党人形象。另一方面，亲历性达标者不同个体对同一审美现象形成了不同的审美体验与人生感受，以及由此产生的审美经验。以《红楼梦》为例，大众读者聚焦于宝黛钗三角爱情的纠葛；而学界则试图从女性主义、反封建等角度解读文本。\n（3）审美体验的整体性使审美经验丰富化、多维化。在审美体验活动中，审美体验活动不是对审美对象某一方面的把握，而是对于审美对象整体的感受，主体执着于体验对象本身的多样性与丰富性。对《狂人日记》的批评既有从鲁迅作品整体性中产生的“批判社会”解读，也有基于鲁迅生平整体产生的“拟超人”（尼采《查拉图斯特拉如是说》）解读"}, {"id": "q71", "type": "简答", "q": "影响审美经验发展的条件有哪些？", "a": "（1）生产劳动的分工状况制约规定着审美经验的分化独立状况。例如,原始狩猎民族以动物为其审美对象,农牧阶段的民族里,植物才进入他们的审美视野,这种发展,正是以其与植物发生实践关系的农牧生产方式为先导的。\n（2）上层建筑以及其他意识形态对审美意识的重要制约影响作用。意识形态制约影响了各自不同时代的审美意识发展，既有积极正面的影响，例如魏晋玄学对山水绘画的影响；也有消极负面的影响，例如传统基督宗教对中世纪戏剧的禁锢。\n（3）艺术对审美意识产生巨大促进作用。我国的近体诗和日本俳句影响了西方庞德为代表的意象派的发展；彼特拉克的十四行诗则直接催动了西南联大诗人群关于诗歌的审美发展。\n（4）审美对象对审美意识的促进作用。审美意识可以外化出新的审美对象，从而提高审美意识的地位。例如，陀思妥耶夫斯基的《罪与罚》等作品刺激产生了“复调”理论的生产。\n（5）审美经验系统内部各个部分的互相促进作用。审美经验系统包括审美感受、审美心理结构、审美态度、审美趣味、审美理想。系统内各部分不平衡引起整个系统的变化。例如“东野圭吾热”则是基于日本“本格推理”传统的审美结构下产生的“非本格推理”审美趣味。"}, {"id": "q72", "type": "简答", "q": "如何理解审美经验内部结构的主要构成", "a": "（1）审美感受：狭义的美感，指人们进行审美活动时的心理活动过程，审美感受在全部审美经验和它的各个方面及各种形态都是在审美感受的基础上形成的。\n（2）审美心理结构：是由人类社会历史性积累、影响而形成的审美生理-心理机制，它是审美感受以及整个审美经验的物质基础。\n（3）审美态度：指人基于审美心理结构而对外界对象主动构成审美关系的特殊心理状态。\n（4）审美趣味：是指在一定审美感受的经验基础上逐渐形成的审美爱好，即有所偏好、具有独特心理定势心理习惯的审美风格倾向或个性化的审美态度。\n（5）审美理想：是指对审美最高境界的向往和追求，是审美的最高范型和标准，审美理想具有升华概括性，而且强调是包含主体愿望在内的审美对象，它不是现成既定的额，还有个性，是审美趣味的升华和结晶。\n系统内各个形态的发展不平衡，这必然引起整个系统发生变化。"}, {"id": "q73", "type": "简答", "q": "审美积淀的含义及其形成的主要形式？", "a": "含义：审美积淀是人将外在的社会生活与历史微化为个体心理结构的过程。这一过程是个体性的，是社会历史总体文化背景下的成果，需要个体自身长期的实践活动，更需要人类千百代实践历史性的继承、积累和传递。\n形式：\n（1）生产积淀。审美积淀是生产劳动的结果。制造和实用工具使得人类社会结构水平不断提高，同时提高人脑中相应的感觉中枢的协同能力的不断提高，人类后来对对称性、和谐性的追求都来自于生产积淀；现代社会电子媒介则是延伸了人的中枢神经。鲁迅的“杭育”理论指明了艺术产生自生产实践；《赛博朋克》则代表了现代技术对人体感官能力的改变。\n（2）以巫术为主的原始文化积淀。远古巫术激活了人类的情感，培养提高了生产技能和想象力，协调和动员的群体生产活动。巫术对氏族成员的强制力和约束力，个体必然需要绝对地、无条件地、全身心地服从和感应，塑造了人对于美感的超验体悟。屈原的《楚辞》就以巫术活动复活了人底层的审美感知。\n（3）以艺术为代表的日常文化积淀。艺术从审美角度塑造了个体心理结构，把社会总体运动内化为个体心理运动，从传统艺术欣赏到大众媒介文化塑造着心理结构，文化积淀使得心理活动多样化、复杂化和丰满化。酒神舞蹈将人从现实限制中解放出来，获得了迷狂的审美自由。"}, {"id": "q74", "type": "简答", "q": "审美感受的特性", "a": "审美感受的特性包括合规律性和合目的性的，具有理性深度，综合性，整体性。\n（1）认识总是对具体的规律内容的认识。当人类探索认识新的规律时，美感以其超前的普遍合规律性提供契机与思路，例如西方文论中三次“死亡”，即上帝之死、作者之死和人之死就与文论史紧密相关，揭示了普遍的审美规律与往后的审美创造。\n（2）特定的意志欲望表现为具体有限的目的。人类劳动工具是人本质的对象化，成为审美对象，审美感受对特定目的欲望的排除，是对特定生存需要所规定的有限片面的扬弃，美感指向最高的目的。例如沈从文《抽象的抒情》对“第一次文代会”方向的拒斥；宫崎骏《幽灵公主》、《红辣椒》等作品对日本军国主义的驳斥与童心的坚守。\n（3）合目的性与合规律性在美感中是统一与一体的，他们统一于特定的审美感受中，审美感受对于认识和意志欲望具有协调、中介的性质。杜甫的创作是六朝诗学的发展，同时又开启了文学史中平民写作；维纳斯的“断臂”体现了是对人体美的追求。"}, {"id": "q75", "type": "简答", "q": "如何理解审美直觉的内涵？", "a": "审美直觉在对象、方法等方面独特而重要的功能性质，主要包括如下特征：\n（1）直觉是直接感觉到的，而不是由感觉传导给大脑、经由思维来把握对象，因为直觉是快速瞬时的、当下即得的；例如布列东的“自动写作”。\n（2）直觉达到了一般理性水平，而且在快速反应、超前预感等方面超出理性水平之上，审美直觉把握的是普遍的内在联系和人生至关重大的价值取向，超越了认识和伦理等界限。\n（3）审美直觉在不抛弃感性现象的情况下把握本质，具有现象与本质相统一的方法论特性，是整体性的、综合性的审美心理结构。"}, {"id": "q76", "type": "简答", "q": "审美心理要素的构成", "a": "（1）感觉。感觉是对事物各种个别感性属性（如色彩、声音、形状）的感受，例如李贺“昆山玉碎凤凰叫，芙蓉泣露香兰笑”就是基于李凭的箜篌声产生的通感效果；近代电影的产生则综合了视听感受形成的第七艺术。\n（2）知觉。知觉是把感觉的联合材料联合为完整性对象的整体性感觉。例如勒内的画作《人类之子》首先是从整体上把握了现代人的特征，再发现了画中人物脸前的苹果，最后联想到伊甸园。\n（3）想象。想象是人们在外在对象和事物的刺激下，在头脑中对原有的记忆表象进行加工、改造、形成新形象的精神活动过程。 例如奥本海默对原子弹的演示属于“科学想象”，而《奥本海默》中对奥本海默的内心揭示属于审美想象。\n（4）情感。情感是审美心理中最活跃的因素，它在感知的触发下，使整个审美过程浸染着情感色彩，对审美心理的总体活动起着推动作用。随便举例（思乡之情）\n（5）领悟。领悟是内在地贯穿审美感受全过程、与其他审美因素交融一体地对审美意蕴本质的把握。审美领悟是指把握审美意蕴本质的一刹那间主体审美感受发生质的飞跃时的心理状态，类似禅宗的“顿悟”。《奇门遁甲》中的“意念过招”就是敌我双方的“顿悟”。"}, {"id": "q77", "type": "简答", "q": "想象和情感的理解及其相互关系", "a": "情感是想象的动力，规定着想象的方向。例如儒家所谓的“仁者乐山，智者乐水”的本质是审美主体以不同的情感为基础，将山水景观与自己同构\n（2）想象为情感提供“客观对应物”，丰富了情感的具体内涵。艾略特认为写作的本质是为情感找寻“客观对应物”，审美主体通过审美想象将情感与形式结合到一起，情感的本质属性被丰富化和可感化。杜甫“国破山河在，城春草木深”\n（3）想象和情感之间需要有一定的客观条件进行约定。审美情感的能动外化是有规定性的，特定情感智能与特定外界客观对象进行结合，审美想象所提供的形式必须基于人类悠久的历史积淀与审美心理结构。"}, {"id": "q147", "type": "填空", "q": "美感的一个重要特性就是（____），这是一种精神享受美感是一种高级的精神愉悦，应该把它和生理快感加以区分，但不应绝对化", "a": "美感的一个重要特性就是（愉悦性），这是一种精神享受美感是一种高级的精神愉悦，应该把它和生理快感加以区分，但不应绝对化"}], "c1": [{"id": "q10", "type": "名词解释", "q": "名词解释：和谐说", "a": "毕达哥拉斯学派。认为美是数量关系的“和谐”，认为数学结构使得音乐变得和谐动听，拓展到宇宙万物层面，他们认为审美的本质是宇宙与人类灵魂的和谐，他们把人的身体看作是“小宇宙”，认为人体跟宇宙天体一样，都由数的和谐原则协调，“和谐说”是西方美学思潮第一次深入探讨美的本质的学说，表明人类早期已经具备相当程度的审美反思意识与本体论思维的萌芽。"}, {"id": "q11", "type": "名词解释", "q": "名词解释：理式说", "a": "柏拉图。提出的关于美本质的学说。“理式”是柏拉图论述美本质的哲学基础，区分了“美的事物”和“美本身”，认为物质世界不存在美或美的属性，美与某种超现实存在的神秘的非物质性的精神实体紧密相联，由于这种精神实体的注入或显现，才使客观事物成为美的。"}, {"id": "q19", "type": "名词解释", "q": "名词解释：美是道德的象征", "a": "康德在《判断力批判》中提出。康德认为，美具有主观普遍性的先验根据，它预设了通向自由的可能性。在康德那里，道德是指一种先天的、不依赖与经验的道德意识，即“实践理性”，它不承认社会功利性，而只承认无条件的“善的意志”，它本身就是一种目的，并且是整个世界的“终极目的”。美是道德的象征，说明了人类通过审美由自然走向自由。任何艺术作品，都要表达出道德的审美理想。所以，审美艺术是道德的象征。"}, {"id": "q20", "type": "名词解释", "q": "名词解释：美是生活", "a": "俄国19世纪革命民主主义思想家车尔尼雪夫斯基在他的美学论文《艺术对现实的审美关系》中提出，他强调一切美的事物都不能脱离人类社会生活,认为凡是有益于人们生活的东西,符合人类生活要求的东西,或者能够显示出生活以及人们想起生活的东西,那就是美的。尽管车尔尼雪夫斯基还不能用历史唯物主义的观点来理解美,因而未能对生活中的美作出完全科学的解释,但他却把美从理念的天国拉回到现实,肯定了现实生活中美的存在,这就使美学研究和艺术创作有了牢固的现实基础。"}, {"id": "q22", "type": "名词解释", "q": "名词解释：大希庇亚篇", "a": "柏拉图。通过罗列形态各异的“美的事物”，追问与之有别的“美本身”，是美学思想史上首次专题讨论审美本质的文献。区别了“美本身”与“美的事物”，否定了美是美的东西、质料或形式，不是某种物质上或精神上的满足，不是恰当、有用、有益等价值，不是由视觉或听觉引起的快感等。美是指“美本身”，是使一切事物成其为美的共同本质。对“美本身”的提问和寻找，是对审美本质的形而上的哲学探讨。"}, {"id": "q29", "type": "名词解释", "q": "名词解释：意象", "a": "客观物象经过创作主体独特的情感活动而创造出来的一种艺术形象。“意”是作者之意；“象”则是客观物象。诗人在创作过程中把握了瞬间的情思并以生动凝练的语言加以表现，审美活动是揭示意象中情感与物象之间的关系，并加入自己的知识视野。在儒家看来，意象之“意”主要是作家光辉的内在修养，认为“意象”是审美表象的本体根源；在道家看来，“意”是内敛朴拙的圣人精神，否定具体物象的美感"}, {"id": "q31", "type": "名词解释", "q": "名词解释：象罔", "a": "象：形象、境相。罔：无、虚幻。原指古代中国寓言中的人物，出自《庄子》。“象罔”象征着虚与实的结合，有限与无限，混沌与差别的统一。"}, {"id": "q35", "type": "名词解释", "q": "名词解释：主体间性", "a": "探究主体相互关系的哲学观念。最早出现在胡塞尔的现象学中探究他者、先验自我与自我的关系，伽达默尔通过诠释学的方法将“主体间性”的交互性转换为视域融合的问题，即视域融合形成了主体与客体的交互状态，新的视域超越了原有的视域状态，给予了新的经验方式与理解可能。哈贝马斯则以语言学的方式突破了先验自我的局限，认为主体的交互必然通过社会实践，即“交往”才能实现。主体间性肯定了主体的交往实践能力，指出主体的交互是肯定彼此为主体后发生的行为；在交互行动中，语言的沟通使得交互的成为可能，主体间性也以此得以实现，反映了对传统主体的延伸与反思。"}, {"id": "q58", "type": "名词解释", "q": "名词解释：自然的人化", "a": "人化自然是马克思论述人与自然的关系时首先使用的术语，表示一种过程，即由于人的对象活动使越来越多的天然生态系统变为人工生态系统的过程。在审美活动中，自然的人化表明人类通过经验的方式将自然审美对象化，人化后的自然能够进行人类精神活动产物的类似分析，同时辩证地深化人类对第一自然的美感认识。在马克思文化自然思想中，表达了他的文化哲学思想的最核心的价值取向。"}, {"id": "q59", "type": "名词解释", "q": "名词解释：人本质力量的对象化", "a": "指人的本质力量通过社会实践在现实世界中得到体现和贯彻。人的本质力量是指人的自由自觉的意识，即人是有目的、有计划地改造自然的特性。人的本质力量是存在于人的本性中的，而社会实践则是人的本质力量发挥和体现的必要条件。只有通过社会实践，人才能够不断地提高自己的本质力量，从而推动社会不断地发展进步。同时，本质力量的对象化也是人的个体生存和发展的必要条件。人的本质力量通过对象化的方式得以实现，同时也是人的个体得以满足自身需求的重要途径。"}, {"id": "q61", "type": "名词解释", "q": "名词解释：美的规律", "a": "马克思在论述动物的生产与人的生产的不同时提出的，是物质生产实践中的一种规律，而且是在真与善的基础上发展起来的一种独立的规律，指人类在欣赏美和创造美的过程中，以及在一切实践活动中，所表现出来的有关美的尺度、标准等诸多规定的总和，集中体现了人的本质及其劳动的理想性（人的本质是自由且无限的，这样的本性必然要求人类的劳动超越单一动物式的“生产”的自由劳动理想，成为渗透了分工、经济、个体与社会、历史进程的价值理想。）"}, {"id": "q62", "type": "名词解释", "q": "名词解释：美的形式", "a": "显现人的本质力量、能唤起人美感的事物感性形式。与“美的内容”相对。美的形式包含内形式与外形式。内形式是指美的内容诸要素的内部组织与结构。外形式包括两个涵义，一是指美的内容的外部表现形态；二是指美的事物外观的装饰成分。"}, {"id": "q63", "type": "名词解释", "q": "名词解释：两个尺度", "a": "其一是“外在尺度”，即马克思所说的“物种的尺度”，动物只能按照它所属的那个“物种的尺度”来满足自己的需要，实际是客观事物本身规律性的体现。"}, {"id": "q78", "type": "简答", "q": "西方传统中对美的本质认识有哪些？", "a": "（1）本体论美学阶段，追求一种独立的、终极的、普遍的美：\n①毕达哥拉斯学派从数学入手，数的原则就是万物的法则，数给一种永恒有序的局面和状态。音乐由数构成，是数中最典型的形式，生活中一切美的事物都以“数的和谐”作为本体。\n②柏拉图区分了“美的事物”和“美本身”。柏拉图认为“美的事物”是指所有一切真实存在的具体事物；而“美本身”则是使得一切成为美的本质，在柏拉图看来这是“理念”，是万物的本体，永恒不变的原型。\n③亚里士多德认为美存在于具体事物当中。亚里士多德认为存在是事物的实体和构成，美不能脱离现实的具体事物而存在，只能作为客观属性存在于具体事物当中，美的本体与美的现象统一于一个客观世界，美是秩序、匀称与和谐\n④到了中世纪神学美学阶段，奥古斯丁等人把美学导向神学，上帝是真、善、美的创造者，真与上帝心中的关联相连、符合自然本性的存在；善是与上帝心智相一致的目的和趋向，美是以上帝为原型的完善与和谐。\n认识论阶段美学，探求审美何以可能与审美如何构成：\n①经验主义认为美学来源于感官知觉和经验，例如夏夫兹博里则认为审美来自于“内在感官”；休谟认为审美趣味的统一标准在于人的生理和心理结构，审美的感性来自于人类的基本情欲。\n②理性主义强调人的理性能力，更加看重理性与法则对美感的重要性，他们以逻辑方法使得美学具有理论性和普遍性，例如笛卡尔认为美来自于相当程度的数学和逻辑学原则；鲍姆加登认为审美活动反映着客观世界的和谐秩序。\n③法国启蒙主义以狄德罗为代表，他提出“美在关系”，美代表着一切物体所共有的艺术品质，这就是关系，关系包括三种，以是同一事物内部的联系，它产生出对称、和谐的美；二是事物的关系，形……"}, {"id": "q79", "type": "简答", "q": "中国传统关于美的本质的认识有哪些？", "a": "中国传统美学的精髓在于天人合一：\n（1）原始先秦时期：原始时期中国先民构建了“神人以和”的远古文化模式，即天人合一的雏形。在先秦时期，儒、道两家以天人合一继续发展美学思想。儒家美学以社会伦理为本位，侧重于从个体与社会关系出发达到天人合一，例如孔子“里仁为美”；老庄“无为”“天然之美；墨家与法家更为狭隘，要求审美脱离人民生活。\n（2）汉代美学：汉代形成了以气、阴阳、五行为核心的宇宙论结构，美学转向了关于个人修养与世界追求的探讨。《淮南子》将儒、道当做对广大外部世界的审美追求;《毛诗序》则以诗歌为对象，总结了“发乎情，止乎礼”的美学风格。\n（3）魏晋隋唐美学：\n①中国美学到了魏晋时期正式独立。魏晋时代儒、释、道三家合流，发展出纯粹的形而上学，《世说新语》、《人物志》等突破了传统美学的道德节操评价模式;陆机《文赋》首次高标“诗缘情”的内容\n②唐代儒释道三家美学一同发展。在儒家美学当中，杜甫、韩愈等人表现出一种志于道的儒家人格，既有温柔敦厚，也有沉郁顿挫；禅宗和道家美学集中体现在意境理论，“境”的出现表明对美学的体验愈发全面化与形而上化。\n（4）宋元明清美学\n①宋代美学的三大特征是平淡境界、以禅喻诗和自然审美。在境界上，宋人不向往神灵境界或修身齐平，重视日常生活情趣;在“以禅喻诗”方面，严羽将禅宗哲学作为理论，指出诗有别材、别趣和“兴趣”；在自然方面，郭熙《林泉高致》扩展了自然山水的审美事业。\n②明代的美学主要表现在大胆地表现个人的真情实感，李贽提出“童心说”，认为美感来源于不受污染的童心；汤显祖则认为美在“至情”；清代美学转向以实学为根基，但主情依然占重要地位，黄宗羲提出“诗以道性情……"}, {"id": "q80", "type": "简答", "q": "人为什么能按照美的规律来建造？", "a": "按照“美的规律”来建造是马克思在《1844年经济学哲学手稿》提出的概念\n（1）从根本上讲，人的生产同动物的生产有本质的不同。在生产过程中，动物按照肉体的支配进行生产，并且只生产自身；人在解放肉体需求之后进行生产，并且生产整个自然界。另一方面，人在生产中体验到情感、智慧、意志等本质力量，在整个过程中充盈着自由性。\n（2）在具体内容上，人能够按照任何“种的尺度”进行生产。动物的生产过程只按照自身的“种的尺度”进行生产，但人的生产过程却能按照任意的“种的尺度”进行生产，并且懂得处处都把固有的尺度运用于对象。\n（3）人的“劳动”是内在尺度与外在尺度寻求统一达到实现的活动。人类的劳动由于超越了动物式生存需求与单一特定活动方式而呈现为自由的活动，因此人的生产是全面的、自由的、自觉的。人能够按照自己的愿望、要求、理想来进行创造，使生产产品能够体现出美的因素。"}, {"id": "q81", "type": "简答", "q": "探讨美的本质必须坚持哪些原则？", "a": "(1)对于审美本质的探讨是美学思想史的首要传统，具有历史性。\n(2)审美本质并非经验科学的实体对象或认识论对，而属于精神哲学范畴并具有价值理想性。\n(3)审美本质是包括审美对象与审美意识在内的整体审美活动经验的本质，具有整体性。\n(4)活动的人类学原型是劳动以及比劳动更广泛形态的实践，以劳动为核心的实践及其结构成为探讨审美本质的基础与出发点。"}, {"id": "q82", "type": "简答", "q": "如何具体理解“作为目的与规律统一的自由形式”这一本质观的内涵？/如何理解马克思主义本质观？", "a": "（1）以劳动工具及其使用技术为中心，劳动双向陶冶着作为主体的人与作为客体的自然，在劳动系统中，人的欲望需求转换为目的，自然力量转化为规律，目的与规律逐渐具备合目的性，双方统一为工具技术的自由操作。\n（2）马克思劳动观念重心在于劳动对人类自身任性欲望的陶冶，自然规律因纳入人类目的而“人化”，欲望目的遵循规律而失去利己性质，人类在面对自然的过程中表示为人与自然新型的互渗关系。\n（3）自由形式不仅是工具积淀的结果，而且是工具活动得以运行的前提条件，自由形式与工具劳作互为因果，规律与目的相统一是一个动态的运行机制，实践活动中不允许分离或游离状态的规律认知与目的欲求，规律与目的济世在劳动过程的某一阶段才实现统一。\n（4）审美作为自由形式，其本源形态乃是以劳动为原型的人类实践中介方式，原初的审美其实就是人感受到超越实用性的自由生活方式。自由的审美形式从多样的实践活动，同时又成为建构整合多样活动形态的中介形式机制。\n（5）作为活动中介方式的自由首先被活动者内在体验，但自由方式-形式不仅会被后续扩展的劳动母体持续生产出来，而且势必摆脱从属于劳动的自发状态。中介方式的演变历史以符号为媒介，沿着巫术-艺术的顺序发展。\n（6）规律与目的相统一是对立统一的动态平衡过程是审美形态及其范畴多样差异性的根源结构。就内容而言，自由形式的不同偏重形成了艺术审美的不同范畴，例如自然美、社会美等形式，但只有在艺术中，作为审美本质的自由形式才呈现为完美纯粹的自由状态。但完美体验自由的纯粹艺术审美是意境，而非真实生活，这自由意境只有回归现实生活自由的不纯粹状态，才会转化为推动现实走向自由的力量。"}, {"id": "q83", "type": "简答", "q": "真善美之间的关系如何？", "a": "美和真善具有辩证关系，既联系紧密，又有区别。\n（1）联系：三者是非常相近的品质。三者的关系从历史的角度来看，只有当人类在实践中掌握了客观规律（真），实现了功利目的（善）并成为生动的形象才可能有美，因为这样才能体现人类的自由创造。从历史成果来看，真善美是同以客观对象的密不可分的三个方面。就对象体现规律看是真，就对象符合一定社会功利目的看是善，就体现人的自由创造的形象看就是美。\n（2）首先美与善的关系:善是和功利直接联系的,美一善为前提。区别:①从功利关系上看,善直接和功利相联系,衡量一件事物是否是善,是以社会功力作为客观标准,而美和功力是一种间接联系,功力是潜伏在形象中。②从内容和形式的关系上看,善虽有形式,但主要不是讲形式,也可以不顾及形式,人们对善的把握主要是通过概念去解释对象的功利性质。③善是意志活动的对象,而美是认识和观赏的对象,能唤起情感的喜悦。\n（3）美与真的关系:真是指客观世界自身的变化、发展规律。真理是指对客观事物及其规律的正确反映。美的产生是人在实践中,以对真的认识和掌握为前提。区别:①真并不就是美,因为美并不就是客观规律本身,客观规律可以脱离人的实践、主体而独立存在,而美却不能离开人的实践,不能离开主体的功利目的和生动形象。②真是客观规律本身,而美是通过实践,在认识客观规律的基础上,肯定人的自由创造的生动形象。③真是求知的对象,引起人们去追求真理,了解客观世界本身的内在联系,而美却是欣赏的对象,它具有生动的形象,是对人自身本质力量的肯定。总之,美不能离开真和善,但又有不同。"}, {"id": "q84", "type": "简答", "q": "如何看待今天的审美时尚？", "a": "现代社会创造了空前丰富多样的价值，但也形成了诸多问题与困境\n（1）价值相对主义导向了价值虚无主义。审美观念史的现代化潮流是“丑”的扩张，作为审美范畴的“丑”以广义的“美”为根据，植根于现代社会生活的复杂冲突，“以丑为美”的审美价值取向却可能模糊乃至消解元价值的“美”，审美范畴的狭义“丑”可能支持元价值负面体系中广义的“丑”，进而消解元价值的真善美与假恶丑的对立。例如国内流行的“大冰现象”对奇异的文青氛围的塑造。\n（2）从社会职业分工到精神活动的分化性，现代性分化对元价值体系的影响使得真善美解体，“美”削弱乃至放弃了对“真善”的依存关系，弱化了前述作为超越性中介“真”与“善”的审美内容，空前积累与扩展了形式美，即符号化的取向，不仅导致了个体形态畸变，也造就了社会群体行为的异化。就符号化层面，国产爱情电影形成了某种“我xx我们”、“我xx你”的庸俗故事与抒情公式。\n（3）当代急需重建真善美得元价值体系。现代社会早就的审美问题需要重建“真善美”的元价值体系，即克服价值虚无主义与后冷战体系下的生存矛盾问题，于是在未来重估“真善美”作为搭建美学体系的基础必不可少，必然需要国家力量与群体意向共同努力。"}, {"id": "q141", "type": "填空", "q": "在西方美学史上，真正在理论上讨论“美”的问题是从（____）开始的", "a": "在西方美学史上，真正在理论上讨论“美”的问题是从柏拉图开始的"}, {"id": "q142", "type": "填空", "q": "（____）最早提出了“美是和谐”的观点", "a": "毕达哥拉斯学派最早提出了“美是和谐”的观点"}, {"id": "q143", "type": "填空", "q": "（____）关于美的本质的观点是“美是理念”", "a": "柏拉图关于美的本质的观点是“美是理念”"}, {"id": "q144", "type": "填空", "q": "（____）给出的关于美的定义是“美是理念的感性显现”（客观题）", "a": "黑格尔给出的关于美的定义是“美是理念的感性显现”（客观题）"}, {"id": "q145", "type": "填空", "q": "审美活动不是认识活动而是（____），因为，研究美的问题不应该依照主客二分的模式，而应该依照（____）", "a": "审美活动不是认识活动而是体验活动，因为，研究美的问题不应该依照主客二分的模式，而应该依照天人合一"}, {"id": "q146", "type": "填空", "q": "在二十世纪西方美学史上，关于美的本质探讨的思维模式的转变，即（____）的转变，关键性的人物是（____）", "a": "在二十世纪西方美学史上，关于美的本质探讨的思维模式的转变，即从主客二分到天人合一的转变，关键性的人物是海德格尔"}], "c9": [{"id": "q13", "type": "名词解释", "q": "名词解释：净化说", "a": "“净化”是朱光潜对亚里士多德《诗学》中“卡塔西斯”的翻译，反映了亚里士多德的悲剧效果思想。亚里士多德在《诗学》中认为悲剧是对一个严肃、完整、有一定长度的行动的摹仿，它会引发审美者的恐惧、怜悯等诸多复杂感情反应，甚至发生某种精神的提升与转变。但亚里士多德的阐释没有指明“净化”发生的一般原理，后来在《悲剧的超越》中，雅思贝尔斯指出悲剧的“净化”效果先验地确立了一个抽象意义的“人”，其次“人”通过旁观与亲身参与激活了上述诸种情绪，最后得到快感的满足。“净化”/“卡塔西斯”是西方美学史上首次将“悲剧”作为一种审美范畴进行详细论述，以戏剧体裁的“悲剧”出发，亚里士多德探讨了戏剧的“悲剧效果”的相关内容，奠定了西方关于悲剧效果的认识基础。"}, {"id": "q14", "type": "名词解释", "q": "名词解释：乖谬说/预期失望说", "a": "乖谬说/预期失望说是康德在《判断力批判》中提出的关于喜剧效果的美学理论。在康德看来，造成喜剧性矛盾的可笑之物是荒谬而不和谐的，常出乎人的预料，让人的心理期待突然归于消失，并做出判断“笑是一种由紧张的期待突然转变成从虚无而来的激情”，斯宾塞又将其分为“上升的乖谬”和“下降的乖谬”两种，前者是超乎期待而引起惊喜，后者则是未能实现而引人发笑。“乖谬”的解释范围不具有绝对的普遍性，一些乖谬往往会引起人们的疼痛与伤感，但其内部强调的“突发性”却成为讨论喜剧的重要特征。"}, {"id": "q15", "type": "名词解释", "q": "名词解释：突然荣耀说", "a": "18世纪英国经验主义美学家霍布斯提出的喜剧性美学理论。霍布斯认为旧主体而言，喜剧令人发笑的重要原因在于发现了许多缺点，从而产生出令自己荣耀的优越感。在“发现”的过程中，主体的客体不仅包括他人还包括以前的自己，对二者的鄙夷促成了自我的优越感。霍布斯的学说相对科学地解释了喜剧和愉悦发生的心理背景与根源，但并不能普遍性地概括喜剧审美的本质，衡量喜剧艺术标准的标准应当是它是否能够产生强烈的辛辣感、批判性与同情感。"}, {"id": "q27", "type": "名词解释", "q": "名词解释：酒神精神", "a": "尼采在《悲剧的诞生》提出的美学概念。尼采指出狂欢节当中人们打破禁忌，放纵欲望，复归自然，处在痛苦与狂喜交织的非理性状态当中。“酒神精神”的解释前后不一，早期指从个人的痛苦和毁灭中获得的悲剧性陶醉，后来指从生命的绝对无意义性中获得的悲剧性陶醉。“酒神精神”解释了古希腊以来悲剧诞生的哲学思潮与生活基础，蕴含在其中的“太一”是尼采对终极的逻各斯的替代，消除了个体间的相对差异，人们在其中体验到恢复存在的本身喜悦。"}, {"id": "q28", "type": "名词解释", "q": "名词解释：狂欢化理论", "a": "俄国学者巴赫金对节庆狂欢与喜剧考察后提出的美学概念。巴赫金把世界分作两个世界，第一世界是官方的、严肃的、等级森严的秩序世界，平民大众则过着常规的、谨小慎微的日常生活。而第二世界则是狂欢广场式生活,在这里打破了等级森严的秩序世界, 人们平等而亲昵地交往、对话与游戏，尽情狂欢，对一切神圣物和日常生活的正常逻辑予以颠倒、亵渎、嘲弄、戏耍、贬低、歪曲与戏仿。在这样的状态之中，人才超越了日常生活的刻板性与功利性，真正回复到本真的存在状态。狂欢节中包含着对生活新的独特理解，体现出人力图打破生活中的各种外在限制，回复到自身的努力，是对常态化生活的中断与升华，呈现出独特的审美意味。"}, {"id": "q48", "type": "名词解释", "q": "名词解释：悲剧", "a": "“悲剧”包括有三层含义，一是日常生活中令人感伤的悲惨遭遇；二是作为一种戏剧体裁；三是作为一种审美范畴。在审美意义上，“悲剧”又称为悲剧美，是指具有值得人同情、认同的个体在宿命中遭受毁灭性打击，引发审美者的悲伤、怜悯与恐惧等复杂情绪，乃至发生转变的一种审美形态。构成悲剧的四个要素包括悲剧主角、悲剧事件、悲剧悖论与悲剧效果。悲剧作为一种审美范畴是对艺术类型与生活实际的典型悲剧事件的概括与意义提升。"}, {"id": "q49", "type": "名词解释", "q": "名词解释：喜剧", "a": "“喜剧”包括三层定义，一是日常生活令人发笑、滑稽幽默的现象，二是作为一种戏剧体裁，三是作为一种审美范畴。在审美意义上，“喜剧”又称为喜剧美，是指有弱点或缺陷，甚至虚假、丑恶特定的人或对象在特定的矛盾冲突或不和谐情境事件中暴露出自身的不协调与自相矛盾性，从而引起人发笑的审美形态。喜剧范畴是一个动态呈现的过程，包括人物、事件、矛盾和效果四个要素，分为肯定性喜剧和否定性喜剧两种。在形成过程中，作为范畴的喜剧将生活现象与戏剧体裁作为艺术基础进行了哲学的，思辨的升华，反映了人们对现实生活丑恶现象的反讽性鞭挞。"}, {"id": "q116", "type": "简答", "q": "举例分析悲剧的审美特征。", "a": "（1）悲剧至少有一个值得人同情和认同的个性化人物作为主人公。\n（2）悲剧人物会遭遇到一个结局不幸的灾祸、失败或死亡的悲催事件，并常常使个性遭到毁灭或者使自由自觉的人性受到一定程度的伤害。\n（3）悲剧人物所遭受的痛苦甚至死亡结局及其人性伤害或丧失，既是必然而不可避免的，又同时是不正当的、令人不可接受的。\n（4）悲剧会引发其审美者恐惧、怜悯与悲伤等诸多复杂的情感反应与审美感受，甚至发生某种精神提升或转变。\n（《巴黎圣母院》《红楼梦》《俄狄浦斯王》）"}, {"id": "q117", "type": "简答", "q": "举例分析喜剧的审美特征。p215", "a": "（1）喜剧人物的无价值或反价值性。《吝啬鬼》阿巴贡：视财如命，罔顾亲情的吝啬鬼\n（2）喜剧事件的矛盾性与可笑性。喜剧事件常常在形式上表现出不和谐、不协调的矛盾性及其反常性，在内容上表现出可笑性的特征。《吝啬鬼》阿巴贡要儿子娶有钱的寡妇，女儿嫁给有钱的老爷，自己和儿子爱上同一个女人。\n（3）喜剧矛盾的突发性。喜剧矛盾冲突的突发性，就是由悬念，能扣人心弦，而且急转直下，出乎人的意料，由知觉、想象到理解、情感的运动异常迅速，形成拍案叫绝、惊喜交错的特点。贾玲的电影《你好，李焕英》当中面对众人的质问，沈光林强调自己因嗓音条件才评上播音员，这时魏翔和另一名职工分别以“广播站之前都没有”和迷人的播音腔造成了矛盾令人发笑。\n（4）喜剧效果的愉悦性。喜剧中的愉悦直接而强烈，更有大众性，凸显了审美的本质特征，对喜剧人物虚假性的暴露、嘲弄或批判的同时，也给人强烈的讽刺感、批判性和同情感。吴敬梓《儒林外史》中范进中举后喜极而疯，所有人都对他害怕又担心，最终老丈人的一巴掌将其唤醒，老丈人却又总觉隐隐作痛，在欢笑之余流露出作者对封建官场的讽刺"}, {"id": "q118", "type": "简答", "q": "分析崇高和悲剧的联系和区别。p212", "a": "联系：\n（1）内容上，都侧重于展现主人公的本质在实现对象化过程中的矛盾激化、艰难斗争，主体遭遇巨大阻力的对抗状态和矛盾冲突；\n（2）目的上，都在主人公的暂时失败中激发人们对人的本质的伟大自豪感和必胜信心\n（3）心理感受上，悲剧与崇高都在压迫中使审美者体验、升华出一种“痛苦”的快感。\n区别：\n崇高突出主人公的斗争精神及其胜利前景，悲剧则更偏重于表现主人公所置身矛盾的主客观条件的限制与主体不可避免的失败、人性的毁灭；\n（2）崇高着重突出人类的整体背景，引导个体向人性道德境界升华，悲剧侧重表现个体的命运，刺激着个体意识的觉醒\n（3）崇高性的悲剧不仅有崇高的亢奋激情和人类自豪，更包括了非崇高性的深邃的哲理内容引人深思，例如三岛由纪夫的《金阁寺》中不仅金阁寺因为“我”而被焚毁，“我”在寺院的苦修同样也毁灭了“我”的天性。“我”认为金阁寺必然要在焚烧中才好看，既有日本传统的“物哀”精神，也有西方以萨特为代表的虚无主义的渗透\n（4）悲剧比崇高的审美范围小，它只涉及到人的行为或事件；崇高的审美对象既可以是人与事件，也可以是自然景观；例如我们对玉龙雪山的审美感受就是以巍峨、神秘、阔大带来的崇高感。"}, {"id": "q119", "type": "简答", "q": "试分析悲剧和喜剧的本质或者实质。", "a": "（1）悲剧的本质是主人公由于坚持正义或积极进取，而与现实环境之间发生的冲突，冲突中主人公因感性生命遭到摧残和毁灭而成就了精神生命的永恒价值，从而激起悲壮之情而使人们的心灵得以净化，精神得以提升。悲剧冲突在于主体所代表的正义精神与永远不能满足的现实之间发生了矛盾。而矛盾的结果，是精神取得了胜利。恩格斯指出，悲剧的本质正是由“历史的必然要求和这个要求的实际上不可能实现之间的悲剧性冲突”所决定的，悲剧是新旧两种社会力量的尖锐矛盾以及这一矛盾在一定历史阶段的不可解决，因而导致下面人物的失败或灭亡。它通过个人的苦难和残废体现出包含在独特个性之中的不朽的具有社会意义的东西。\n（2）喜剧的本质是以笑为手段，去否定生活中的不协调的形式，从中肯定生活中的美的艺术、社会现象、生活现象，乃至社会历史事件。喜剧的本质是强烈的讽刺与揭露。喜剧中的丑角表现了人的非本质与无价值性，对喜剧人物的虚假性暴露、嘲弄与批判构成了喜剧审美的核心内容，喜剧的本质是对作为审美对象的喜剧主人公遮蔽自我或人性本质的揭露。"}, {"id": "q190", "type": "填空", "q": "鲁迅：“（____）”（客观题）", "a": "鲁迅：“悲剧将人生的有价值的东西毁灭给人看”（客观题）"}, {"id": "q191", "type": "填空", "q": "美学意义上的悲剧可以分为两种类型：（____）、（____）", "a": "美学意义上的悲剧可以分为两种类型：崇高性悲剧、非崇高性悲剧"}, {"id": "q192", "type": "填空", "q": "作为审美范畴的悲剧，有四个要素：（____）、（____）、（____）、（____）", "a": "作为审美范畴的悲剧，有四个要素：悲剧人物、悲剧事件、悲剧悖论、悲剧效果"}, {"id": "q193", "type": "填空", "q": "从对待喜剧主人公的价值态度出发，可以把喜剧分为（____）与（____）", "a": "从对待喜剧主人公的价值态度出发，可以把喜剧分为肯定性喜剧与否定性喜剧"}, {"id": "q194", "type": "填空", "q": "作为审美范畴的喜剧，有四个要素：（____）、（____）、（____）、（____）", "a": "作为审美范畴的喜剧，有四个要素：喜剧人物、喜剧事件、喜剧矛盾、喜剧效果"}, {"id": "q195", "type": "填空", "q": "喜剧的矛盾冲突具有（____），就是有悬念，能扣人心弦，而且急转直下，出乎人的意料，形成拍案叫绝、惊喜交错的特点", "a": "喜剧的矛盾冲突具有突发性，就是有悬念，能扣人心弦，而且急转直下，出乎人的意料，形成拍案叫绝、惊喜交错的特点"}, {"id": "q196", "type": "填空", "q": "康德用“（____）”解释喜剧，他认为，造成喜剧性矛盾的可笑的东西是荒谬的、不和谐的，常常出乎人的意料，让人的心理期待突然归于消失", "a": "康德用“预期失望说”解释喜剧，他认为，造成喜剧性矛盾的可笑的东西是荒谬的、不和谐的，常常出乎人的意料，让人的心理期待突然归于消失"}], "c11": [{"id": "q16", "type": "名词解释", "q": "名词解释：以美育代宗教说", "a": "蔡元培在近代中国处境下形成的美育思想。在西方传统教育中，宗教主宰了世俗教育，随着社会发展，教育获得了独立的地位，宗教只能以美的因素存在于世间。蔡元培认为纯粹的美育可以替代宗教，主要包含了三个方面的内容，首先，宗教是强制的而美育是自由的；其次，美育是进步的而宗教是保守的；最后，美育是普及的而宗教是有限的，美育替代宗教反映了蔡元培以美育救国的主张。有利于“自由、平等、博爱”理想的实现，在政治上具有很大的进步意义。"}, {"id": "q21", "type": "名词解释", "q": "名词解释：美育书简", "a": "德国哲学家席勒所作。在书中他正式提出了“美育”概念。在书中，席勒把人性划分为两个部分，“人格”相当于理性，“状态”相当于感性，二者协调地统一在理想的境界当中，但在现实生活中，人格与状态是分裂的。因为人在自由的审美观照中理性和感性才能达到平衡，席勒认为“游戏冲动”/美能够消除人性的分裂状态。美育是人实现自由的根本途径，应当促进鉴赏力和美的教育，把美育当做人性解放、道德完善的唯一出路。《美育书简》是历史上第一部以美育为研究对象的理论著作，是美育理论形成独立体系的标志，被称为第一部美的宣言书。但书中过分夸大美育的作用，是离开社会的空想，反映了德国资产阶级的软弱。"}, {"id": "q56", "type": "名词解释", "q": "名词解释：美育", "a": "又称美感教育。即通过培养人们认识美、体验美、感受美、欣赏美和创造美的能力，从而使我们具有美的理想、美的情操、美的品格和美的素养。狭义的美育是认为美育指“美感教育”“审美教育”“审美观和美学素养教育”等。广义的美育，是将美学原则渗透于各科教学后形成的教育。美育是一种快乐教育，是有目的、有具体内容的系统教育活动，在“立德树人”方面发挥着独特的、不可替代的作用。"}, {"id": "q57", "type": "名词解释", "q": "名词解释：寓教于乐", "a": "古罗马的文艺理论家贺拉斯在《诗艺》中提出的美育思想。贺拉斯认为文艺的社会功能是寓教于乐，既能劝谕读者，又能使他奋发，才能符合众望，一部作品要达到教育的目的必须使得欣赏者从中获得愉悦。“寓教于乐”揭示了艺术的本质特征：艺术中所包含的普遍性的真、善、美必须通过明晰的个性化,转化为个体感性可以直接接受的形式,艺术作品必须是形式与内容的美的融合、统一。“寓教于乐”思想对18世纪启蒙运动以及古典主义的文艺理论和文艺创作产生了深远的影响,至今仍是衡量艺术作品优劣的标准之一。"}, {"id": "q125", "type": "简答", "q": "使命", "a": "（1）素质教育的保障。美育既是审美教育,也是艺术教育。\n（2）肩负着完整人的塑造。铸造人的完美人格为核心目标,以人的全面能力发展和自主性、创造性能力培养为旨归,实现人与自然、社会的和谐发展和人类自身可持续发展为终极追求美育以情感丰富人的心灵;美育以艺术启迪人的智慧;美育以审美培养人的情操。\n（3）美育决定着人类生活的品质。美育本身所蕴含的情感性、艺术性和审美性,将人们的生活由简单地追求物质提升到对生活艺术、生活品位的追求，极大地促进人类生活品质的提高。\n（4）美育促进和谐社会的构建。首先,美育有对道德的催化作用;其次,美育与法律的融汇让感性与理性有机结合;最后,美育促进人与自然和谐相处。"}, {"id": "q126", "type": "简答", "q": "特性", "a": "（1）从施教手段来看，美育是一种形象教育。美育总是通过一定的审美对象媒介来施行，以感性的形象诉之于人，人们因形象获得活跃的情感，摆脱了世俗功利欲望，在灵魂上受到了净化。例如在初中教育中为了使得同学们感受孔子的精神美，教师往往会播放李玫的《孔子》作为教学辅助；又如在历史学科教育中，为了使材料变得直观，教师也会播放纪录片《西南联大》作为补充。\n（2）从受教方式来看，美育是一种情感教育。美育要激发教育者感情。美育的成功有赖于受教育者自觉自愿地作为审美主体进入对审美对象的体验中，是对对象意蕴的直觉性领悟，美育是以情服人而不是以理服人。朱光潜也提出“美育是一种情感教育”，要重视学生的情感与教学活动的情感状态的变化。\n（3）就受教效果而言，美育是一种快乐教育。美育以审美活动为主要施教方式与手段，人们接受美育的过程是一种高级的精神消费或享受的过程，是获得精神愉悦的过程。古罗马的贺拉斯就提出美育应当遵守“寓教于乐”的原则，让学生在快乐对诗歌直观性的把握"}, {"id": "q127", "type": "简答", "q": "功能", "a": "（1）培养审美能力。可以从情感与形象的角度提高想象力和理解力，健全审美心理结构，全面培养审美能力。审美对象的反复展现可以促进感官对形式的认知，训练人的多维想象力，为艺术的发展与物质生产创造了条件。\n（2）陶冶人的性情。美育为人创造了自由审美的审美空间，人通过对审美对象所蕴含的意义的感受、体验与领悟获得情感的振荡、超越与洗涤，这个过程就是“洗涤”。陶冶是一种潜移默化的过程，美育的陶冶会逐渐培养和建立起一种超越使用功利的人生态度，改变人的性情，带有固定性和延续性，使人具备对事业的巨大激情和动力。\n（3）完善人格。人格是人的性格、气质、能力等特征的总和。在审美活动中，主体的各项心理功能处于一种自由和谐的状态当中，审美对象所蕴含的意义总是潜移默化地直达人心，使人进入高尚的审美境界，去掉私立之心和“小我”精神，唤起真正的人的价值与属性。\n（4）树立正确的审美观。审美观是人世界观的重要组成部分，美育让人自觉地领略到美和丑的分界，帮助人们树立正确的世界观与审美观，激发人们执着地追求自己的事业，自觉地排除一切卑劣欲望的侵袭。"}, {"id": "q128", "type": "简答", "q": "途径", "a": "（1）审美理论的学习。包括了美学基础理论、艺术理论与艺术史和其他审美常识三部分，\n（2）艺术美赏析。对典型艺术品进行美学角度的分析能够陶冶人的性情，完善人的精神与人格。\n（3）自然美赏析。生成对大自然的感激与敬畏，达到天人合一的美学感受。\n（4）社会美赏析。明确自己的人生目标，塑造自己美的形象，人类活动场景的赏析同样是一种美育，能够激励在日常生活中发现美、创造美"}, {"id": "q205", "type": "填空", "q": "（____）的美育思想中最为突出的是他提出了“以美育代宗教”的学说", "a": "蔡元培的美育思想中最为突出的是他提出了“以美育代宗教”的学说"}, {"id": "q206", "type": "填空", "q": "古罗马的诗人、文艺理论家（____）第一个提出了“寓教于乐”的思想", "a": "古罗马的诗人、文艺理论家贺拉斯第一个提出了“寓教于乐”的思想"}, {"id": "q207", "type": "填空", "q": "古代的美育，无论在西方还是在东方，是从属于（____）的，是进行道德教育的补充手段", "a": "古代的美育，无论在西方还是在东方，是从属于道德教育的，是进行道德教育的补充手段"}, {"id": "q208", "type": "填空", "q": "（____）首次在中国提出了“趣味教育”的概念（客观题）", "a": "梁启超首次在中国提出了“趣味教育”的概念（客观题）"}, {"id": "q209", "type": "填空", "q": "美育的功能包括：（____）、（____）、（____）、（____）", "a": "美育的功能包括：培养审美能力、陶冶性情、完善人格、树立正确的审美观"}, {"id": "q210", "type": "填空", "q": "审美理论主要包括三方面的内容，即（____）、（____）、（____）", "a": "审美理论主要包括三方面的内容，即美学基础理论、艺术理论与艺术史、其他审美常识"}], "c0": [{"id": "q17", "type": "名词解释", "q": "名词解释：美学", "a": "美学学科是人类知识近代分化所产生的理论自觉形态，是一门人文学科，也是理论学科。美学是研究审美活动的学科，1750年鲍姆嘉通《美学》的出版标志着美学成为一门学科门类。"}, {"id": "q18", "type": "名词解释", "q": "名词解释：马克思主义美学", "a": "马克思主义美学是指由马克思主义者们关于“美”的理论分析的美学体系，并非专指马克思、恩格斯的美学思想，敏锐地察觉到美作为人类的创造产物而存在，肯定了人在审美中的主体性地位。哲学基础是辩证唯物主义、历史唯物主义与德国古典哲学。在艺术起源上，马克思主义美学指出劳动创造了美；就规律性而言，马克思主义美学认为美是有规律可循的；就本质论而言，艺术是作为上层建筑依赖于经济基础；通过对异化劳动的分析，一方面尖锐批判了资本主义私有制的罪行，另一方面又具体分析了异化劳动的两重性：既制造丑，又创造美。"}, {"id": "q36", "type": "名词解释", "q": "名词解释：审美活动", "a": "作为人把握世界的特殊方式，是人在感性与理性的统一中，按照“美的规律”来把握现实的一种自由的创造性实践，包括欣赏美的事物、创造美的作品、研究美学理论、评论文艺现象以及美化环境等等。是美学学科的研究对象。审美活动是人类特有的的一种精神活动和文化活动，是人性的需求，是人以意象世界为对象的人生体验活动，具有社会性和历史性。审美活动主要由审美对象和审美意识构成，按照审美活动的存在领域，美学对象范围可分为社会美，自然美，艺术美和美育。按照审美活动的形态类型可分为崇高，悲剧，喜剧，优美，丑审美范畴。"}, {"id": "q42", "type": "名词解释", "q": "名词解释：审美现代性", "a": "在现代社会中，人们在审美体验和艺术表现上所展现的现代性特征。在观念上，吸收现代主义和后现代主义的哲学文化思想，中西交融；在内容上，体现为美学形式的新旧之争，包括传统文学与现代文学、戏曲与电影等。审美现代化代表着单一的古典美学时代结束，但由于时间距离较短，审美的现代性内部仍然存在包括肯定与否定、精英与民粹、普遍人类学与资产阶级意识形态三大矛盾，其发展仍然是一个未完成的阶段。"}, {"id": "q64", "type": "简答", "q": "美学是一门什么样的学科？/美学的学科定义（历史和属性）", "a": "美学是一门产生于近代的，基于人类长期的审美活动而形成的，研究“美”的对象与人类审美活动的人文学科，具有如下的学科特质：\n奠基于历史悠久的美学思维，经历了如下阶段：物象判断、以物象生发抽象思考、纯粹理性思考，黑格尔就指出人类的审美活动经历了“象征-古典-浪漫”的三个基本阶段并循环往复；\n学科内部支系庞杂，丰富多样。就共时性特征而言，处在某一阶段的美学都在判别美学的研究对象，思考新的研究方法，同一时期中不同理论家与作家具有不同取向的美学体系，例如在1929-1939年间我国小说创作上就出现了延安文学、国统区文学和“孤岛文学”三大研究范式与作品分区。就历时性角度而言，每一阶段的美学都是对前一时段的扬弃与继承，例如在20世纪前期波德莱尔反对19世纪现实主义全然纪实的文学传统，上承浪漫主义就提出“以丑为美”的审美特质，并强调以象征书写真实的心灵动荡感受。\n（3）与社会思潮发展大致同步，也表露出明显的独立性，有时也呈现出对社会思潮的先导作用和滞于社会发展的现象。就同步状态而言，随着董仲舒“罢黜百家，独尊儒术”后，古代审美进入了以儒家为主导的新阶段；就超前性而言，马雅可夫斯基等人的“未来主义”则超越了二战后充满郁闷与虚无的当代技术世界；就滞后性而言，林纾的小说翻译观则是典例。"}, {"id": "q65", "type": "简答", "q": "美学研究什么？（对象和内容）", "a": "基于审美的本质是对审美活动的哲学抽象这一逻辑，一般认为美学的研究对象是人类的审美活动，根据不同的维度划分，美学对“审美活动”的研究主要包括如下四个方面：\n（1）审美活动由审美对象与审美意识构成。审美对象是发生的前提；审美意识指导着审美活动，没有审美意识的审美活动与人类其他精神活动无异。美学所研究的是在历史的审美活动中，审美对象是如何被审美主体判定以及审美意识的总体特征与产生过程。\n（2）按照存在领域分，美学的研究对象包括自然美、社会美、艺术美和美育四个方面。自然美是人关系自然活动的审美，人类能够从自然环境中获得美的精神体验，例如陶渊明言“采菊东篱下，悠然见南山”；社会美是社会生活中的审美经验，例如《桃花源记》当中“黄发垂髫，并怡然自乐”；艺术美是存在于艺术形态当中的审美，例如波旁王朝时期盛行的洛可可油画；美育是对人类审美教育与修养，一般认为是美学的教育功能的体现，例如朱光潜《给青年的十二封信》。\n（3）按照形态类型分，审美活动包括崇高、优美、悲剧、喜剧、丑五类。崇高是人的本质力量与客体之间处于尖锐对立与严峻冲突时，主客体之间所呈现出来的冲突的美，例如海明威《老人与海》当中老人与鲨鱼的搏斗；优美是平静、舒畅、主客体统一的感受，例如欧阳修《蝶恋花》中“泪眼问花花不语，乱红飞过秋千去”；悲剧是“把一切美好的东西毁灭给人看”的一种感受，它被泛化到所有的艺术形态当中，例如《红楼梦》；喜剧是令人发笑的的作品，例如《人间喜剧》；“丑”则是泛指一切与“美”对立的事物，二者之间可以相互转换，李贺。"}, {"id": "q66", "type": "简答", "q": "怎样研究美学（研究方法）", "a": "区别于实证经验科学的哲学思维，以及区别于纯思辨的人文体验描述。\n1学好哲学特别是马克思主义哲学\n2理论联系实际，美学史的理论实践和艺术实践\n3独立思考，要有自己的认识，要系统的学习研究掌握知识要点\n（1）观察。例如南北朝时期宗炳就提出“澄怀味象”的方法观察山水；而庄子则是指出审美无主客之分，审美的观察是一种“齐物”的观察。\n（2）体验。审美的研究需要研究者自我卷入，对其作体验，对美的体验包括一种追问和对话行为，例如西苏认为女性批评的前提是“身体写作”，包括体验身体和体验身体的遭遇；\n（3）解释。解释是阐发现象的深层意义，各种审美形态、审美现象的意义也需要主体的解释显露出来；就陶渊明的接受史而言，在唐代的解释当中，陶渊明被认为是虚假的自况，杜甫就言“观其著诗集，颇亦恨枯槁”；而在宋代陶渊明被朱熹评价为“超脱自然”。"}, {"id": "q67", "type": "简答", "q": "为什么要学习美学", "a": "（1）提供愉悦的感受：美学可以让人观察感受体验美好感觉，提供让人愉悦的感受，安顿身心，深化我们对世界美感的认知，“博物馆”通过全景式的实物展示让游客品味美感；\n（2）研究审美关系：美学是研究人与世界审美关系的一门学科，即美学研究的对象是审美活动。审美活动是人的一种以意象世界为对象的人生体验活动，是人类的一种精神文化活动。例如《拉奥孔》给我们提供了“诗画同源”的分析方法；\n（3）转化生产力：美学可以转化为生产力，例如在商业领域，美感获得差异化价值，让企业脱颖而出。商业成功靠的不仅仅是没有温度的数据，因为数据背后的用户是活生生的人。\n（4）提升综合能力：对审美的研究其实与对科学本身的研究至少同等复杂，感性的能力在结合了理性以后的一种综合能力，已经很难为理性或哲学思辨所把握。"}, {"id": "q68", "type": "简答", "q": "美学和哪些学科关系切近？", "a": "（1）与艺术学:两者有相当部分的研究内容重叠\n就相同部分而言，美学与艺术学都着重研究艺术审美\n就不同而言，美学与艺术学主要存在两个向度的不同：\n①研究的对象范围不同。美学不只研究艺术审美，还研究更加广阔的现实审美，与现实生活要素广泛结合，在服饰领域，山本耀司体现了“侘寂”的审美风格；而艺术学则研究与艺术有关的一切，包括艺术品(杜尚的《喷泉》与行为艺术)、艺术家(孟子知人论世说)、艺术欣赏(诗中有画画中有诗）和艺术创作（“复调”小说），以及艺术与非艺术（“上帝已死”和现代主义）在文化史上所发生的一切。\n②研究内容和研究方法不同。美学的研究基础和归宿都指向更为普遍的现实审美，美学的研究方法是基于哲学而形成；而艺术学研究中审美关系只是一条内在的指导线索，艺术学研究还包括其他方面的研究方法，例如结构主义、传记批评等方面。\n（2）与心理学：美学是一种心理活动得益于心理学的研究成果，例如精神分析法，心理学成为了美学研究中有效的解释工具；心理学也与美学有所区别，主要包括如下三个方面：\n①心理学是对心理现象外在的观测，美学立足于审美心理内在的体验\n②心理学记录心理反应的生理-物理变量，美学要理解审美心理作出不同于客观说明的解释\n③心理学属于“自然科学”的部分，但美学则是形而上学的范畴\n（3）与宗教学:在现代性之后，审美保留了“祛魅”以前的审美思维，保留了宗教带来的独特的超理性部分，艺术取代了“神灵”成为新的信仰本体，审美活动的本质是承认艺术本位的前提下使用宗教学的分析方法，例如弗莱的原型批评。"}, {"id": "q129", "type": "填空", "q": "美学学科的名称是德国哲学家（____）在1750年首次提出", "a": "美学学科的名称是德国哲学家鲍姆嘉通在1750年首次提出"}, {"id": "q130", "type": "填空", "q": "康德关于美学的一部名著书名叫（____）", "a": "康德关于美学的一部名著书名叫《判断力批判》"}, {"id": "q131", "type": "填空", "q": "中国古典美学的三个黄金时代分别是（____）", "a": "中国古典美学的三个黄金时代分别是先秦、魏晋南北朝和清代前期"}, {"id": "q132", "type": "填空", "q": "中国美学的真正起点是（____），他开创了（____）的传统", "a": "中国美学的真正起点是老子，他开创了道家美学的传统"}, {"id": "q133", "type": "填空", "q": "（____）是中国历史上第一个提倡美育的思想家", "a": "孔子是中国历史上第一个提倡美育的思想家"}, {"id": "q134", "type": "填空", "q": "在唐、五代和宋元时期，中国古典美学除了儒家美学、道家美学这两条线之外，（____）对中国古典美学也产生了越来越大的影响", "a": "在唐、五代和宋元时期，中国古典美学除了儒家美学、道家美学这两条线之外，禅宗对中国古典美学也产生了越来越大的影响"}, {"id": "q135", "type": "填空", "q": "中国近代美学的三大家是（____）", "a": "中国近代美学的三大家是梁启超 、王国维、蔡元培"}, {"id": "q136", "type": "填空", "q": "中国现代美学两大代表性人物是（____）", "a": "中国现代美学两大代表性人物是朱光潜、宗白华"}, {"id": "q137", "type": "填空", "q": "在中国当代美学第一次热潮中出现了四大美学流派，他们分别是（____），（____），（____）和（____）", "a": "在中国当代美学第一次热潮中出现了四大美学流派，他们分别是以蔡仪为代表的客观派，以高尔泰、吕荧为代表的主观派，以朱光潜为代表的主客观统一派和以李泽厚为代表的客观性和社会性统一派 "}, {"id": "q138", "type": "填空", "q": "美学研究的对象是（____）", "a": "美学研究的对象是审美活动"}, {"id": "q139", "type": "填空", "q": "审美活动由（____）和（____）构成", "a": "审美活动由审美对象和审美意识构成"}, {"id": "q140", "type": "填空", "q": "美学的学科特性： 美学是一门（____）；（____）；（____）", "a": "美学的学科特性： 美学是一门人文学科；理论学科；美学相邻学科"}], "c10": [{"id": "q23", "type": "名词解释", "q": "名词解释：丑的美学", "a": "德国美学家罗森克兰兹。罗森克兰兹认为“丑”作为一种美学范畴，包括有四个层面的意义，首先，美与丑是对立的，但研究方法是相似的；其次，丑不仅作为提高陪衬美的范畴出现在艺术中，更有其独立的经验意义；第三艺术创作不能以美化丑，但表现丑仍然需要在对称、比例等形式美的范围进行异化与夸张，突出其另类又反常规的外在特征；最后，艺术的丑削弱了现实中丑恶现象令人不快的特征，无形中将丑同等化为与“美”相同的审美范畴，升华了“丑”的哲学意义。《丑的美学》是第一部研究丑的美学专著，标志着丑正式成为一种特殊的审美形态，开启了现代丑学的研究。"}, {"id": "q50", "type": "名词解释", "q": "名词解释：丑", "a": "是一个特殊的否定的审美范畴，有广义和狭义之分。广义的丑是现实对人的本质的否定，是对目的与规律相统一的破坏与背离，狭义的丑则是对优美纯粹与完满的否定与破坏。丑是人的本质对象化的未实现和残缺状态，是对规范和正常尺度的破坏与否定；富于刺激性。丑包括三种类型，一是自然形态的丑，二是社会形态的丑，三是艺术的丑，表现为畸形、混乱、过度。现代意义的美与丑不再存在明显界限，逐渐成为先锋与时尚的因素。丑的审美意义就在于可以以丑衬美，而且生活中的丑经过艺术家的灵心点化，可以转化成艺术中的美。"}, {"id": "q51", "type": "名词解释", "q": "名词解释：怪", "a": "丑的审美范畴之一，是对正常的人和事及其关系的正常尺度的夸张变形，是一种极端反常化的变形。怪的变形包括有事物变形、事物关系变形、整个世界图景的变形三类，在历史发展中“怪”同样作为一个概念存在于人类审美活动当中。人们由于怪的夸张和变形引发了不快与快活混合的复杂情感，“怪”通过对对象的“降格”让其贬低化和世俗化，人基于“荣耀感”产生了“快活”的解放感。"}, {"id": "q52", "type": "名词解释", "q": "名词解释：酷", "a": "丑的审美范畴之一，是人的本质对象化过程的一个特定阶段和特殊形态。在“酷”的过程中，现实以包容的方式否定人的本质，目的性与规律性发生有限的偏离，是对偏离于和谐完满性的各行其志的自恋式认同。就其外在表现而言，酷表现为一个人思想观念、穿衣打扮的标新立异，蕴含着游戏社会的文化意义；就其本质而言，酷包括了自恋情结、超然嘲讽和享乐主义三种因素，是一种无深度的平面文化；就其审美感受而言，“酷”排除了伦理道德内涵，呈现出满不在乎的开心陶醉。酷以其多元特征向传统习惯发起挑战，丰富了扩展了人们的审美观念，但其形式化、自恋化的形式使其在内容上处于半空洞状态，在精神上处于亚健康状态。"}, {"id": "q53", "type": "名词解释", "q": "名词解释：荒诞", "a": "丑的审美范畴之一，是人本质力量对象化过程的特定阶段。在这个阶段，由于人的本质的分解、弥散或缺位，使对象化过程变成一种无根基、无秩序、无归宿的解体过程。换言之，荒诞是对无意义、无本质、无深度、无价值本身的对象化过程，因而也是对虚无的对象化和对象化的虚无。"}, {"id": "q54", "type": "名词解释", "q": "名词解释：恐怖", "a": "作为丑的审美范畴之一，主要是对“异形”反常的丑的形式的虚构组合，是对形式背后可能的内容和支配力量的“升格”或神秘化，其审美感受是恐惧感、惊悚感、崇拜感和厌恶感的混合。因此，否定、背离以及与之相关的惊悚、恐惧、神秘、厌恶等，是恐怖美学范畴的主要特征。"}, {"id": "q55", "type": "名词解释", "q": "名词解释：恐怖小说", "a": "以“恐怖”作为审美范畴的小说形式。评论家将恐怖小说分为哥特小说和现代恐怖两类，前者主要以宗教的衰落意象营造恐怖氛围，后者主要是冤魂幽鬼、死灵僵尸、精神变态等一系列意象营造恐怖氛围，引发人们紧张窒息与尽情尖叫的情感反应；但就其积极意义上，恐怖以恶性刺激和过度刺激拓展了人们的审美生活。就恐怖小说发展的历史而言，美国作家艾伦·坡是现代恐怖小说的开山鼻祖，后来也有斯蒂芬·金、詹姆斯·帕特森等人相继扩张现代恐怖小说的表现能力与范畴。"}, {"id": "q120", "type": "简答", "q": "怎样在美丑转化把握丑的特征？", "a": "（1）审美活动包括对美的发现与对丑的揭露。审美活动本身必然包含了对美的发现、欣赏、创造与对于丑的揭露、鞭挞和摒弃两个侧面，同时，两个侧面也都处于历史过程中，美与丑是在审美实践中不断生成和发展。\n（2）丑可以使人联想到美或转换为美。亚里士多德认为现实生活中的丑可以转化为艺术世界的美，艺术家能够通过联想、变化等艺术手法将现实生活的丑转变为引起人们快感的艺术形式，这个过程中，丑能够发挥其积极作用，激活审美主体热烈、激荡、积极的生命经验。\n（3）丑依据美的规则进行表现。罗森克兰兹认为丑的通过比例、对称等形式美因素进行表现，削弱了丑在现实生活中令人不快的感受。"}, {"id": "q121", "type": "简答", "q": "分析丑的审美本质", "a": "（1）从审美活动中审美主体与审美客体之间来看，丑是人的本质对象化的未实现和残缺，是目的性与规律性的不统一；\n（2）从审美意象中内容与形式看，丑是理性内容与感性形式、理想与现实、社会与自然之间的背离，是对规范和正常尺度的破坏与否定；\n（3）从审美感受来看，丑引起的感觉富有刺激性，使人不安，令人厌恶，否定和苦味愉悦是丑的本质属性。"}, {"id": "q122", "type": "简答", "q": "怎么理解丑与崇高、优美之间的渗透和转换关系？", "a": "（1）丑与优美的联系是以“反形式”，优美在形式上表现为和谐、圆满、秀美和凝静，而丑则是在形式上反对优美，呈现出反常与混乱的特征，在外观上的特点是不完整、不规律和不和谐，决不能构成优美的整体。不规律是指丑的事物是畸形怪异的，违反了事物自身整体性；无规律是丑的事物是杂乱无章的；不和谐是各个部分相互冲突、彼此对立的状态。在转换过程中，丑给人以强烈的不适感，但同时也在艺术当中获得了崇高的体验，呈现出“非优美”的审美价值。例如《水浒传》中武大郎与潘金莲的则是表与里不同的美丑对立，武大郎外丑内美，潘金莲外美内丑，巨大的反差感最终导致潘金莲毒死亲夫，将丑从内向外的放大。\n（2）丑与崇高在内容与形式上高度关联。丑与崇高不仅给人同样地从个体痛苦转向族群经验的审美感受，也在形式上表现为不完整、不和谐、扭曲变形，体现出观念大于形式的特征。丑与崇高存在着基本的界限，丑的东西必然需要激活人类自身的敬仰感或自觉因牺牲而带来的进取意义才能被称为“崇高”的美，丑参与崇高之中表现了人的自由本质为实现自身对象化而努力斗争的精神空前高涨，但丑作为现实对人自由本质的否定，其转换也需要把握主体对客体征服欲望与客体对主体压迫性的适度，只有主体取得胜利的发展后丑才能被称为崇高。例如雕塑《拉奥孔》就以拉奥孔父子受难的场面表现出不和谐的状态，但同样也给人与神矛盾不可调和的悲剧感；《西游记》中孙悟空和猪八戒二人都长得其貌不扬，但二人在内心里对取经大业的信仰，对唐僧的尊敬和面对妖魔的勇武都是对不规律的“丑”向美的转换。"}, {"id": "q123", "type": "简答", "q": "丑有哪些审美范畴？（名词解释51—54）", "a": "（1）怪：“怪”包括了三种变形，一是事物的变形，例如电影《复仇者联盟》中的“浩克”，我国传说中的烛九阴；二是事物关系的变形，例如蒲松龄中的“聂小倩”由鬼化人；三是整个世界图景的变形，例如电影《爱丽丝梦游仙境》，我国传统小说《老残游记》。\n（2）酷：例如“杀马特”文化，y2k文化。\n（3）荒诞：例如贝克特的代表作品《等待戈多》戈戈和蒂蒂在“等待戈多”的过程中无意义地做着一些可笑的消遣之举，又遭遇了老爷和仆人，最后当戈多“今天不会来”后二人决定明天再来等，表现出巨大的虚无感与无聊感；\n（4）恐怖：日本电影《午夜凶铃》是对日常生活的“偶然物”的升格创造，通过一卷被诅咒的录像带，从电视中爬出的“贞子”形象成为当代世界电影史中的经典形象；美国恐怖电影《招魂2》则回到了人类关于宗教的反价值想象，“鬼修女”凝结了历史性的关于宗教的反思。"}, {"id": "q124", "type": "简答", "q": "如何理解荒诞？", "a": "荒诞是人的本质对象化过程的一个特定阶段，在这个阶段中由于人的本质分解，弥散或者缺位，对象化的过程变得无根基、无秩序、无归宿的解体过程。荒诞是用非理性的方式发生对生活的体验，表达一种强烈的意义缺失的虚无感与绝望感，用否定的方式曲折地肯定人的自由。（名词解释53）\n（1）荒诞由三对关系而存有意义。从荒诞的主客体关系看，由于主体虚位而导致主客关系瓦解，客体变得碎片杂陈，慌乱无主，主体既不是被单纯的肯定，也不是被单纯否定，既不是目的性对规律性的最终统一或宰制；从内容与形式的关系看，荒诞是无理性内容的感性形式、无理想的现实、无背景的背景、无深度的平面、无指涉的拟像，人的卑微生存也被集中地表现出来；从人与他者的关系看，不仅是人是无意义的，世界本身也是无意义的，荒诞的人与世界相互冷漠、彼此疏远；人无法区分理性与非理性，只能通过拼接无理性来引起审美感觉，既有意义流落的虚无感与恐慌感；又有不承担责任、不追求意义的解放感。\n（2）作为审美范畴的荒诞是现代社会的运动结果。现代社会的高度异化、人对异化社会的彻底绝望使人对社会失去基本理想与感受，在现代世界中人愈发地孤独无助，没有基本的对于未来的希望，由而荒诞才能被生成。\n（3）荒诞的审美特征：\n①形式的碎片化与丑怪。荒诞艺术不在理性意义把实体看作可以透彻了解的存在，在完整的意义取消后，人变为一个被无限延展的、实体被挤压的、毫不相关的元素组合的平面，单向度的人生获得无实质的能力，例如在尤奈斯库的《犀牛》中人变犀牛的荒诞感；而卡夫卡的《城堡》中那个从未存在的城堡主人主宰者k的人生。\n②内容的平面化和无中心。由于时空深度的消失，内容的中心和主体弥散出现了无高……"}, {"id": "q197", "type": "填空", "q": "丑可以分为三类一是（____）；二是（____）；三是（____）", "a": "丑可以分为三类一是自然形态的丑；二是社会形态的丑；三是艺术形态的丑"}, {"id": "q198", "type": "填空", "q": "在审美经验中，美与丑是（____）的", "a": "在审美经验中，美与丑是共存的"}, {"id": "q199", "type": "填空", "q": "（____）认为，丑比美更深刻，审丑比审美更有价值", "a": "马克斯·德索认为，丑比美更深刻，审丑比审美更有价值"}, {"id": "q200", "type": "填空", "q": "从形式方面看，丑与崇高都具有（____）、（____）、（____）的特点", "a": "从形式方面看，丑与崇高都具有不和谐、不完整、扭曲变形的特点"}, {"id": "q201", "type": "填空", "q": "从审美效果方面看，丑与崇高都在一定程度上（____）", "a": "从审美效果方面看，丑与崇高都在一定程度上引起人们的苦痛感"}, {"id": "q202", "type": "填空", "q": "从观念与形式的关系上看，丑与崇高都具有（____），体现出（____）的特征", "a": "从观念与形式的关系上看，丑与崇高都具有非理性因素，体现出观念大于形式的特征（客观题）"}, {"id": "q203", "type": "填空", "q": "丑的审美范畴包括：（____）、（____）、（____）、（____）", "a": "丑的审美范畴包括：怪、酷、荒诞、恐怖（客观题）"}, {"id": "q204", "type": "填空", "q": "怪，主要包括三个方面一是（____）；二是（____）；三是（____）", "a": "怪，主要包括三个方面一是事物的变形；二是事物关系的变形；三是整个世界图景的变形"}], "c4": [{"id": "q24", "type": "名词解释", "q": "名词解释：包豪斯", "a": "即德国魏玛的“公立包豪斯学校”，它的成立标志着现代设计学的诞生。包豪斯是世界上第一所完全为发展现代设计教育而建立的学院。包豪斯代表的现代设计体现了艺术与技术在美感价值上的统一。包豪斯学派主张把建筑、雕塑和绘画结合成一个整体，互相促进，把现实生活融入设计当中，追求艺术与生活的统一。包豪斯的诞生是技术在美学领域的一次重要转型，体现了技术的美感潜质，但该学派由于过分强调材料与功能，忽视了人的心理需求，形成了普遍化的国际主义，缺少对美感与技术的界限探求。"}, {"id": "q25", "type": "名词解释", "q": "名词解释：迪扎因", "a": "“设计”（design）的音译，代表了把一种设想通过合理的规划、周密的计划、通过各种感觉形式传达出来的过程。设计活动是一种文化整合的过程，包含了三个方面的整合，一是产品自身属性的总和，二是消费者本性构成的属性综合，三是与产品在特定环境中发挥作用的条件的属性综合。设计的过程是技术和艺术的结合，设计的审美创造主要通过产品形式表现，体现为形式的自由，不同设计师在设计中通过不同的材料形式将涉及的美感丰富化和多维化，是在遵守设计的规定性（包括产品技术、生产技术和操作技术）中设计师自由对美感的具象化过程。"}, {"id": "q43", "type": "名词解释", "q": "名词解释：装饰", "a": "作为动词，装饰指主体在审美理想的指导下，按照美的规律装点和打扮对象，使其审美特性更加鲜明。作为名词，装饰指经过主体一系列装点、打扮之后具有审美效果的成品。艺术对日常生活的审美化改造正是充分发挥艺术的装饰功能，增添日常生活的审美色彩，使生活在主体对艺术装饰的审美观照下获得情趣，“情趣本来是物我交感共鸣的结果。景物变动不居，情趣亦自生生不息。”丰富多彩的装饰活动与装饰作品构筑了主体审美生活的广阔情趣空间，主体在情趣的体验中完成人生的审美建构。"}, {"id": "q44", "type": "名词解释", "q": "名词解释：技术", "a": "技术是人们从事生产活动的手段，人们凭借技术自觉地应用客观规律以引起、调整和控制人与自然界之间的物质交换过程。技术是一个历史范畴，在历史发展中对其界定不一，古代的技术是人类手艺、技巧、技艺和技能的总称，主要依靠人类积累的经验；亚里士多德将其界定为“智慧”。进入21世纪后技术的定义愈发模糊化。技术是人类劳动生存目的与规律相统一最核心的解构，是自由形式感最切近的凝聚体。"}, {"id": "q45", "type": "名词解释", "q": "名词解释：艺术", "a": "是人类在掌握一定制作技艺的基础上，按照一定规律所进行的美的创造，它同时是人的自由本质的精神对象化方式。从表面上看，艺术是以现实生活和世界为蓝本，实质却是以现实审美为前提与中介。艺术以形式美为手段，以技术美为结构，以社会美为主题，以自然美为形态榜样。"}, {"id": "q91", "type": "简答", "q": "技术与艺术的区别？", "a": "（1）本质和目的：技术是一种解决问题的方法或手段，追求的是效率、准确性和可重复性，主要服务于生产和生活，旨在解决实际问题，提高生产效率和生活质量。而艺术则是一种创造性的表达形式，追求的是美的感受、情感的共鸣和精神的满足，旨在传达创作者的情感、思想和观念，引发观众的共鸣和思考。\n（2）表现形式：技术通常以工艺流程、设计图、操作方法等形式出现，技术成果可以商品化。而艺术则通过色彩、线条、声音、动作等元素来传达情感和思想，具有多样性，包括绘画、雕塑、音乐、舞蹈等多种形式。\n（3）评价标准：技术产品的评价主要基于客观的性能指标和效率标准，如速度、精度、可靠性等。而艺术作品的评价则具有主观性，受到观众的个人喜好、文化背景和审美观念的影响，艺术作品的优劣难以用客观的标准来衡量。\n总的来说，技术和艺术在本质、目的、表现形式以及评价标准等方面存在明显的区别。技术更侧重于实用性和功能性，而艺术则更侧重于审美和情感表达。"}, {"id": "q92", "type": "简答", "q": "为什么设计是技术与艺术的结合？", "a": "设计在很大程度上受科技的影响,设计是设计者通过对人们生活的方式和习惯结合美学因素而创作的,它给人们带来实用和美观结合的产品,给使用者带来愉悦。设计的产品要考虑实用性,美学的审美性应当寓于实用性之中。因此在设计创作时,都应当围绕着实际使用的要求来考虑和设计,从材料的选择、外部造型、色彩装饰等多方面,都要结合实用要求来考虑艺术处理和加工等问题。实用工艺品应当适用、经济、美观。就是要在满足人们的物质需要的同时满足人们的精神需要,在具有实用功能的同时也具有审美的功能。随着社会的发展和人类科技的进步,人们对物质生活与精神生活提出了愈来愈高的要求,不仅希望日常生活用品坚固适用,而且希望这些用品精致美观,甚至把美观放到越来越重要的地位上。"}, {"id": "q93", "type": "简答", "q": "什么是艺术美与功能美？实用就是美吗？", "a": "（1）艺术美是一种观念存在的反映美。\n（2）功能美是人所直观到的此产品积淀了人类长期生活实践经验成果的外在审美形式美，是人在使用此产品过程中所感受到的此产品及其形式符号对产品功利内容和功能目的最大化实现后的审美表现美。功能美范畴的提出，可以从根本上克服对产品审美内涵分析上的单纯形式观点，从而关注于产品的功能目的性。\n（3）实用并不等于美。一个技术产品的功利价值与审美价值是两种不同性质的存在。一个产品可能有实用价值，却可能缺乏审美价值，那是因为它没有实现对功能目的的审美表现。美学所说的技术产品的功能美，不能简单地理解为技术产品的适用性，此范畴实具有更广泛的意义。首先，功能美具有丰富的文化内涵，成为社会前进的目的性的展示，它把科技进步所取得的成就直观化了。其次，功能美通过特定的组合秩序促进生活环境与人的生理、心理和社会的协调。此外，产品的功能美也是激发人的购买欲和促进商品流通的重要因素"}, {"id": "q155", "type": "填空", "q": "（____）把技术看作制作的智慧", "a": "亚里士多德把技术看作制作的智慧"}, {"id": "q156", "type": "填空", "q": "英国手工艺运动倡导者（____）认为，“机器本身没有灵魂，它会让人类也同样失去灵魂”", "a": "英国手工艺运动倡导者约翰·罗斯金认为，“机器本身没有灵魂，它会让人类也同样失去灵魂”"}, {"id": "q157", "type": "填空", "q": "技术美的核心是（____）", "a": "技术美的核心是功能美"}, {"id": "q158", "type": "填空", "q": "实用产品的（____）是其各种价值的核心部分", "a": "实用产品的功能价值是其各种价值的核心部分"}], "c8": [{"id": "q34", "type": "名词解释", "q": "名词解释：中和之美", "a": "中和之美是中国古代审美形态的最高典范。在外在形式中，中和之美表现为对阴柔之美与阳刚之美的调和；在内在精神性而言，中和之美将对象与主体、美与善、形式与内容全部普遍化，上升到以优美为典范形态，以人文审美为中心的形而上的宇宙观准则；就内心感受而言，志气和平，情感表现遵循理性规范，是中和之美的理想情境。中和之美给人温柔敦厚的精神享受。“中和之美”广泛深刻地支配者中国古代社会的各种意识形态，对后代艺术产生了巨大影响。"}, {"id": "q46", "type": "名词解释", "q": "名词解释：优美", "a": "审美范畴之一，又称秀美，是通常所说的狭义美，与崇高相对。优美的审美对象在形式方面一般都具有小巧、柔和、清新、秀丽、细腻、圆润等特征，在内容方面一般都不呈现激烈的矛盾冲突，而表现为矛盾双方的暂时相对静止状态。在形式和内容的关系上则表现为十分协调、和谐统一。优美是最易为人们所接受的美的形态，给人赏心悦目的愉快之感。"}, {"id": "q47", "type": "名词解释", "q": "名词解释：崇高", "a": "审美范畴之一，与优美相对。在外在形式中，崇高突出显示为“大”的特征，同时，崇高也表现出反常甚至怪异，带有巨大、粗糙甚至丑陋的特征。就其内在性而言，崇高侧重展示人的本质对象化的曲折过程，主体与客体处于矛盾对立的状态，主体因受到外界压力而遭到摧毁甚至走向死亡，获得了超越生命物质性的本质伟大；就主体内心感受而言，崇高给人以“痛苦的愉悦”，审美主体能够在人抗争的摧毁或死亡中萌生敬仰之情，由紧张动荡转向骄傲、自豪与愉悦，伴有强烈的审美想象与情感的剧烈变化，"}, {"id": "q110", "type": "简答", "q": "优美和崇高的联系和区别是什么？", "a": "优美和崇高是一种对应性的审美范畴，二者相互依存，又相互转换，客观彰显出人的本质力量对象化的特点与规律，表现出丰富的特征：\n联系：\n（1）崇高和优美都是西方美学的基本形态，都是人在认识自然、改造自然的实践活动中以及在各种社会生活中积累起来的审美体验，是审美主体与客体相互作用的结果。二者在不同程度上丰富了人类的精神生活，并反作用于人的实践活动，对人类的生产生活产生了重大影响。\n（2）在美学发展史上，人们首先意识到的是“优美”，并且在一定程度上将优美等同于美，也就是较早地产生了优美的概念。但随着人们认识水平的逐渐提高，单一的优美已经不能满足人们的审美需求，笼统的“美”的概念便产生了分化，细化为优美与崇高两个部分。也即是说崇高这一审美概念的出现，为单一的优美作了补充，并且提供了一种参照对比，进而丰富了美的内涵。\n区别：\n（1）就内在结构而言，优美是规律与目的相统一的内在结构，是主体与客体和谐完满的统一性；崇高突出了主体与客体、感性与理性的矛盾对立，包含了从痛到快感的复杂心灵体验。\n（2）就外在表现形式而言，优美的外在结构形式相对稳定，表现出柔媚、安静、秀美等形态与境界，形式偏重于小巧、平缓与圆润，更多地体现于艺术与自然这类形式美因素突出的形态中，在社会美中的优美只能通过抽象的方式被领悟到；崇高则突出表现为“大”的外在形式特征，形式趋近于无限，甚至表现出反常甚至怪异的特征，崇高通常在社会美与自然美中能够被直接感受，社会行动中推翻封建统治、反抗入侵战争，自然界中狂风暴雨、江河波涛等都有直接的壮阔形式。\n（3）就审美享受而言，优美因主客体始终处于统一状态而具有直观的审美愉悦，人因“审美愉悦”……"}, {"id": "q111", "type": "简答", "q": "简述优美的特征。", "a": "（1）规律与目的相统一是优美的内在结构。优美是人的本质力量对象化的结果，是合目的性与合规律性统一的最终成果，因此在对象表现中有秀丽、单纯、完整的特征，主体的心灵也产生了柔和平稳、舒畅喜悦的美感心理特质。\n（2）优美的对象表现出静态的特征。优美侧重于结果的展示，在本质上是静态的，少有矛盾冲突与审美张力的痕迹，审美主体在其中体验到和谐圆美的精神感受。例如谢朓“好诗圆美流转如弹丸”，强调写诗的目的是抚慰人心，缓和矛盾\n（3）艺术美以形式美作为主要表现方式。优美体现在艺术与自然这类形式美因素突出的形态中，而社会美中优美一般只能以较为抽象的领悟方式被人感受到。偏重于小巧纤细、平缓光滑。王维的《山居秋暝》以“空山”、“新雨”、“竹”、“莲花”等意象以清新朗秀的形式将人、景、情统一到一幅静态的风景画当中\n（4）优美的最终效果是“审美愉快”。人的本质化的实现消除了矛盾抗争的紧张情绪，达到各种心理要素的和谐，在形式上带有纯粹与和谐感，是所有审美形态感受的最高境界。"}, {"id": "q112", "type": "简答", "q": "简述崇高的特征。", "a": "（1）个体处于压迫状态，带有社会总体的伦理道德。崇高美中受阻受挫，甚至招致死亡的是矛盾状态中的个体主体，崇高中主体力量的发挥以人的总体性为实现目标，用个体的牺牲显示人的本质力量的伟大。《俄狄浦斯王》中弑父娶母的预言。\n（2）以庄严、宏伟为外在特征，表现一种主体斗争与反抗的美。在社会领域中，凡是体现实践主体的巨大力量，展现主体征服和掌握客体的坚强意志，表现主体从弱到强的努力，显示巨大潜力的行为都是崇高美的体现，例如美国南北战争对奴隶制的推翻，我国的抗日战争；作为社会个体而言，先行者大义凛然的精神，如鲁迅“俯首甘为孺子牛”的奉献精神。\n（3）外形上的突出特征为“大”，具有对各种特定有限形式的包容、涵括的性质，趋向无限性。“大”的极致是“无限性”，人只有在想象中把握无限性后才掌握了崇高的审美特征。“大”在到达极致后表现为现有审美规范的反转，进而表现出粗糙、丑陋的反传统特征，打破了平面的和谐与流畅。例如，在自然审美中，泰山与封禅传统得以关联在于庞大给人以无限的宇宙想象，韩愈的诗。\n（4）给人以痛苦的愉悦特征。崇高在展现主客体由巨大冲突到趋向统一的艰难过程中，主体经历了由强大所造成的紧张与压力，从而引起主体的抗争。主体能自觉意识到一个更为持久而伟大的人类本质力量的存在境界，例如埃斯库罗斯《普罗米修斯》中普罗米修斯盗火"}, {"id": "q113", "type": "简答", "q": "从现代性语境看崇高的生成和演变。p190", "a": "（1）从审美文化史的角度看，如果把审美范畴作为对特定社会审美文化现象的抽象与概括，那么，作为逻辑行程结果的优美反而是人类最早注意的形态范畴，崇高则更为晚近才被注意，属于近代以后的审美范畴。原因之一在于人类生存状态的内在变化背景。近代社会分工及产革命之后迅猛发展的资本主义工业化，不仅从生产方式上也从生活方式与社会心理状态上深刻地打破了中世纪田园牧歌式的和谐平衡，一种空前剧烈而痛苦的矛盾冲突日渐扩大演化为人类常态。崇高正是这种人类社会进程加剧阶段上的审美反映。而崇高在近代的崛起，是人类把所处社会中更为尖锐复杂的矛盾斗争，直观为主体自由化历程中一种特定阶段的表现。在原始野蛮人那里只能视为神秘恐怖对象的自然灾异，却被纳入文明更高阶段人类的审美欣赏之中，应当说是人化自然达到一定历史水平之后的结果。因而，崇高在近代的流行，又反映出人类文明发展的更高成就。\n（2）崇高的范畴主要是从西方引进的，中国古代相关的概念有“大”、“阳刚”以及类似崇高风格的“风骨”等。西方美学史上最早提出“崇高”这一范畴的是朗吉诺期，他在《论崇高》中论及了这一美的范畴。博克最早把优美与崇高并立起来加以研究，认为崇高以痛感为基础，是痛感向快感的转变。康德进一步把崇高进行了分类，认为崇高分为数学的崇高和力学的崇高两种。黑格尔则认为崇高是理念压倒形式，对崇高进行了分析。"}, {"id": "q114", "type": "简答", "q": "举例分析优美与崇高的相互转化。p192", "a": "（1）转换的基本规律是由崇高趋向优美再转向崇高。优美与崇高作为美的不同表现状态，他们的关系由审美的本质所规定的，即真与善、合规律性与合目的性的统一。\n①由崇高到优美：当人的本质实现自身对象化的过程遭遇阻力，甚至牺牲时，审美活动呈现为崇高的美感，对抗性可以激发主体战胜阻力；而当人的本质实现对象化，主客体矛盾趋于和谐，达到规律与目的的统一时，崇高向着优美转换，意味着人类对自然和社会斗争的不断发展与进步。以姚鼐的《登泰山记》为例，攀登泰山的过程中遭遇了“道中迷雾冰滑，磴几不可登”，人与泰山发生了对抗，产生了崇高感，当完成攀登后，又见“苍山负雪，明烛天南”，崇高被深化，产生出对自然的敬仰感；最后到了“与子颖坐观日亭，待日出”，人与泰山、与天空没有明确的对立感，人作为欣赏者介入自然风光，由前文的危机与矛盾转向了优美与齐一感。\n②由优美到崇高：基于合目的性与合规律性的统一关系，新因素介入对原有的美学范畴造成了不平衡，审美又从无冲突走向冲突状态，优美又开始向崇高转换，人类社会的发展与主体的生存不断经历着由崇高转向优美再转向崇高的一种无限延伸过程。叙事学中的“突转”就是从优美转向崇高的典型化案例，在普洛普的民间故事研究中“王子拯救公主”就是这类转换的案例，我国民间故事“白素贞”也有相类似的转换范式的内容。\n（2）优美与崇高的转换产生新的审美范畴。主体存在位置与活动情境的变化导致了新的审美范畴产生的取向，当主体失去与对象的对抗力量，被客体压倒后，崇高就会转换为悲剧，例如《美狄亚》、《浮士德》等；而与人对抗的力量因主体的更迭而落后时，它就转换为可笑与没落，例如滑稽喜剧，例如《伪君子》、《钦差大臣》……"}, {"id": "q115", "type": "简答", "q": "结合而现代审美状况分析崇高的现代意义。p194", "a": "（1）重塑新的人性建设与完善现代的主体意义。后现代社会表现出强烈的审美贫困，在审美追求中，文化价值的随意使得实践由崇高转向卑微的媚俗倾向，审美追求形象上的肤浅愉悦。崇高是人在面对对象压抑中从痛苦走向敬仰的美感经验，在现代意义中，崇高解放了个体的现实压抑性，激活了人面对他者压迫时旺盛的生命力，重新树立人对事物的超越与征服力。北岛的诗《回答》用富有对抗意义的“我不相信！”与世界的谬话对峙，反映了现代诗人“普罗米修斯”精神的回归。\n（2）唤醒人类集体的审美共通感。崇高是人类自觉地将个体的痛苦转换为人类本质力量的实现的过程，在这个过程中，审美共通感重新进入了现代性领域，重新统一在一致的认识体系当中，崇高将个体的痛觉转化为人类普遍的荣耀感。马尔克斯的《百年孤独》以一个家族九代人的命运故事彰显了人类文明的共通性与同构性，其中重复的名字、结构相同的故事隐喻了新的共同体面前所有人命运的殊途同归。\n（3）聚合了人自由的个性与社会的使命。崇高带有明显的社会伦理道德感，表现了人本质力量对象化的矛盾性与斗争性，在现代社会中，崇高美自觉地聚合了人自由的个性与其社会的使命，是人类生命精神与实践目的的回归，有助于人类社会层面的升华。海明威的小说《老人与海》通过老人与鲨鱼的搏斗，最后拖回大马林鱼的尸体这一情节表明人类在现代社会异化中仍是自由的，仍是怀有理想并为理想奋斗的。"}]}};
